    /* ══════════════════════════════════════════
           🌌 AURORA BACKGROUND ANIMATION
           ══════════════════════════════════════════ */
    body::before {
        content: '';
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background:
            /* Aurora Green Light - MORE VISIBLE */
            radial-gradient(ellipse 80% 50% at 20% 40%, rgba(0, 230, 118, 0.15) 0%, transparent 50%),
            /* Aurora Violet Light - MORE VISIBLE */
            radial-gradient(ellipse 60% 60% at 80% 20%, rgba(124, 77, 255, 0.2) 0%, transparent 50%),
            /* Aurora Pink Light - MORE VISIBLE */
            radial-gradient(ellipse 70% 40% at 60% 80%, rgba(233, 30, 99, 0.12) 0%, transparent 50%),
            /* Aurora Cyan Light - MORE VISIBLE */
            radial-gradient(ellipse 50% 50% at 10% 90%, rgba(0, 188, 212, 0.1) 0%, transparent 40%),
            /* Deep Blue Base - MORE VISIBLE */
            radial-gradient(ellipse 100% 100% at 50% 50%, rgba(13, 71, 161, 0.15) 0%, transparent 70%);
        z-index: 0;
        pointer-events: none;
        animation: auroraShift 20s ease-in-out infinite;
    }

    /* Second Aurora Layer - MORE VISIBLE */
    body::after {
        content: '';
        position: fixed;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        background:
            radial-gradient(ellipse 40% 30% at 70% 60%, rgba(0, 230, 118, 0.1) 0%, transparent 50%),
            radial-gradient(ellipse 50% 40% at 30% 30%, rgba(124, 77, 255, 0.12) 0%, transparent 50%);
        z-index: 0;
        pointer-events: none;
        animation: auroraShift2 25s ease-in-out infinite reverse;
    }

    @keyframes auroraShift {

        0%,
        100% {
            opacity: 1;
            transform: scale(1) translateY(0);
        }

        25% {
            opacity: 0.9;
            transform: scale(1.05) translateY(-10px);
        }

        50% {
            opacity: 0.8;
            transform: scale(1.1) translateY(0);
        }

        75% {
            opacity: 0.9;
            transform: scale(1.05) translateY(10px);
        }
    }

    @keyframes auroraShift2 {

        0%,
        100% {
            opacity: 0.8;
            transform: scale(1.1) translateX(0);
        }

        50% {
            opacity: 0.6;
            transform: scale(1) translateX(20px);
        }
    }

    /* ══════════════════════════════════════════
           🎭 AURORA GLOW KEYFRAMES
           ══════════════════════════════════════════ */
    @keyframes auroraGlow {

        0%,
