                                        <div class="layout-sidebar-block"></div>
                                        <div class="layout-sidebar-block"></div>
                                    </div>
                                </div>
                            </div>
                            <div class="layout-info">
                                <div class="layout-name">
                                    <i class="fas fa-columns" style="color: #7c3aed;"></i>
                                    Sidebar Layout
                                </div>
                                <div class="layout-description">
