            <!-- Visual Design Reference Uploader -->
            <div id="referenceImagesSection" class="card card-full fade-in" style="animation-delay: 0.39s;">
                <div class="card-header">
                    <div class="card-icon" style="background: linear-gradient(135deg, #ec4899 0%, #8b5cf6 100%);">
                        <i class="fas fa-images"></i>
                    </div>
                    <h2 class="card-title">Visual Design Reference (Optional)</h2>
                </div>
                <div class="card-body">
                    <p class="card-description">Upload screenshots or design inspirations that AI should use as visual
                        reference</p>

                    <!-- Reference Upload Zone -->
                    <div class="visual-reference-zone" id="referenceDropZone">
                        <input type="file" id="referenceImageInput" multiple accept="image/*" style="display: none;">
                        <div style="position: relative; z-index: 1;">
                            <div class="visual-reference-icon">
                                <i class="fas fa-image"></i>
                            </div>
                            <h3 class="visual-reference-title">Upload Design Reference Images</h3>
                            <p class="visual-reference-subtitle">Drag & drop screenshots of designs you like, or click
                                to browse</p>
                            <div class="visual-reference-hint">
                                <i class="fas fa-lightbulb"></i>
                                Screenshots from other websites, mockups, or design inspirations
                            </div>
                        </div>
                    </div>

                    <!-- Reference Images Gallery -->
                    <div class="reference-images-gallery" id="referenceGallery">
                        <h3 style="font-family: 'Space Grotesk', sans-serif; font-size: 1.25rem; margin-bottom: 1rem;">
                            <i class="fas fa-images" style="color: #ec4899;"></i> Uploaded Reference Images
                        </h3>

                        <div class="reference-images-grid" id="referenceImagesGrid">
                            <!-- Reference images will appear here -->
                        </div>

                        <!-- Reference Application Mode -->
                        <div class="reference-mode-selector">
                            <h4
                                style="font-family: 'Space Grotesk', sans-serif; font-size: 1.1rem; margin-bottom: 0.75rem; color: var(--text-primary);">
                                <i class="fas fa-cogs"></i> How should AI use these references?
                            </h4>

                            <label class="reference-mode-option selected" data-mode="ai-inspiration">
                                <input type="radio" name="reference_mode" value="ai-inspiration"
                                    class="reference-mode-radio" checked onchange="updateReferenceMode(this)">
                                <div class="reference-mode-header">
                                    <div class="reference-mode-icon">
                                        <i class="fas fa-brain"></i>
                                    </div>
                                    <div>
                                        <div class="reference-mode-title">AI Inspiration Mode</div>
                                    </div>
                                </div>
                                <div class="reference-mode-description">
                                    AI will analyze all uploaded images and intelligently choose design elements, color
                                    schemes, layouts, and styles from them to create a cohesive design. AI decides which
                                    image inspires which page based on best fit.
                                </div>
                                <div class="reference-mode-features">
                                    <div class="reference-mode-feature">
                                        <i class="fas fa-check"></i>
                                        Intelligent Extraction
                                    </div>
                                    <div class="reference-mode-feature">
                                        <i class="fas fa-check"></i>
                                        Best Fit Matching
                                    </div>
                                    <div class="reference-mode-feature">
                                        <i class="fas fa-check"></i>
                                        Cohesive Design
                                    </div>
                                    <div class="reference-mode-feature">
                                        <i class="fas fa-check"></i>
                                        Creative Adaptation
                                    </div>
                                </div>
                            </label>

                            <label class="reference-mode-option" data-mode="exact-replication">
                                <input type="radio" name="reference_mode" value="exact-replication"
                                    class="reference-mode-radio" onchange="updateReferenceMode(this)">
                                <div class="reference-mode-header">
                                    <div class="reference-mode-icon">
                                        <i class="fas fa-copy"></i>
                                    </div>
                                    <div>
                                        <div class="reference-mode-title">Exact Replication Mode</div>
                                    </div>
                                </div>
                                <div class="reference-mode-description">
                                    AI will replicate the exact design from each image to matching pages. Image named
                                    "contact" → Contact page design, "products" → Products page design. Pixel-perfect
                                    recreation of layouts, colors, and styling from the references.
                                </div>
                                <div class="reference-mode-features">
                                    <div class="reference-mode-feature">
                                        <i class="fas fa-check"></i>
                                        Pixel-Perfect Match
                                    </div>
                                    <div class="reference-mode-feature">
                                        <i class="fas fa-check"></i>
                                        Page-to-Image Mapping
                                    </div>
                                    <div class="reference-mode-feature">
                                        <i class="fas fa-check"></i>
                                        Exact Layout Copy
                                    </div>
                                    <div class="reference-mode-feature">
                                        <i class="fas fa-check"></i>
                                        Precise Recreation
                                    </div>
                                </div>
                            </label>
                        </div>

                        <!-- Info Box -->
                        <div class="reference-info-box">
                            <i class="fas fa-info-circle"></i>
                            <div>
                                <strong>Important Note:</strong>
                                <p>When reference images are uploaded, AI will ONLY use design inspiration from these
                                    images and will NOT use any external design sources. Your uploaded images become the
                                    exclusive visual reference for the entire project.</p>
                            </div>
                        </div>

                        <!-- Action Buttons -->
                        <div style="display: flex; gap: 1rem; margin-top: 1.5rem; flex-wrap: wrap;">
                            <button class="btn btn-danger" onclick="clearReferenceImages()">
                                <i class="fas fa-trash-alt"></i>
                                Clear All References
                            </button>
                        </div>
                    </div>

                </div>
            </div>

            <!-- Exclusion Manager -->
            <div id="excludedFilesSection" class="card card-full fade-in" style="animation-delay: 0.395s;">
                <div class="card-header">
                    <div class="card-icon" style="background: linear-gradient(135deg, #f59e0b 0%, #ef4444 100%);">
                        <i class="fas fa-ban"></i>
                    </div>
                    <h2 class="card-title">File Exclusion Manager (Optional)</h2>
                </div>
                <div class="card-body">
                    <p class="card-description">Exclude specific pages from theme and/or layout changes</p>

                    <!-- File Picker -->
                    <div class="exclusion-file-picker" id="exclusionFilePicker">
                        <input type="file" id="exclusionFileInput" multiple accept=".html,.php,.htm"
                            style="display: none;">
                        <div class="exclusion-file-picker-content">
                            <div class="exclusion-file-picker-icon">
                                <i class="fas fa-file-circle-xmark"></i>
                            </div>
                            <div class="exclusion-file-picker-title">Select Files to Exclude</div>
                            <div class="exclusion-file-picker-hint">
                                Click to choose pages that should keep their original design
                            </div>
                        </div>
                    </div>

                    <!-- Excluded Files List -->
                    <div class="excluded-files-list" id="excludedFilesList">
                        <h3
                            style="font-family: 'Space Grotesk', sans-serif; font-size: 1.25rem; margin-bottom: 1.5rem;">
                            <i class="fas fa-list-check" style="color: #f59e0b;"></i> Excluded Pages
                        </h3>

                        <div id="excludedFilesContainer">
                            <!-- Excluded files will appear here -->
                        </div>

                        <!-- Warning -->
                        <div class="exclusion-warning">
                            <i class="fas fa-exclamation-triangle"></i>
                            <div class="exclusion-warning-content">
                                <strong>Important:</strong>
                                <p>
                                    Excluded files will preserve their original design for the selected aspects (Theme
                                    and/or Layout).
                                    Only CSS/HTML changes will be prevented - JavaScript and PHP functionality remains
                                    untouched as always.
                                </p>
                            </div>
                        </div>

                        <!-- Clear All Button -->
                        <div style="margin-top: 1.5rem;">
                            <button class="btn btn-danger" onclick="clearAllExclusions()">
                                <i class="fas fa-trash-alt"></i>
                                Clear All Exclusions
                            </button>
                        </div>
                    </div>

                </div>
            </div>

            <!-- Logo & Branding Section -->
            <div id="logoBrandingSection" class="card card-full fade-in" style="animation-delay: 0.397s;">
                <div class="card-header">
                    <div class="card-icon" style="background: linear-gradient(135deg, #8b5cf6 0%, #06b6d4 100%);">
                        <i class="fas fa-crown"></i>
                    </div>
                    <h2 class="card-title">Logo & Branding</h2>
                    <div id="logoBrandingBadge"
                        style="background: linear-gradient(135deg, #8b5cf6 0%, #06b6d4 100%); color: white; padding: 0.4rem 0.8rem; border-radius: 20px; font-size: 0.85rem; font-weight: 600; display: none; margin-left: auto; align-items: center; gap: 0.4rem;">
                        <i class="fas fa-check-circle"></i>
                        <span id="logoBrandingText">Logo Uploaded</span>
                    </div>
                </div>
                <div class="card-body">
                    <p class="card-description">Upload your logo and set the page title for consistent branding across
                        all pages</p>

                    <!-- Logo Upload Zone -->
                    <div class="logo-upload-zone" id="logoDropZone"
                        onclick="document.getElementById('logoFileInput').click();" style="
                        border: 3px dashed rgba(139, 92, 246, 0.4);
                        border-radius: var(--radius-xl);
                        padding: 2rem;
                        text-align: center;
                        cursor: pointer;
                        transition: all var(--transition-base);
                        background: linear-gradient(135deg, rgba(139, 92, 246, 0.08) 0%, rgba(6, 182, 212, 0.08) 100%);
                        position: relative;
                        overflow: hidden;
                        margin-bottom: 1.5rem;
                    ">
                        <input type="file" id="logoFileInput" accept="image/*" style="display: none;"
                            onchange="handleLogoUpload(this)">

                        <!-- Logo Preview (hidden by default) -->
                        <div id="logoPreviewContainer" style="display: none;">
                            <img id="logoPreview" src="" alt="Logo Preview" style="
                                max-width: 200px;
                                max-height: 120px;
                                border-radius: var(--radius-md);
                                box-shadow: var(--shadow-lg);
                                margin-bottom: 1rem;
                                border: 3px solid rgba(139, 92, 246, 0.3);
                            ">
                            <p id="logoFileName"
                                style="color: var(--aurora-green); font-weight: 600; margin: 0.5rem 0;"></p>
                            <button type="button" onclick="event.stopPropagation(); clearLogoUpload();"
                                class="btn btn-danger btn-sm" style="margin-top: 0.5rem;">
                                <i class="fas fa-times"></i> Remove Logo
                            </button>
                        </div>

                        <!-- Upload Prompt (shown by default) -->
                        <div id="logoUploadPrompt">
                            <div style="font-size: 3.5rem; margin-bottom: 0.75rem;">
                                <i class="fas fa-image"
                                    style="background: linear-gradient(135deg, #8b5cf6, #06b6d4); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text;"></i>
                            </div>
                            <h3
                                style="font-family: var(--font-display); font-size: 1.3rem; font-weight: 700; color: var(--text-primary); margin-bottom: 0.5rem;">
                                Upload Your Logo</h3>
