                            padding: 1rem 1.25rem;
                            font-size: 0.95rem;
                            font-family: var(--font-body);
                            background: linear-gradient(135deg, rgba(13, 27, 42, 0.95) 0%, rgba(27, 38, 59, 0.8) 100%);
                            border: 2px solid rgba(251, 191, 36, 0.3);
