    <script>
    // ============================================
    // STEP 1: BASIC JAVASCRIPT FUNCTIONS
    // ============================================

    console.log('🎨 Design Enhancer - Step 1 Loaded');

    // Theme Toggle Function
    function toggleTheme() {
        const html = document.documentElement;
        const currentTheme = html.getAttribute('data-theme');
        const newTheme = currentTheme === 'light' ? 'dark' : 'light';

        html.setAttribute('data-theme', newTheme);
        localStorage.setItem('theme', newTheme);

        // Update icon
        const icon = document.getElementById('themeIcon');
        icon.className = newTheme === 'light' ? 'fas fa-moon' : 'fas fa-sun';

        showNotification(`Switched to ${newTheme} mode`, 'success');
    }

    // Load saved theme
    const savedTheme = localStorage.getItem('theme') || 'dark';
    document.documentElement.setAttribute('data-theme', savedTheme);
    document.getElementById('themeIcon').className = savedTheme === 'light' ? 'fas fa-moon' : 'fas fa-sun';

    // Notification System
    function showNotification(message, type = 'info') {
        const container = document.getElementById('notificationContainer');
        const notification = document.createElement('div');
        notification.className = `notification notification-${type}`;
        notification.innerHTML = `
                <div style="display: flex; align-items: center; gap: 0.75rem;">
                    <i class="fas fa-${type === 'success' ? 'check-circle' : type === 'error' ? 'exclamation-circle' : type === 'warning' ? 'exclamation-triangle' : 'info-circle'}" 
                       style="font-size: 1.25rem;"></i>
                    <span>${message}</span>
                </div>
            `;

        container.appendChild(notification);

        // Show notification
        setTimeout(() => notification.classList.add('show'), 10);

        // Hide and remove after 4 seconds
        setTimeout(() => {
            notification.classList.remove('show');
            setTimeout(() => notification.remove(), 300);
        }, 4000);
    }

    // Show welcome notification
    setTimeout(() => {
        showNotification('✨ Design Enhancer loaded successfully!', 'success');
    }, 500);

    console.log('✅ Step 1: HTML Structure + Enhanced CSS Design - COMPLETE');

    // ============================================
    // SIDEBAR NAVIGATION SYSTEM
    // ============================================

    // Toggle Sidebar
    window.toggleSidebar = function() {
        const sidebar = document.getElementById('sidebarNav');
        if (sidebar) {
            sidebar.classList.toggle('open');

            // Save state to localStorage
            localStorage.setItem('sidebarOpen', sidebar.classList.contains('open'));

            console.log('📍 Sidebar:', sidebar.classList.contains('open') ? 'Opened' : 'Closed');
        }
    };

    // Scroll to Section with smooth animation
    window.scrollToSection = function(sectionId) {
        const section = document.getElementById(sectionId);
        if (section) {
            // Remove active class from all items
            document.querySelectorAll('.sidebar-item').forEach(item => {
                item.classList.remove('active');
            });

            // Add active class to clicked item
            const clickedItem = document.querySelector(`.sidebar-item[href="#${sectionId}"]`);
            if (clickedItem) {
                clickedItem.classList.add('active');
            }

            // Smooth scroll to section
            const headerOffset = 100;
            const elementPosition = section.getBoundingClientRect().top;
            const offsetPosition = elementPosition + window.pageYOffset - headerOffset;

            window.scrollTo({
                top: offsetPosition,
                behavior: 'smooth'
            });

            // Highlight effect
            section.style.transition = 'box-shadow 0.3s ease';
            section.style.boxShadow = '0 0 30px rgba(124, 77, 255, 0.4), 0 0 60px rgba(0, 230, 118, 0.2)';

            setTimeout(() => {
                section.style.boxShadow = '';
            }, 1500);

            console.log('📍 Scrolled to:', sectionId);
        }

        // Don't close sidebar - keep it open
        return false;
    };

    // Update active sidebar item on scroll
    window.updateActiveSidebarItem = function() {
        const sections = [
            'executionModeSection', 'fileUploadSection', 'themeSelectionSection',
            'enhancementOptionsSection', 'designStyleSection', 'colorThemeSection',
            'layoutSection', 'referenceImagesSection', 'excludedFilesSection',
            'logoBrandingSection', 'homepageCreationSection', 'documentationPageSection',
            'customInstructionsSection', 'promptOutputSection'
        ];

        let currentSection = '';
        const scrollPosition = window.scrollY + 150;

        sections.forEach(sectionId => {
            const section = document.getElementById(sectionId);
            if (section) {
                const sectionTop = section.offsetTop;
                const sectionBottom = sectionTop + section.offsetHeight;

                if (scrollPosition >= sectionTop && scrollPosition < sectionBottom) {
                    currentSection = sectionId;
                }
            }
        });

        // Update active states
        document.querySelectorAll('.sidebar-item').forEach(item => {
            item.classList.remove('active');
            if (item.getAttribute('href') === `#${currentSection}`) {
                item.classList.add('active');
            }
        });
    };

    // Initialize sidebar on page load
    document.addEventListener('DOMContentLoaded', function() {
        // Restore sidebar state (open by default unless explicitly closed)
        const sidebarOpen = localStorage.getItem('sidebarOpen');
        const sidebar = document.getElementById('sidebarNav');

        if (sidebar) {
            // Only close if user has explicitly closed it before (saved as 'false')
            if (sidebarOpen === 'false') {
                sidebar.classList.remove('open');
            } else {
                sidebar.classList.add('open');
            }
        }

        // Add scroll listener for active state
        let scrollTimeout;
        window.addEventListener('scroll', function() {
            clearTimeout(scrollTimeout);
            scrollTimeout = setTimeout(updateActiveSidebarItem, 50);
        });

        console.log('📍 Sidebar Navigation initialized');
    });

