    let currentHelpSection = null;

    // Show help popup for a section
    window.showSectionHelp = function(sectionKey) {
        const content = helpContent[sectionKey];
        if (!content) return;

        currentHelpSection = sectionKey;

        // Update popup content
        const icon = document.getElementById('helpPopupIcon');
        const title = document.getElementById('helpPopupTitle');
        const subtitle = document.getElementById('helpPopupSubtitle');
        const description = document.getElementById('helpPopupDescription');
        const features = document.getElementById('helpPopupFeatures');
        const tip = document.getElementById('helpPopupTip');

        // Set icon
        icon.innerHTML = `<i class="fas ${content.icon}"></i>`;
        icon.style.background = content.iconBg;
        icon.style.color = content.iconColor;

        // Set text content
        title.textContent = content.title;
        subtitle.textContent = content.subtitle;
        description.textContent = content.description;

        // Set features list
        features.innerHTML = content.features.map(f => `<li>${f}</li>`).join('');

        // Set tip
        tip.innerHTML = `<strong>Pro Tip:</strong> ${content.tip}`;

        // Show popup
        document.getElementById('helpPopupOverlay').classList.add('active');
        document.body.style.overflow = 'hidden';

        console.log('📖 Help opened for:', content.title);
    };

    // Close help popup
    window.closeHelpPopup = function(event) {
        if (event && event.target !== event.currentTarget) return;

        document.getElementById('helpPopupOverlay').classList.remove('active');
        document.body.style.overflow = '';
        currentHelpSection = null;
    };

    // Go to section from help popup
    window.goToSectionFromHelp = function() {
        if (currentHelpSection && helpContent[currentHelpSection]) {
            const sectionId = helpContent[currentHelpSection].sectionId;
            closeHelpPopup();

            setTimeout(() => {
                scrollToSection(sectionId);
            }, 300);
        }
    };

    // ============================================
    // 🎮 GAME-STYLE EXECUTION MODE HELP
    // ============================================
    
    // Show Execution Mode Help (Game Style)
    window.showExecutionModeHelp = function() {
        const overlay = document.getElementById('executionModeHelpOverlay');
        if (overlay) {
            overlay.classList.add('active');
            document.body.style.overflow = 'hidden';
            console.log('🎮 Execution Mode Help opened!');
        }
    };
    
    // Close Execution Mode Help
    window.closeExecutionModeHelp = function(event) {
        if (event && event.target !== event.currentTarget) return;
        
        const overlay = document.getElementById('executionModeHelpOverlay');
        if (overlay) {
            overlay.classList.remove('active');
            document.body.style.overflow = '';
            console.log('🎮 Execution Mode Help closed!');
        }
    };

    // ============================================
    // 🎬 CINEMA-STYLE VIDEO TUTORIAL
    // ============================================
    
    let cinemaInterval = null;
    let cinemaStep = 0;
    let cinemaPaused = false;
    let cinemaProgress = 0;
    const totalCinemaSteps = 5;
    let currentStepDuration = 8000; // Will be dynamically set based on speech
    let speechFinished = false; // Track if speech is done
    let minimumStepTime = 3000; // Minimum time to show each step (for animations)
    
    // Speech synthesis variables
    let speechSynthesis = window.speechSynthesis;
    let britishVoice = null;
    let currentUtterance = null;
    let voicesLoaded = false;
    
    // Load voices (needs to wait for voices to be available)
    function loadVoices() {
        const voices = speechSynthesis.getVoices();
        
        // Find a British English voice
        britishVoice = voices.find(voice => 
            voice.lang === 'en-GB' || 
            voice.name.includes('British') || 
            voice.name.includes('UK') ||
            voice.name.includes('Daniel') ||
            voice.name.includes('George') ||
            voice.name.includes('Arthur')
        );
        
        // Fallback to any English voice
        if (!britishVoice) {
            britishVoice = voices.find(voice => voice.lang.startsWith('en'));
        }
        
        // Last resort: use first available voice
        if (!britishVoice && voices.length > 0) {
            britishVoice = voices[0];
        }
        
        if (britishVoice) {
            voicesLoaded = true;
            console.log('🎤 Voice loaded:', britishVoice.name, britishVoice.lang);
        }
    }
    
    // Initialize voices
    if (speechSynthesis) {
        loadVoices();
        speechSynthesis.onvoiceschanged = loadVoices;
    }
    
    // Mute control variable
    let cinemaVoiceMuted = false;
    
    // Speak text with British accent
    function speakText(text, onEnd) {
        // Mark speech as not finished
        speechFinished = false;
        
        // Check if muted
        if (cinemaVoiceMuted) {
            console.log('🔇 Voice muted, skipping speech');
            speechFinished = true;
            if (onEnd) setTimeout(onEnd, 100);
            return;
        }
        
        if (!speechSynthesis) {
            console.warn('Speech synthesis not supported');
            speechFinished = true;
            if (onEnd) setTimeout(onEnd, 2000);
            return;
        }
        
        // Cancel any ongoing speech
        speechSynthesis.cancel();
        
        // Clean text (remove emojis for cleaner speech)
        const cleanText = text.replace(/[\u{1F300}-\u{1F9FF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{1F600}-\u{1F64F}]|[\u{1F680}-\u{1F6FF}]/gu, '').trim();
        
        currentUtterance = new SpeechSynthesisUtterance(cleanText);
        
        // Set voice properties
        if (britishVoice) {
            currentUtterance.voice = britishVoice;
        }
        currentUtterance.lang = 'en-GB';
        currentUtterance.rate = 0.9; // Slightly slower for clarity
        currentUtterance.pitch = 1.05; // Slightly higher for friendliness
        currentUtterance.volume = 1;
        
        // Handle end of speech
        currentUtterance.onend = function() {
            console.log('🎤 Speech ended');
            speechFinished = true;
            if (onEnd) onEnd();
        };
        
        currentUtterance.onerror = function(e) {
            console.error('🎤 Speech error:', e);
            speechFinished = true;
            if (onEnd) onEnd();
        };
        
        // Speak!
        speechSynthesis.speak(currentUtterance);
        console.log('🎤 Speaking:', cleanText.substring(0, 50) + '...');
    }
    
    // Stop speaking
    function stopSpeaking() {
        if (speechSynthesis) {
            speechSynthesis.cancel();
        }
        speechFinished = true; // Mark as finished when manually stopped
    }
    
    // Cinema tutorial steps with voice-friendly text
    const cinemaSteps = [
        {
            speech: "Hey there, friend! 👋 Welcome to the Execution Mode tutorial! Let me show you how to supercharge your AI!",
            voiceText: "Hello there, friend! Welcome to the Execution Mode tutorial! Let me show you how to supercharge your AI experience!",
            title: "🚀 Execution Mode",
            action: "intro",
            mascot: "🤖"
        },
        {
            speech: "First, look at this dropdown! 👆 This is where the magic happens! Click it to see your options!",
            voiceText: "First, look at this dropdown menu. This is where the magic happens! Simply click on it to reveal your options.",
            title: "Step 1: Find the Dropdown",
            action: "highlightDropdown",
            mascot: "👀"
        },
        {
            speech: "Woohoo! 🎉 See these two options? Each one changes how the AI works! Let me explain...",
            voiceText: "Brilliant! You can see two options here. Each one changes how the AI processes your files. Let me explain both of them.",
            title: "Step 2: See Your Options",
            action: "showOptions",
            mascot: "🎯"
        },
        {
            speech: "📖 'Read Before' = AI reads ALL your files first! It's like studying before a test! Smarter results! 🧠",
            voiceText: "The first option is Read Before Executing. The AI will read all your files first, like studying before a test. This gives you smarter, more accurate results!",
            title: "Option 1: Read Before",
            action: "highlightOption1",
            mascot: "📚"
        },
        {
            speech: "⚡ 'Default Process' = AI goes fast! Like a speed run! Good for quick fixes! 🏃‍♂️",
            voiceText: "The second option is Default Process. The AI works faster, like a speed run! This is perfect for quick fixes and simple modifications.",
            title: "Option 2: Default Process",
            action: "highlightOption2",
            mascot: "🚀"
        }
    ];
    
    // Show Cinema
    window.showExecutionModeVideo = function() {
        const overlay = document.getElementById('executionModeCinema');
        if (overlay) {
            overlay.classList.add('active');
            document.body.style.overflow = 'hidden';
            console.log('🎬 Cinema opened!');
            
            // Reset and start
            cinemaStep = 0;
            cinemaProgress = 0;
            cinemaPaused = false;
            speechFinished = false;
            updatePlayPauseIcon();
            
            // Speak intro and wait for it to finish
            speakText("Welcome to the Execution Mode video tutorial! Let's get started!", function() {
                // After intro speech, hide intro and start cinema
                document.getElementById('cinemaIntro').classList.add('hide');
                setTimeout(startCinema, 500);
            });
            
            // Fallback timeout in case speech doesn't work
            setTimeout(() => {
                if (!document.getElementById('cinemaIntro').classList.contains('hide')) {
                    document.getElementById('cinemaIntro').classList.add('hide');
                    setTimeout(startCinema, 500);
                }
            }, 5000);
        }
    };
    
    // Close Cinema
    window.closeExecutionModeVideo = function() {
        const overlay = document.getElementById('executionModeCinema');
        if (overlay) {
            overlay.classList.remove('active');
            document.body.style.overflow = '';
            stopCinema();
            stopSpeaking(); // Stop any ongoing speech
            resetCinema();
            console.log('🎬 Cinema closed!');
        }
    };
    
    // Start Cinema
    function startCinema() {
        if (cinemaInterval) clearInterval(cinemaInterval);
        
        let stepStartTime = Date.now();
        speechFinished = false;
        
        playCinemaStep(cinemaStep);
        
        cinemaInterval = setInterval(() => {
            if (!cinemaPaused) {
                const elapsedTime = Date.now() - stepStartTime;
                
                // Calculate progress based on minimum time
                // But don't move to next step until speech is done
                const progressBasedOnTime = Math.min(100, (elapsedTime / minimumStepTime) * 100);
                
                // If speech is not finished, cap progress at 95%
                if (!speechFinished && progressBasedOnTime >= 95) {
                    cinemaProgress = 95;
                } else {
                    cinemaProgress = progressBasedOnTime;
                }
                
                updateProgressBar();
                
                // Only advance to next step if:
                // 1. Minimum time has passed AND
                // 2. Speech has finished (or is muted)
                const canAdvance = elapsedTime >= minimumStepTime && (speechFinished || cinemaVoiceMuted);
                
                if (canAdvance) {
                    cinemaProgress = 0;
                    cinemaStep++;
                    stepStartTime = Date.now();
                    speechFinished = false;
                    
                    if (cinemaStep >= totalCinemaSteps) {
                        // Loop back to start
                        cinemaStep = 0;
                    }
                    
                    playCinemaStep(cinemaStep);
                }
            }
        }, 100);
    }
    
    // Stop Cinema
    function stopCinema() {
        if (cinemaInterval) {
            clearInterval(cinemaInterval);
            cinemaInterval = null;
        }
    }
    
    // Reset Cinema
    function resetCinema() {
        cinemaStep = 0;
        cinemaProgress = 0;
        cinemaPaused = false;
        speechFinished = false;
        
        // Stop any speech
        stopSpeaking();
        
        // Reset UI elements
        document.getElementById('cinemaIntro').classList.remove('hide');
        document.getElementById('cinemaTitle').classList.remove('show');
        document.getElementById('cinemaDemoContainer').classList.remove('show');
        document.getElementById('cinemaSpeech').classList.remove('show');
        document.getElementById('cinemaCursor').classList.remove('show');
        document.getElementById('cinemaDropdown').classList.remove('highlight');
        document.getElementById('cinemaDropdownOptions').classList.remove('show');
        document.getElementById('cinemaOption1').classList.remove('highlight', 'selected');
        document.getElementById('cinemaOption2').classList.remove('highlight', 'selected');
        
        // Reset dropdown text
        document.getElementById('cinemaDropdownText').innerHTML = 
            '<i class="fas fa-book-reader" style="color: #10b981;"></i> 📖 Read Before Executing';
        
        updateProgressBar();
        updatePlayPauseIcon();
    }
    
    // Play specific step
    function playCinemaStep(step) {
        const stepData = cinemaSteps[step];
        if (!stepData) return;
        
        // Stop any previous speech and reset flag
        stopSpeaking();
        speechFinished = false;
        
        // Update step counter
        document.getElementById('cinemaCurrentStep').textContent = step + 1;
        
        // Update speech bubble
        const speech = document.getElementById('cinemaSpeech');
        const speechText = document.getElementById('cinemaSpeechText');
        speechText.innerHTML = stepData.speech;
        speech.classList.add('show');
        
        // Update title
        const title = document.getElementById('cinemaTitle');
        title.textContent = stepData.title;
        title.classList.add('show');
        
        // Update mascot
        document.getElementById('cinemaMascot').textContent = stepData.mascot;
        
        // Show demo container
        document.getElementById('cinemaDemoContainer').classList.add('show');
        
        // Execute action
        executeAction(stepData.action);
        
        // 🎤 Speak the text with British voice!
        if (!cinemaPaused) {
            speakText(stepData.voiceText || stepData.speech);
        }
        
        console.log(`🎬 Playing step ${step + 1}: ${stepData.title}`);
    }
    
    // Execute cinema action
    function executeAction(action) {
        const cursor = document.getElementById('cinemaCursor');
        const dropdown = document.getElementById('cinemaDropdown');
        const dropdownOptions = document.getElementById('cinemaDropdownOptions');
        const option1 = document.getElementById('cinemaOption1');
        const option2 = document.getElementById('cinemaOption2');
        
        // Reset states
        dropdown.classList.remove('highlight');
        dropdownOptions.classList.remove('show');
        option1.classList.remove('highlight', 'selected');
        option2.classList.remove('highlight', 'selected');
        cursor.classList.remove('show');
        
        switch(action) {
            case 'intro':
                // Just show intro elements
                break;
                
            case 'highlightDropdown':
                // Show cursor moving to dropdown
                cursor.classList.add('show');
                cursor.style.top = '50%';
                cursor.style.left = '30%';
                
                setTimeout(() => {
                    // Move cursor to dropdown
                    cursor.style.transition = 'all 1s ease';
                    cursor.style.top = '55%';
                    cursor.style.left = '50%';
                    
                    setTimeout(() => {
                        cursor.classList.add('clicking');
                        dropdown.classList.add('highlight');
                        setTimeout(() => cursor.classList.remove('clicking'), 300);
                    }, 1000);
                }, 500);
                break;
                
            case 'showOptions':
                dropdown.classList.add('highlight');
                setTimeout(() => {
                    dropdownOptions.classList.add('show');
                }, 500);
                break;
                
            case 'highlightOption1':
                dropdownOptions.classList.add('show');
                cursor.classList.add('show');
                cursor.style.top = '58%';
                cursor.style.left = '50%';
                
                setTimeout(() => {
                    option1.classList.add('highlight');
                    setTimeout(() => {
                        cursor.classList.add('clicking');
                        option1.classList.add('selected');
                        setTimeout(() => cursor.classList.remove('clicking'), 300);
                    }, 500);
                }, 800);
                break;
                
            case 'highlightOption2':
                dropdownOptions.classList.add('show');
                cursor.classList.add('show');
                cursor.style.top = '66%';
                cursor.style.left = '50%';
                
                setTimeout(() => {
                    option2.classList.add('highlight');
                    setTimeout(() => {
                        cursor.classList.add('clicking');
                        option2.classList.add('selected');
                        document.getElementById('cinemaDropdownText').innerHTML = 
                            '<i class="fas fa-bolt" style="color: #f59e0b;"></i> ⚡ Default Process';
                        setTimeout(() => cursor.classList.remove('clicking'), 300);
                    }, 500);
                }, 800);
                break;
        }
    }
    
    // Update progress bar
    function updateProgressBar() {
        const bar = document.getElementById('cinemaProgressBar');
        if (bar) {
            bar.style.width = cinemaProgress + '%';
        }
    }
    
    // Toggle play/pause
    window.toggleCinemaPlayPause = function() {
        cinemaPaused = !cinemaPaused;
        updatePlayPauseIcon();
        
        // Handle speech pause/resume
        if (speechSynthesis) {
            if (cinemaPaused) {
                speechSynthesis.pause();
            } else {
                speechSynthesis.resume();
            }
        }
    };
    
    // Update play/pause icon
    function updatePlayPauseIcon() {
        const icon = document.getElementById('cinemaPlayIcon');
        if (icon) {
            icon.className = cinemaPaused ? 'fas fa-play' : 'fas fa-pause';
        }
    }
    
    // Restart cinema
    window.restartCinema = function() {
        stopCinema();
        resetCinema();
        
        setTimeout(() => {
            document.getElementById('cinemaIntro').classList.add('hide');
            setTimeout(startCinema, 500);
        }, 500);
    };
    
    // Skip to next step
    window.skipCinemaStep = function() {
        stopSpeaking(); // Stop current speech before skipping
        cinemaProgress = 0;
        cinemaStep++;
        
        if (cinemaStep >= totalCinemaSteps) {
            cinemaStep = 0;
        }
        
        playCinemaStep(cinemaStep);
        updateProgressBar();
    };
    
    // Volume/Mute control
    window.toggleCinemaVolume = function() {
        cinemaVoiceMuted = !cinemaVoiceMuted;
        
        const icon = document.getElementById('cinemaVolumeIcon');
        if (icon) {
            icon.className = cinemaVoiceMuted ? 'fas fa-volume-mute' : 'fas fa-volume-up';
        }
        
        // If muting, stop current speech
        if (cinemaVoiceMuted) {
            stopSpeaking();
        }
        
        console.log('🔊 Voice:', cinemaVoiceMuted ? 'Muted' : 'Unmuted');
    };

    // Close popup with Escape key
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') {
            // Close regular help popup
            if (document.getElementById('helpPopupOverlay').classList.contains('active')) {
                closeHelpPopup();
            }
            // Close execution mode help popup
            if (document.getElementById('executionModeHelpOverlay') && 
                document.getElementById('executionModeHelpOverlay').classList.contains('active')) {
                closeExecutionModeHelp();
            }
            // Close cinema overlay
            if (document.getElementById('executionModeCinema') && 
                document.getElementById('executionModeCinema').classList.contains('active')) {
                closeExecutionModeVideo();
            }
        }
    });

    // ============================================
