    };

    // Global state for enabled sections (all enabled by default)
    window.enabledSections = {
        executionMode: true,
        fileUpload: true,
        themeSelection: true,
        enhancementOptions: true,
        designStyle: true,
        colorTheme: true,
        layout: true,
        referenceImages: true,
        excludedFiles: true,
        logoBranding: true,
        homepageCreation: true,
