    // Handle sidebar item click (only if section is enabled)
    window.handleSidebarItemClick = function(event, sectionId) {
        const sectionKey = Object.keys(sectionMapping).find(key => sectionMapping[key] === sectionId);
        if (sectionKey && !window.enabledSections[sectionKey]) {
            event.preventDefault();
            event.stopPropagation();
            showNotification('⚠️ This section is disabled. Check the box to enable it.', 'warning');
            return false;
        }
        scrollToSection(sectionId);
    };

    // Toggle section enabled/disabled
    window.toggleSectionEnabled = function(sectionKey, isEnabled) {
        if (sectionKey === 'promptOutput') return; // Cannot disable output section

        window.enabledSections[sectionKey] = isEnabled;

        // Get the section DOM element
        const sectionId = sectionMapping[sectionKey];
        const sectionElement = document.getElementById(sectionId);
        const sidebarItem = document.querySelector(`.sidebar-item[data-section="${sectionKey}"]`);

        if (sectionElement) {
            if (isEnabled) {
                sectionElement.style.display = '';
                sectionElement.style.opacity = '1';
                sectionElement.style.pointerEvents = '';
                sectionElement.style.filter = '';
            } else {
                sectionElement.style.display = 'none';
            }
        }

        if (sidebarItem) {
            if (isEnabled) {
                sidebarItem.classList.remove('section-disabled');
            } else {
                sidebarItem.classList.add('section-disabled');
            }
        }

        // Save to localStorage
        saveSectionStates();

        console.log(`📌 Section "${sectionKey}": ${isEnabled ? 'ENABLED ✅' : 'DISABLED ❌'}`);
    };

    // Save section states to localStorage
    function saveSectionStates() {
        localStorage.setItem('enabledSections', JSON.stringify(window.enabledSections));
    }

    // Load section states from localStorage
    function loadSectionStates() {
        const saved = localStorage.getItem('enabledSections');
        if (saved) {
            try {
                const states = JSON.parse(saved);
                Object.keys(states).forEach(key => {
                    if (key in window.enabledSections && key !== 'promptOutput') {
                        window.enabledSections[key] = states[key];
                    }
                });
            } catch (e) {
                console.error('Error loading section states:', e);
            }
        }

        // Apply loaded states
        Object.keys(window.enabledSections).forEach(sectionKey => {
            const checkbox = document.querySelector(
                `.sidebar-item[data-section="${sectionKey}"] .sidebar-section-toggle input`);
            if (checkbox) {
                checkbox.checked = window.enabledSections[sectionKey];
            }

            // Apply visual state
            if (!window.enabledSections[sectionKey]) {
                toggleSectionEnabled(sectionKey, false);
            }
        });

        console.log('📌 Section states loaded:', window.enabledSections);
    }

    // Check if a section is enabled
    window.isSectionEnabled = function(sectionKey) {
        return window.enabledSections[sectionKey] !== false;
    };

    // Get all enabled sections
    window.getEnabledSections = function() {
        return Object.keys(window.enabledSections).filter(key => window.enabledSections[key]);
    };

    // Get all disabled sections
    window.getDisabledSections = function() {
        return Object.keys(window.enabledSections).filter(key => !window.enabledSections[key]);
    };

    // Initialize section states on DOM ready
    document.addEventListener('DOMContentLoaded', function() {
        setTimeout(loadSectionStates, 100);
    });

    // ============================================
