    // File Storage Object
    const fileStorage = {
        html: [],
        css: [],
        javascript: [],
        php: [],
        images: [],
        documents: [],
        other: []
    };

    // Category Configuration
    const categoryConfig = {
        html: {
            title: 'HTML Files',
            icon: 'fa-html5',
            gradient: 'var(--gradient-primary)',
            extensions: ['html', 'htm'],
            description: 'Website structure files'
        },
        css: {
            title: 'Stylesheets',
            icon: 'fa-css3-alt',
            gradient: 'var(--gradient-ocean)',
            extensions: ['css', 'scss', 'sass', 'less'],
            description: 'Design & styling files'
        },
        javascript: {
            title: 'JavaScript Files',
            icon: 'fa-js',
            gradient: 'var(--gradient-warning)',
            extensions: ['js', 'jsx', 'ts', 'tsx', 'mjs'],
            description: 'Interactive scripts'
        },
        php: {
            title: 'PHP Files',
            icon: 'fa-php',
            gradient: 'var(--gradient-danger)',
            extensions: ['php'],
            description: 'Backend logic files'
        },
        images: {
            title: 'Images',
            icon: 'fa-image',
            gradient: 'var(--gradient-success)',
            extensions: ['jpg', 'jpeg', 'png', 'gif', 'svg', 'webp', 'ico', 'bmp'],
            description: 'Visual assets'
        },
        documents: {
            title: 'Documents',
            icon: 'fa-file-alt',
            gradient: 'var(--gradient-sunset)',
            extensions: ['txt', 'md', 'pdf', 'doc', 'docx', 'rtf'],
            description: 'Documentation files'
        }
    };

    // Initialize File System
    function initFileSystem() {
        const dropZone = document.getElementById('dropZone');
        const fileInput = document.getElementById('fileInput');

        if (!dropZone || !fileInput) {
            console.error('❌ Drop zone or file input not found! Retrying in 500ms...');
            setTimeout(initFileSystem, 500);
            return;
        }

        console.log('🔧 Initializing file system...');
        console.log('   Drop Zone found:', !!dropZone);
        console.log('   File Input found:', !!fileInput);

        // File input change handler - CRITICAL for file selection
        fileInput.addEventListener('change', function(e) {
            console.log('📂 File input changed, files:', e.target.files.length);
            if (e.target.files && e.target.files.length > 0) {
                handleFiles(e.target.files);
            }
        });

        // Drag and drop handlers
        dropZone.addEventListener('dragenter', function(e) {
            e.preventDefault();
            e.stopPropagation();
            dropZone.classList.add('drag-over');
            console.log('📥 Drag enter');
        }, false);

        dropZone.addEventListener('dragover', function(e) {
            e.preventDefault();
            e.stopPropagation();
            dropZone.classList.add('drag-over');
        }, false);

        dropZone.addEventListener('dragleave', function(e) {
            e.preventDefault();
            e.stopPropagation();
            dropZone.classList.remove('drag-over');
            console.log('📤 Drag leave');
        }, false);

        dropZone.addEventListener('drop', function(e) {
            e.preventDefault();
            e.stopPropagation();
            dropZone.classList.remove('drag-over');
            console.log('📦 Files dropped:', e.dataTransfer.files.length);

            const files = e.dataTransfer.files;
            if (files && files.length > 0) {
                handleFiles(files);
            }
        }, false);

        // Prevent default drag behaviors on body
        document.body.addEventListener('dragover', function(e) {
            e.preventDefault();
        }, false);

        document.body.addEventListener('drop', function(e) {
            e.preventDefault();
        }, false);

        console.log('✅ File system initialized successfully');
    }

    // Global click handler for drop zone (backup)
    window.openFileDialog = function() {
        const fileInput = document.getElementById('fileInput');
        if (fileInput) {
            console.log('🖱️ Opening file dialog...');
            fileInput.click();
        } else {
            console.error('❌ File input not found!');
        }
    };

    // Handle uploaded files
    function handleFiles(files) {
        if (!files || files.length === 0) {
            showNotification('No files selected', 'warning');
            return;
        }

        console.log(`📁 Processing ${files.length} file(s)...`);
        showNotification(`Processing ${files.length} file(s)...`, 'info');

        // Clear previous files
        Object.keys(fileStorage).forEach(key => fileStorage[key] = []);

        // Categorize files
        Array.from(files).forEach(file => {
            const category = categorizeFile(file);
            fileStorage[category].push(file);
        });

        // Display categorized files
        displayCategorizedFiles();
        displayDistributionMap();

        // Show file categories section
        document.getElementById('fileCategories').classList.add('show');

        showNotification(`✅ ${files.length} file(s) categorized successfully!`, 'success');
    }

    // Categorize file by extension
    function categorizeFile(file) {
        const fileName = file.name.toLowerCase();
        const extension = fileName.split('.').pop();

        // Check each category
        for (const [category, config] of Object.entries(categoryConfig)) {
            if (config.extensions.includes(extension)) {
                return category;
            }
        }

        return 'other';
    }

    // Display categorized files
    function displayCategorizedFiles() {
        const grid = document.getElementById('categoryGrid');
        grid.innerHTML = '';

        Object.entries(categoryConfig).forEach(([category, config]) => {
            const files = fileStorage[category];
            const hasFiles = files.length > 0;

            const categoryBox = document.createElement('div');
            categoryBox.className = `category-box ${hasFiles ? 'has-files' : ''}`;

            categoryBox.innerHTML = `
                    <div class="category-header">
                        <div class="category-icon" style="background: ${config.gradient};">
                            <i class="fab ${config.icon}"></i>
                        </div>
                        <div class="category-title">${config.title}</div>
                        ${hasFiles ? `<div class="category-count">${files.length}</div>` : ''}
                    </div>
                    ${hasFiles ? `
                        <div class="file-list">
                            ${files.map((file, index) => `
                                <div class="file-item">
                                    <i class="fas fa-file"></i>
                                    <span class="file-name" title="${file.name}">${file.name}</span>
                                    <span class="file-size">${formatFileSize(file.size)}</span>
                                    <button class="file-remove" onclick="removeFile('${category}', ${index})" title="Remove file">
                                        <i class="fas fa-times"></i>
                                    </button>
                                </div>
                            `).join('')}
                        </div>
                    ` : `
                        <p style="color: var(--text-muted); font-size: 0.9rem; text-align: center; margin: 0;">
                            No ${config.title.toLowerCase()} uploaded
                        </p>
                    `}
                `;

            grid.appendChild(categoryBox);
        });
        
        // Populate page detection dropdowns after files are displayed
        populatePageDetectionDropdowns();
    }

    // Display distribution map
    function displayDistributionMap() {
        const map = document.getElementById('distributionMap');
        const flow = document.getElementById('distributionFlow');

        const hasAnyFiles = Object.values(fileStorage).some(arr => arr.length > 0);

        if (!hasAnyFiles) {
            map.style.display = 'none';
            return;
        }

        map.style.display = 'block';
        flow.innerHTML = '';

        // Create flow items for categories with files
        const flowData = [{
                category: 'html',
                destination: 'Layout Analysis',
                icon: 'fa-sitemap'
            },
            {
                category: 'css',
                destination: 'Design Enhancement',
                icon: 'fa-palette'
            },
            {
                category: 'javascript',
                destination: 'Preserved (No Changes)',
                icon: 'fa-lock'
            },
            {
                category: 'php',
                destination: 'Preserved (No Changes)',
                icon: 'fa-lock'
            },
            {
                category: 'images',
                destination: 'Asset Optimization',
                icon: 'fa-images'
            },
            {
                category: 'documents',
                destination: 'Content Reference',
                icon: 'fa-book'
            }
        ];

        flowData.forEach(item => {
            const files = fileStorage[item.category];
            if (files.length > 0) {
                const config = categoryConfig[item.category];
                const flowItem = document.createElement('div');
                flowItem.className = 'flow-item active';

                flowItem.innerHTML = `
                        <div class="flow-source">
                            <i class="fab ${config.icon}"></i>
                            ${config.title} (${files.length})
                        </div>
                        <div class="flow-files">
                            ${files.map(f => `<span style="font-size: 0.85rem; color: var(--text-muted);">${f.name}</span>`).slice(0, 2).join(', ')}
                            ${files.length > 2 ? `<span style="font-size: 0.85rem; color: var(--text-muted);">... +${files.length - 2} more</span>` : ''}
                        </div>
                        <div class="flow-arrow">
                            <i class="fas fa-arrow-right"></i>
                        </div>
                        <div class="flow-destination">
                            <i class="fas ${item.icon}"></i>
                            ${item.destination}
                        </div>
                    `;

                flow.appendChild(flowItem);
            }
        });
    }

    // Remove specific file
    function removeFile(category, index) {
        fileStorage[category].splice(index, 1);
        displayCategorizedFiles();
        displayDistributionMap();
        showNotification('File removed', 'info');
    }

    // Clear all files
    function clearAllFiles() {
        if (!confirm('Are you sure you want to clear all uploaded files?')) {
            return;
        }

        Object.keys(fileStorage).forEach(key => fileStorage[key] = []);
        document.getElementById('fileInput').value = '';
        document.getElementById('fileCategories').classList.remove('show');
        displayCategorizedFiles();
        
        // Clear page detection
        clearPageDetection();

        showNotification('All files cleared', 'info');
    }

    // ============================================
    // PAGE DETECTION SYSTEM
    // ============================================
    
    // Global variables for page detection
    let detectedHomepage = null;
    let detectedFeaturedPage = null;

    // Populate page detection dropdowns with uploaded files
    function populatePageDetectionDropdowns() {
        const homepageSelect = document.getElementById('homepageFileSelect');
        const featuredPageSelect = document.getElementById('featuredPageFileSelect');
        const pageDetectionSection = document.getElementById('pageDetectionSection');
        
        if (!homepageSelect || !featuredPageSelect) return;
        
        // Get all HTML and PHP files (page files)
        const pageFiles = [
            ...fileStorage.html.map(f => ({ name: f.name, category: 'html' })),
            ...fileStorage.php.map(f => ({ name: f.name, category: 'php' }))
        ];
        
        // Show/hide detection section based on available files
        if (pageFiles.length > 0) {
            pageDetectionSection.classList.add('show');
        } else {
            pageDetectionSection.classList.remove('show');
            clearPageDetection();
            return;
        }
        
        // Save current selections
        const currentHomepage = homepageSelect.value;
        const currentFeatured = featuredPageSelect.value;
        
        // Clear and repopulate dropdowns
        homepageSelect.innerHTML = '<option value="">-- Select Homepage File --</option>';
        featuredPageSelect.innerHTML = '<option value="">-- Select Featured Page File --</option>';
        
        pageFiles.forEach(file => {
            const optionHomepage = document.createElement('option');
            optionHomepage.value = file.name;
            optionHomepage.textContent = `${file.name} (${file.category.toUpperCase()})`;
            homepageSelect.appendChild(optionHomepage);
            
            const optionFeatured = document.createElement('option');
            optionFeatured.value = file.name;
            optionFeatured.textContent = `${file.name} (${file.category.toUpperCase()})`;
            featuredPageSelect.appendChild(optionFeatured);
        });
        
        // Restore selections if files still exist
        if (pageFiles.some(f => f.name === currentHomepage)) {
            homepageSelect.value = currentHomepage;
        }
        if (pageFiles.some(f => f.name === currentFeatured)) {
            featuredPageSelect.value = currentFeatured;
        }
        
        // Load saved detection from localStorage
        loadPageDetection();
        
        // Load custom homepage name
        loadCustomHomepageName();
        
        // Show custom homepage section if no homepage is detected yet
        const customHomepageSection = document.getElementById('customHomepageNameSection');
        if (customHomepageSection && !detectedHomepage) {
            customHomepageSection.classList.add('show');
        }
        
        // Ensure featured page dropdown is disabled if no homepage selected
        const featuredOverlay = document.getElementById('featuredPageDisabledOverlay');
        if (!detectedHomepage && featuredPageSelect) {
            featuredPageSelect.disabled = true;
            featuredPageSelect.innerHTML = '<option value="">-- Select Homepage First --</option>';
        }
        if (!detectedHomepage && featuredOverlay) {
            featuredOverlay.style.display = 'flex';
        }
    }

    // Handle homepage detection
    function handleHomepageDetection() {
        const select = document.getElementById('homepageFileSelect');
        const detectionItem = document.getElementById('homepageDetectionItem');
        const badge = document.getElementById('homepageBadge');
        const featuredPageSelect = document.getElementById('featuredPageFileSelect');
        const featuredPageItem = document.getElementById('featuredPageDetectionItem');
        const featuredPageOverlay = document.getElementById('featuredPageDisabledOverlay');
        const customHomepageSection = document.getElementById('customHomepageNameSection');
        
        if (select.value) {
            detectedHomepage = select.value;
            detectionItem.classList.add('detected');
            badge.textContent = 'Detected';
            
            // Enable featured page selection
            if (featuredPageSelect) {
                featuredPageSelect.disabled = false;
                featuredPageSelect.innerHTML = '<option value="">-- Select Featured Page File --</option>';
                // Repopulate with files excluding the selected homepage
                const pageFiles = [
                    ...fileStorage.html.map(f => ({ name: f.name, category: 'html' })),
                    ...fileStorage.php.map(f => ({ name: f.name, category: 'php' }))
                ];
                pageFiles.forEach(file => {
                    if (file.name !== select.value) { // Exclude selected homepage
                        const option = document.createElement('option');
                        option.value = file.name;
                        option.textContent = `${file.name} (${file.category.toUpperCase()})`;
                        featuredPageSelect.appendChild(option);
                    }
                });
            }
            if (featuredPageOverlay) {
                featuredPageOverlay.style.display = 'none';
            }
            if (featuredPageItem) {
                featuredPageItem.classList.remove('disabled');
            }
            
            // Hide custom homepage name section (since homepage is detected)
            if (customHomepageSection) {
                customHomepageSection.classList.remove('show');
            }
            
            // Hide "Create New Landing Page" option
            hideCreateNewLandingPageOption();
            
            // Hide "Home" from additional pages
            hideHomePageFromAdditionalPages();
            
            // Save to localStorage
            savePageDetection();
            
            showNotification(`Homepage detected: ${select.value}`, 'success');
        } else {
            detectedHomepage = null;
            detectionItem.classList.remove('detected');
            badge.textContent = 'Not Set';
            
            // Disable featured page selection
            if (featuredPageSelect) {
                featuredPageSelect.disabled = true;
                featuredPageSelect.innerHTML = '<option value="">-- Select Homepage First --</option>';
                featuredPageSelect.value = '';
            }
            if (featuredPageOverlay) {
                featuredPageOverlay.style.display = 'flex';
            }
            if (featuredPageItem) {
                featuredPageItem.classList.add('disabled');
            }
            
            // Clear featured page detection
            detectedFeaturedPage = null;
            const featuredBadge = document.getElementById('featuredPageBadge');
            if (featuredBadge) featuredBadge.textContent = 'Not Set';
            if (featuredPageItem) featuredPageItem.classList.remove('detected');
            
            // Show custom homepage name section
            if (customHomepageSection) {
                customHomepageSection.classList.add('show');
            }
            
            // Show "Create New Landing Page" option back
            showCreateNewLandingPageOption();
            
            // Show "Home" from additional pages back
            showHomePageInAdditionalPages();
            
            // Save to localStorage
            savePageDetection();
        }
        
        updatePageDetectionNotice();
    }
    
    // Global variable for custom homepage name
    let customHomepageName = 'index.html';
    
    // Handle custom homepage name change
    function handleCustomHomepageNameChange() {
        const input = document.getElementById('customHomepageNameInput');
        if (input) {
            const newName = input.value.trim() || 'index.html';
            customHomepageName = newName;
            
            // Update "Home" page label in additional pages to show the custom name
            updateHomePageLabelWithCustomName(newName);
            
            // Save to localStorage
            localStorage.setItem('customHomepageName', newName);
            
            console.log('🏠 Custom homepage name set to:', newName);
        }
    }
    
    // Update "Home" page label in additional pages with custom name
    function updateHomePageLabelWithCustomName(customName) {
        const homePageLabel = document.querySelector('label[data-page="home"] span');
        if (homePageLabel) {
            // Update the display name to show the custom filename
            const displayName = customName.replace(/\.(html|php|htm)$/i, '');
            const capitalizedName = displayName.charAt(0).toUpperCase() + displayName.slice(1);
            homePageLabel.textContent = `Home (${customName})`;
        }
    }
    
    // Load custom homepage name from localStorage
    function loadCustomHomepageName() {
        const saved = localStorage.getItem('customHomepageName');
        if (saved) {
            customHomepageName = saved;
            const input = document.getElementById('customHomepageNameInput');
            if (input) {
                input.value = saved !== 'index.html' ? saved : '';
            }
            updateHomePageLabelWithCustomName(saved);
        }
    }

    // Handle featured page detection
    function handleFeaturedPageDetection() {
        const select = document.getElementById('featuredPageFileSelect');
        const detectionItem = document.getElementById('featuredPageDetectionItem');
        const badge = document.getElementById('featuredPageBadge');
        
        if (select.value) {
            detectedFeaturedPage = select.value;
            detectionItem.classList.add('detected');
            badge.textContent = 'Detected';
            
            // Save to localStorage
            savePageDetection();
            
            showNotification(`Featured page detected: ${select.value}`, 'success');
        } else {
            detectedFeaturedPage = null;
            detectionItem.classList.remove('detected');
            badge.textContent = 'Not Set';
            
            // Save to localStorage
            savePageDetection();
        }
        
        updatePageDetectionNotice();
    }

    // Hide "Create New Landing Page" option
    function hideCreateNewLandingPageOption() {
        const homepageOptionBox = document.querySelector('.homepage-option-box');
        const createNewHomepageLabel = document.querySelector('.homepage-checkbox-label');
        const targetPagePicker = document.getElementById('targetPagePicker');
        const createNewHomepageCheckbox = document.getElementById('createNewHomepage');
        
        if (createNewHomepageLabel) {
            createNewHomepageLabel.style.display = 'none';
        }
        if (targetPagePicker) {
            targetPagePicker.style.display = 'none';
        }
        if (createNewHomepageCheckbox) {
            createNewHomepageCheckbox.checked = false;
            createNewHomepage = false;
            localStorage.setItem('createNewHomepage', 'false');
        }
        
        console.log('🏠 Homepage detected - "Create New Landing Page" option hidden');
    }

    // Show "Create New Landing Page" option back
    function showCreateNewLandingPageOption() {
        const createNewHomepageLabel = document.querySelector('.homepage-checkbox-label');
        
        // Only show if not in Preserve Mode
        const preserveRadio = document.getElementById('enhancementPreserve');
        const isPreserveMode = preserveRadio && preserveRadio.checked;
        
        if (createNewHomepageLabel && !isPreserveMode) {
            createNewHomepageLabel.style.display = '';
        }
        
        console.log('🏠 Homepage detection cleared - "Create New Landing Page" option shown');
    }

    // Hide "Home" page from additional pages
    function hideHomePageFromAdditionalPages() {
        const homePageLabel = document.querySelector('label[data-page="home"]');
        const homePageCheckbox = document.querySelector('input[name="create_pages"][value="home"]');
        
        if (homePageLabel) {
            homePageLabel.style.display = 'none';
        }
        if (homePageCheckbox) {
            homePageCheckbox.checked = false;
        }
        
        updateSelectedPagesCount();
        console.log('🏠 Homepage detected - "Home" page hidden from additional pages');
    }

    // Show "Home" page in additional pages back
    function showHomePageInAdditionalPages() {
        const homePageLabel = document.querySelector('label[data-page="home"]');
        
        if (homePageLabel) {
            homePageLabel.style.display = '';
        }
        
        updateSelectedPagesCount();
        console.log('🏠 Homepage detection cleared - "Home" page shown in additional pages');
    }

    // Update page detection notice
    function updatePageDetectionNotice() {
        const notice = document.getElementById('pageDetectionNotice');
        const noticeText = document.getElementById('pageDetectionNoticeText');
        
        if (!notice || !noticeText) return;
        
        if (detectedHomepage || detectedFeaturedPage) {
            let message = '<i class="fas fa-check-circle"></i> ';
            const detections = [];
            
            if (detectedHomepage) {
                detections.push(`Homepage: <strong>${detectedHomepage}</strong>`);
            }
            if (detectedFeaturedPage) {
                detections.push(`Featured: <strong>${detectedFeaturedPage}</strong>`);
            }
            
            message += detections.join(' | ');
            
            if (detectedHomepage) {
                message += '<br><small style="color: var(--text-muted);"><i class="fas fa-info-circle"></i> "Create New Landing Page" and "Home" page options have been hidden.</small>';
            }
            
            noticeText.innerHTML = message;
            notice.classList.add('show');
        } else {
            notice.classList.remove('show');
        }
    }

    // Save page detection to localStorage
    function savePageDetection() {
        const detectionData = {
            homepage: detectedHomepage,
            featuredPage: detectedFeaturedPage
        };
        localStorage.setItem('pageDetection', JSON.stringify(detectionData));
        console.log('💾 Page detection saved:', detectionData);
    }

    // Load page detection from localStorage
    function loadPageDetection() {
        try {
            const saved = localStorage.getItem('pageDetection');
            if (saved) {
                const detectionData = JSON.parse(saved);
                
                const homepageSelect = document.getElementById('homepageFileSelect');
                const featuredPageSelect = document.getElementById('featuredPageFileSelect');
                
                // Check if saved files still exist in uploads
                const pageFiles = [
                    ...fileStorage.html.map(f => f.name),
                    ...fileStorage.php.map(f => f.name)
                ];
                
                // Restore homepage detection if file exists
                if (detectionData.homepage && pageFiles.includes(detectionData.homepage)) {
                    homepageSelect.value = detectionData.homepage;
                    handleHomepageDetection();
                }
                
                // Restore featured page detection if file exists
                if (detectionData.featuredPage && pageFiles.includes(detectionData.featuredPage)) {
                    featuredPageSelect.value = detectionData.featuredPage;
                    handleFeaturedPageDetection();
                }
                
                console.log('📂 Page detection loaded:', detectionData);
            }
        } catch (e) {
            console.error('Error loading page detection:', e);
        }
    }

    // Clear page detection
    function clearPageDetection() {
        detectedHomepage = null;
        detectedFeaturedPage = null;
        
        const homepageSelect = document.getElementById('homepageFileSelect');
        const featuredPageSelect = document.getElementById('featuredPageFileSelect');
        const pageDetectionSection = document.getElementById('pageDetectionSection');
        
        if (homepageSelect) homepageSelect.value = '';
        if (featuredPageSelect) featuredPageSelect.value = '';
        if (pageDetectionSection) pageDetectionSection.classList.remove('show');
        
        // Reset UI elements
        const homepageItem = document.getElementById('homepageDetectionItem');
        const featuredItem = document.getElementById('featuredPageDetectionItem');
        const homepageBadge = document.getElementById('homepageBadge');
        const featuredBadge = document.getElementById('featuredPageBadge');
        const notice = document.getElementById('pageDetectionNotice');
        
        if (homepageItem) homepageItem.classList.remove('detected');
        if (featuredItem) featuredItem.classList.remove('detected');
        if (homepageBadge) homepageBadge.textContent = 'Not Set';
        if (featuredBadge) featuredBadge.textContent = 'Not Set';
        if (notice) notice.classList.remove('show');
        
        // Show hidden options back
        showCreateNewLandingPageOption();
        showHomePageInAdditionalPages();
        
        // Clear from localStorage
        localStorage.removeItem('pageDetection');
        
        console.log('🗑️ Page detection cleared');
    }

    // Apply all files (prepare for prompt generation)
    function applyAllFiles() {
        const totalFiles = Object.values(fileStorage).reduce((sum, arr) => sum + arr.length, 0);

        if (totalFiles === 0) {
            showNotification('No files to apply', 'warning');
            return;
        }

        // Store in localStorage for next step
        const filesSummary = {
            html: fileStorage.html.map(f => ({
                name: f.name,
                size: f.size
            })),
            css: fileStorage.css.map(f => ({
                name: f.name,
                size: f.size
            })),
            javascript: fileStorage.javascript.map(f => ({
                name: f.name,
                size: f.size
            })),
            php: fileStorage.php.map(f => ({
                name: f.name,
                size: f.size
            })),
            images: fileStorage.images.map(f => ({
                name: f.name,
                size: f.size
            })),
            documents: fileStorage.documents.map(f => ({
                name: f.name,
                size: f.size
            })),
            other: fileStorage.other.map(f => ({
                name: f.name,
                size: f.size
            }))
        };

        localStorage.setItem('filesSummary', JSON.stringify(filesSummary));
        localStorage.setItem('filesApplied', 'true');

        showNotification(`✅ ${totalFiles} file(s) applied and ready for prompt generation!`, 'success');

        // Disable apply button
        document.getElementById('applyAllBtn').disabled = true;
        document.getElementById('applyAllBtn').innerHTML = '<i class="fas fa-check"></i> Files Applied';

        console.log('📦 Files applied:', filesSummary);
    }

    // Format file size helper
    function formatFileSize(bytes) {
        if (bytes === 0) return '0 B';
        const k = 1024;
        const sizes = ['B', 'KB', 'MB', 'GB'];
        const i = Math.floor(Math.log(bytes) / Math.log(k));
        return Math.round((bytes / Math.pow(k, i)) * 100) / 100 + ' ' + sizes[i];
    }

    // Initialize file system on load - ensure DOM is ready
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', function() {
            initFileSystem();
        });
    } else {
        // DOM is already ready
        initFileSystem();
    }

    console.log('✅ Step 2: File Upload System + Smart Distribution - COMPLETE');

    // ============================================
    // STEP 3 & 4: OPTIONS MANAGEMENT + PROMPT GENERATION
    // Enhanced LocalStorage + AI Prompt Builder
    // ============================================

    // Enhancement Options Storage
    const enhancementOptions = {
        layout: true,
        colors: true,
        animations: true,
        responsive: true,
        modern: true,
        seo: true,
        level: 'moderate',
        style: 'ai-choice',
        instructions: ''
    };

    // Update SEO option
    function updateSEOOption() {
        const seoCheckbox = document.getElementById('opt_seo');
        const seoDetails = document.getElementById('seoFeatureDetails');

        enhancementOptions.seo = seoCheckbox?.checked || false;

        // Show/hide feature details
        if (seoDetails) {
            seoDetails.style.display = enhancementOptions.seo ? 'flex' : 'none';
        }

        // Update visual state
        if (seoCheckbox) {
            const label = seoCheckbox.closest('.checkbox-item');
            if (label) {
                label.classList.toggle('checked', enhancementOptions.seo);
            }
        }

        // Save to localStorage
        localStorage.setItem('opt_seo', enhancementOptions.seo);

        console.log('✅ SEO option updated:', enhancementOptions.seo);
    }

    // Toggle SEO option visual state
    function toggleSEOOption(label) {
        const checkbox = label.querySelector('input[type="checkbox"]');
        if (checkbox) {
            setTimeout(() => {
                if (checkbox.checked) {
                    label.classList.add('checked');
                } else {
                    label.classList.remove('checked');
                }
            }, 10);
        }
    }

    // Update options when checkboxes change
    function updateOptions() {
        // Update focus areas
        enhancementOptions.layout = document.getElementById('opt_layout')?.checked || false;
        enhancementOptions.colors = document.getElementById('opt_colors')?.checked || false;
        enhancementOptions.animations = document.getElementById('opt_animations')?.checked || false;
        enhancementOptions.responsive = document.getElementById('opt_responsive')?.checked || false;
        enhancementOptions.modern = document.getElementById('opt_modern')?.checked || false;
        enhancementOptions.seo = document.getElementById('opt_seo')?.checked || false;

        // Update enhancement level
        const levelRadios = document.querySelectorAll('input[name="enhancement_level"]');
        levelRadios.forEach(radio => {
            if (radio.checked) {
                enhancementOptions.level = radio.value;
                // Update UI for selected radio
                document.querySelectorAll('[data-level]').forEach(item => {
                    item.classList.remove('checked');
                });
                radio.closest('.checkbox-item').classList.add('checked');
            }
        });
        
        // Handle "Preserve Design" mode - hide irrelevant sections
        handlePreserveModeVisibility(enhancementOptions.level);

        // Update checkbox UI
        document.querySelectorAll('[data-option] input[type="checkbox"]').forEach(checkbox => {
            const parent = checkbox.closest('.checkbox-item');
            if (checkbox.checked) {
                parent.classList.add('checked');
            } else {
                parent.classList.remove('checked');
            }
        });

        // Update additional instructions
        const textarea = document.getElementById('additionalInstructions');
        if (textarea) {
            enhancementOptions.instructions = textarea.value;
            // Update character count
            const charCount = document.getElementById('charCount');
            if (charCount) {
                charCount.textContent = textarea.value.length + ' characters';
            }
        }

        // Update enhancement style
        const styleRadios = document.querySelectorAll('input[name="enhancement_style"]');
        styleRadios.forEach(radio => {
            if (radio.checked) {
                enhancementOptions.style = radio.value;
            }
        });

        // Save to localStorage
        localStorage.setItem('enhancementOptions', JSON.stringify(enhancementOptions));

        console.log('Options updated:', enhancementOptions);
    }
    
    // Handle "Preserve Design" mode - hide/show sections based on enhancement level
    function handlePreserveModeVisibility(level) {
        // Sections to hide when "preserve" mode is selected (not relevant to preserving design)
        const sectionsToHideInPreserveMode = [
            'designStyleSection',        // Enhanced Style Types - not needed, keeping current style
            'colorThemeSection',         // Design Theme Selection - theme is already in the preserved design
            'layoutSection',             // Page Layout Structure - layout is preserved from original
            'referenceImagesSection',    // Visual Design Reference - not changing visual design
            'logoBrandingSection'        // Logo & Branding - keeping existing branding
        ];
        
        // Sidebar section names that correspond to the hidden sections
        const sidebarSectionsToDisable = [
            'designStyle',
            'colorTheme', 
            'layout',
            'referenceImages',
            'logoBranding'
        ];
        
        const isPreserveMode = level === 'preserve';
        
        // Hide/show main sections
        sectionsToHideInPreserveMode.forEach(sectionId => {
            const section = document.getElementById(sectionId);
            if (section) {
                if (isPreserveMode) {
                    // Hide section with smooth animation
                    section.style.transition = 'opacity 0.3s ease, max-height 0.4s ease, margin 0.3s ease, padding 0.3s ease';
                    section.style.opacity = '0';
                    section.style.maxHeight = '0';
                    section.style.overflow = 'hidden';
                    section.style.marginTop = '0';
                    section.style.marginBottom = '0';
                    section.style.paddingTop = '0';
                    section.style.paddingBottom = '0';
                    setTimeout(() => {
                        section.style.display = 'none';
                    }, 400);
                } else {
                    // Show section with smooth animation
                    section.style.display = '';
                    section.style.transition = 'opacity 0.3s ease, max-height 0.4s ease, margin 0.3s ease, padding 0.3s ease';
                    setTimeout(() => {
                        section.style.opacity = '1';
                        section.style.maxHeight = '';
                        section.style.overflow = '';
                        section.style.marginTop = '';
                        section.style.marginBottom = '';
                        section.style.paddingTop = '';
                        section.style.paddingBottom = '';
                    }, 10);
                }
            }
        });
        
        // Disable/enable sidebar items for hidden sections
        sidebarSectionsToDisable.forEach(sectionName => {
            const sidebarItem = document.querySelector(`.sidebar-item[data-section="${sectionName}"]`);
            if (sidebarItem) {
                if (isPreserveMode) {
                    sidebarItem.style.opacity = '0.4';
                    sidebarItem.style.pointerEvents = 'none';
                    sidebarItem.style.filter = 'grayscale(1)';
                    sidebarItem.title = 'Not available in Preserve Design mode';
                } else {
                    sidebarItem.style.opacity = '';
                    sidebarItem.style.pointerEvents = '';
                    sidebarItem.style.filter = '';
                    sidebarItem.title = '';
                }
            }
        });
        
        // Show a notification/info message when preserve mode is active
        updatePreserveModeNotification(isPreserveMode);
        
        console.log(`🛡️ Preserve mode: ${isPreserveMode ? 'ACTIVE - hiding design sections' : 'INACTIVE - showing all sections'}`);
    }
    
    // Show/hide preserve mode notification
    function updatePreserveModeNotification(isPreserveMode) {
        let notification = document.getElementById('preserveModeNotification');
        
        if (isPreserveMode && !notification) {
            // Create notification if doesn't exist
            notification = document.createElement('div');
            notification.id = 'preserveModeNotification';
            notification.innerHTML = `
                <div style="
                    background: linear-gradient(135deg, rgba(34, 197, 94, 0.15) 0%, rgba(16, 185, 129, 0.15) 100%);
                    border: 2px solid rgba(34, 197, 94, 0.4);
                    border-radius: 12px;
                    padding: 1rem 1.25rem;
                    margin-bottom: 1.5rem;
                    display: flex;
                    align-items: center;
                    gap: 1rem;
                    animation: slideDown 0.4s ease;
                ">
                    <div style="
                        width: 45px;
                        height: 45px;
                        background: linear-gradient(135deg, #22c55e 0%, #10b981 100%);
                        border-radius: 12px;
                        display: flex;
                        align-items: center;
                        justify-content: center;
                        flex-shrink: 0;
                    ">
                        <i class="fas fa-shield-alt" style="color: white; font-size: 1.3rem;"></i>
                    </div>
                    <div>
                        <strong style="color: #22c55e; font-size: 1rem; display: block; margin-bottom: 0.25rem;">
                            🛡️ Preserve Design Mode Active
                        </strong>
                        <p style="color: var(--text-secondary); font-size: 0.85rem; margin: 0; line-height: 1.4;">
                            Design-related sections are hidden. Only bug fixes, functionality improvements, and new features will be generated.
                            The current visual design will remain 100% unchanged.
                        </p>
                    </div>
                </div>
            `;
            
            // Insert after enhancement level section
            const enhancementLevelSection = document.querySelector('.card:has([name="enhancement_level"])');
            if (enhancementLevelSection && enhancementLevelSection.parentNode) {
                enhancementLevelSection.parentNode.insertBefore(notification, enhancementLevelSection.nextSibling);
            }
        } else if (!isPreserveMode && notification) {
            // Remove notification with animation
            notification.style.transition = 'opacity 0.3s ease, max-height 0.3s ease';
            notification.style.opacity = '0';
            notification.style.maxHeight = '0';
            notification.style.overflow = 'hidden';
            setTimeout(() => {
                notification.remove();
            }, 300);
        }
    }

    // Update Enhancement Style (Override global function) - Now supports multiple selections
    window.updateEnhancementStyle = function() {
        const checkboxes = document.querySelectorAll('input[name="enhancement_style"]');
        const selectedStyles = [];

        checkboxes.forEach(checkbox => {
            const parent = checkbox.closest('.checkbox-item');
            if (checkbox.checked) {
                selectedStyles.push(checkbox.value);
                parent.classList.add('checked');
            } else {
                parent.classList.remove('checked');
            }
        });

        // Update enhancementOptions with array of styles
        enhancementOptions.styles = selectedStyles;
        enhancementOptions.style = selectedStyles.length > 0 ? selectedStyles[0] :
            ''; // Keep for backward compatibility

        // Update style count badge
        const countBadge = document.getElementById('styleCountBadge');
        const countText = document.getElementById('styleCountText');
        if (countBadge && countText) {
            if (selectedStyles.length > 0) {
                countBadge.style.display = 'flex';
                countBadge.style.alignItems = 'center';
                countBadge.style.gap = '0.4rem';
                countText.textContent =
                    `${selectedStyles.length} style${selectedStyles.length > 1 ? 's' : ''} selected`;

                // Change color based on count
                if (selectedStyles.length === 1) {
                    countBadge.style.background = 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)';
                } else if (selectedStyles.length <= 3) {
                    countBadge.style.background = 'linear-gradient(135deg, #10b981 0%, #059669 100%)';
                } else if (selectedStyles.length <= 5) {
                    countBadge.style.background = 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)';
                } else {
                    countBadge.style.background = 'linear-gradient(135deg, #ec4899 0%, #db2777 100%)';
                }
            } else {
                countBadge.style.display = 'none';
            }
        }

        // Update live preview
        updateLivePreview(selectedStyles);

        // Save to localStorage
        localStorage.setItem('enhancementOptions', JSON.stringify(enhancementOptions));

        console.log('✅ Enhancement styles selected:', selectedStyles);

        // Update Read First checkbox based on AI Decision
        if (typeof updateReadFirstCheckbox === 'function') {
            updateReadFirstCheckbox();
        }
    };

    // Reset Style Selection
    window.resetStyleSelection = function() {
        const checkboxes = document.querySelectorAll('input[name="enhancement_style"]');
        checkboxes.forEach(checkbox => {
            checkbox.checked = false;
            const parent = checkbox.closest('.checkbox-item');
            parent.classList.remove('checked');
        });

        // Clear enhancementOptions
        enhancementOptions.styles = [];
        enhancementOptions.style = '';

        // Reset preview
        updateLivePreview([]);

        // Save to localStorage
        localStorage.setItem('enhancementOptions', JSON.stringify(enhancementOptions));

        console.log('🔄 All styles reset');
    };

