    // Scroll to Top of Styles Container
    window.scrollStylesToTop = function() {
        const container = document.getElementById('stylesScrollContainer');
        if (container) {
            container.scrollTo({
                top: 0,
                behavior: 'smooth'
            });
        }
    };

    // Scroll to Bottom of Styles Container
    window.scrollStylesToBottom = function() {
        const container = document.getElementById('stylesScrollContainer');
        if (container) {
            container.scrollTo({
                top: container.scrollHeight,
                behavior: 'smooth'
            });
        }
    };

    // Search Styles Function
    window.searchStyles = function(searchTerm) {
        const styles = document.querySelectorAll('.checkbox-item[data-style]');
        const term = searchTerm.toLowerCase().trim();

        let visibleCount = 0;

        styles.forEach(style => {
            const styleName = style.getAttribute('data-style') || '';
            const styleText = style.textContent.toLowerCase();

            if (term === '' || styleText.includes(term) || styleName.includes(term)) {
                style.style.display = 'flex';
                visibleCount++;
            } else {
                style.style.display = 'none';
            }
        });

        // Show message if no results
        let noResultsMsg = document.getElementById('noStyleResults');
        if (visibleCount === 0 && term !== '') {
            if (!noResultsMsg) {
                noResultsMsg = document.createElement('div');
                noResultsMsg.id = 'noStyleResults';
                noResultsMsg.style.cssText =
                    'padding: 2rem; text-align: center; color: var(--text-muted); font-size: 1.1rem;';
                noResultsMsg.innerHTML =
                    '<i class="fas fa-search" style="font-size: 2rem; opacity: 0.3; display: block; margin-bottom: 1rem;"></i>No styles found matching "' +
                    searchTerm + '"';
                document.getElementById('stylesScrollContainer').appendChild(noResultsMsg);
            } else {
                noResultsMsg.style.display = 'block';
                noResultsMsg.innerHTML =
                    '<i class="fas fa-search" style="font-size: 2rem; opacity: 0.3; display: block; margin-bottom: 1rem;"></i>No styles found matching "' +
                    searchTerm + '"';
            }
        } else if (noResultsMsg) {
            noResultsMsg.style.display = 'none';
        }

        console.log('🔍 Search results:', visibleCount, 'styles found for:', term);
    };

    // Add hover effects to scroll buttons
    document.addEventListener('DOMContentLoaded', function() {
        const scrollTopBtn = document.getElementById('scrollToTopBtn');
        const scrollBottomBtn = document.getElementById('scrollToBottomBtn');

        if (scrollTopBtn) {
            scrollTopBtn.addEventListener('mouseenter', function() {
                this.style.transform = 'scale(1.1)';
                this.style.boxShadow = '0 6px 20px rgba(102, 126, 234, 0.6)';
            });
            scrollTopBtn.addEventListener('mouseleave', function() {
                this.style.transform = 'scale(1)';
                this.style.boxShadow = '0 4px 15px rgba(102, 126, 234, 0.4)';
            });
        }

        if (scrollBottomBtn) {
            scrollBottomBtn.addEventListener('mouseenter', function() {
                this.style.transform = 'scale(1.1)';
                this.style.boxShadow = '0 6px 20px rgba(240, 147, 251, 0.6)';
            });
            scrollBottomBtn.addEventListener('mouseleave', function() {
                this.style.transform = 'scale(1)';
                this.style.boxShadow = '0 4px 15px rgba(240, 147, 251, 0.4)';
            });
        }

        // Add focus effect to search box
        const searchBox = document.getElementById('styleSearchBox');
        if (searchBox) {
            searchBox.addEventListener('focus', function() {
                this.style.borderColor = '#667eea';
                this.style.boxShadow = '0 0 0 3px rgba(102, 126, 234, 0.1)';
            });
            searchBox.addEventListener('blur', function() {
                this.style.borderColor = 'rgba(102, 126, 234, 0.3)';
                this.style.boxShadow = 'none';
            });
        }
    });

    // Documentation file management
    let documentationFileContent = null;
    let documentationFileName = null;
    let integrationMode = 'ai-decision'; // Default mode

    function toggleDocumentationUpload() {
        const checkbox = document.getElementById('enableDocumentation');
        const uploadSection = document.getElementById('documentationUploadSection');

        if (checkbox.checked) {
            uploadSection.style.display = 'block';
            // Animate in
            setTimeout(() => {
                uploadSection.style.opacity = '1';
                uploadSection.style.transform = 'translateY(0)';
            }, 10);
        } else {
            uploadSection.style.display = 'none';
            // Clear file if unchecked
            removeDocumentationFile();
            // Hide integration mode section
            document.getElementById('integrationModeSection').style.display = 'none';
        }
    }

    function toggleEmailInput() {
        const checkbox = document.getElementById('enableFormSubmit');
        const emailSection = document.getElementById('emailInputSection');

        if (checkbox.checked) {
            emailSection.style.display = 'block';
            // Focus on email input
            setTimeout(() => {
                document.getElementById('contactEmail').focus();
            }, 100);
            // Save checkbox state
            localStorage.setItem('enableFormSubmit', 'true');
            console.log('✅ FormSubmit.co enabled');
        } else {
            emailSection.style.display = 'none';
            // Save checkbox state
            localStorage.setItem('enableFormSubmit', 'false');
            console.log('❌ FormSubmit.co disabled');
        }
    }

    // Save email when it changes
    function saveContactEmail() {
        const email = document.getElementById('contactEmail').value.trim();
        if (email) {
            localStorage.setItem('formSubmitEmail', email);
            console.log('💾 Email saved:', email);
        }
    }

    function updateIntegrationMode() {
        const radios = document.querySelectorAll('input[name="integration_mode"]');
        radios.forEach(radio => {
            const parent = radio.closest('.checkbox-item');
            if (radio.checked) {
                integrationMode = radio.value;
                parent.classList.add('checked');
                console.log('✅ Integration mode selected:', integrationMode);
            } else {
                parent.classList.remove('checked');
            }
        });

        // Save to localStorage
        localStorage.setItem('integrationMode', integrationMode);
    }

    function handleDocumentationUpload(event) {
        const file = event.target.files[0];
        if (!file) return;

        documentationFileName = file.name;
        const fileSize = formatFileSize(file.size);

        // Display file info
        document.getElementById('fileName').textContent = file.name;
        document.getElementById('fileSize').textContent = fileSize;

        // Read file content
        const reader = new FileReader();
        reader.onload = function(e) {
            documentationFileContent = e.target.result;

            // Show preview (first 500 characters)
            const preview = documentationFileContent.substring(0, 500);
            document.getElementById('filePreview').textContent = preview + (documentationFileContent.length > 500 ?
                '\n\n...(truncated)' : '');

            // Show file info display
            document.getElementById('fileInfoDisplay').style.display = 'block';

            // Show integration mode section
            const modeSection = document.getElementById('integrationModeSection');
            modeSection.style.display = 'block';

            // Initialize mode selection UI
            updateIntegrationMode();

            showNotification('📄 Documentation file loaded successfully!', 'success');
            console.log('Documentation loaded:', file.name, 'Size:', fileSize);
        };

        reader.onerror = function() {
            showNotification('❌ Error reading file. Please try again.', 'error');
        };

        reader.readAsText(file);
    }

    function removeDocumentationFile() {
        documentationFileContent = null;
        documentationFileName = null;

        // Clear file input
        document.getElementById('documentationFile').value = '';

        // Hide file info display
        document.getElementById('fileInfoDisplay').style.display = 'none';

        // Hide integration mode section
        document.getElementById('integrationModeSection').style.display = 'none';

        // Clear preview
        document.getElementById('filePreview').textContent = '';

        showNotification('🗑️ Documentation file removed', 'info');
    }

    // Load saved options on page load
    function loadSavedOptions() {
        const saved = localStorage.getItem('enhancementOptions');
        if (saved) {
            const options = JSON.parse(saved);

            // Restore checkboxes
            if (document.getElementById('opt_layout')) document.getElementById('opt_layout').checked = options.layout;
            if (document.getElementById('opt_colors')) document.getElementById('opt_colors').checked = options.colors;
            if (document.getElementById('opt_animations')) document.getElementById('opt_animations').checked = options
                .animations;
            if (document.getElementById('opt_responsive')) document.getElementById('opt_responsive').checked = options
                .responsive;
            if (document.getElementById('opt_modern')) document.getElementById('opt_modern').checked = options.modern;

            // Restore SEO option (default to true if not saved)
            const seoCheckbox = document.getElementById('opt_seo');
            const seoDetails = document.getElementById('seoFeatureDetails');
            if (seoCheckbox) {
                seoCheckbox.checked = options.seo !== false; // Default to true
                const label = seoCheckbox.closest('.checkbox-item');
                if (label) label.classList.toggle('checked', seoCheckbox.checked);
            }
            if (seoDetails) {
                seoDetails.style.display = (options.seo !== false) ? 'flex' : 'none';
            }
            enhancementOptions.seo = options.seo !== false;

            // Restore level
            if (options.level) {
                const levelRadio = document.getElementById('level_' + options.level);
                if (levelRadio) levelRadio.checked = true;
                // Apply preserve mode visibility if needed
                handlePreserveModeVisibility(options.level);
            }

            // Restore enhancement styles (supports multiple selections)
            if (options.styles && Array.isArray(options.styles)) {
                options.styles.forEach(styleValue => {
                    const styleCheckbox = document.getElementById('style_' + styleValue.replace(/-/g, '_'));
                    if (styleCheckbox) {
                        styleCheckbox.checked = true;
                    }
                });
                updateEnhancementStyle();
            } else if (options.style) {
                // Backward compatibility - single style
                const styleCheckbox = document.getElementById('style_' + options.style.replace(/-/g, '_'));
                if (styleCheckbox) {
                    styleCheckbox.checked = true;
                    updateEnhancementStyle();
                }
            }

            // Restore instructions
            if (options.instructions) {
                const textarea = document.getElementById('additionalInstructions');
                if (textarea) textarea.value = options.instructions;
            }

            // Update UI
            updateOptions();

            console.log('Saved options loaded');
        }
    }

