            console.log('📺 Displaying prompt in UI...');
            const promptContentElement = document.getElementById('promptContent');
            const promptOutputElement = document.getElementById('promptOutputSection');

            if (!promptContentElement || !promptOutputElement) {
                console.error('❌ ERROR: Prompt display elements not found!');
                showNotification('❌ Error: Display elements not found. Please refresh the page.', 'error');
                return;
            }

            promptContentElement.textContent = prompt;
            promptOutputElement.style.display = 'block';

            // Scroll to prompt
            setTimeout(() => {
                promptOutputElement.scrollIntoView({
                    behavior: 'smooth',
                    block: 'start'
                });
