            console.log(`🔍 SEO & Keywords: ${enhancementOptions.seo ? '✅ YES' : '❌ NO'}`);
            console.log(`🖼️ Reference Images: ${referenceImages.length}`);
            console.log(`🚫 Excluded Files: ${excludedFiles.length}`);
