            );
            console.log(
                `📖 Execution Mode Type: ${isReadBeforeMode ? '✅ Read Before Executing' : '⚡ Default Process'}`);
            console.log(`📊 Reading Steps: ${readingSteps} of ${taskParts} parts`);
            console.log(`📊 Task Parts: ${taskParts}`);
            console.log(`⚙️ Execution Mode: ${executionMode}`);
            console.log('');

            if (isDocEnabled && documentationFileContent) {
