    // Load saved data on page load
    function loadAllSavedData() {
        loadSavedOptions();
        
        // Load optimize token limit setting
        loadOptimizeTokenLimit();

        // Check if files were applied
        const filesApplied = localStorage.getItem('filesApplied');
        if (filesApplied === 'true') {
            const applyBtn = document.getElementById('applyAllBtn');
            if (applyBtn) {
                applyBtn.disabled = true;
                applyBtn.innerHTML = '<i class="fas fa-check"></i> Files Applied';
            }
        }

        // Load generated prompt if exists
        const savedPrompt = localStorage.getItem('generatedPrompt');
        if (savedPrompt) {
            document.getElementById('promptContent').textContent = savedPrompt;
            // Don't show automatically - user can regenerate if needed
        }

        // Load logo branding data
        if (window.loadSavedLogoData) {
            window.loadSavedLogoData();
        }

        // Load FormSubmit.co state
        const savedFormSubmit = localStorage.getItem('enableFormSubmit');
        const formSubmitCheckbox = document.getElementById('enableFormSubmit');
        const emailInputSection = document.getElementById('emailInputSection');
        const contactEmailInput = document.getElementById('contactEmail');
        const savedEmail = localStorage.getItem('formSubmitEmail');

        if (formSubmitCheckbox && savedFormSubmit === 'true') {
            formSubmitCheckbox.checked = true;
            if (emailInputSection) {
                emailInputSection.style.display = 'block';
            }
            if (contactEmailInput && savedEmail) {
                contactEmailInput.value = savedEmail;
            }
            console.log('✅ FormSubmit state restored');
        }

        // Load execution mode type
        const savedExecModeType = localStorage.getItem('executionModeType');
        if (savedExecModeType) {
            const execModeSelect = document.getElementById('executionModeSelect');
            if (execModeSelect) {
                execModeSelect.value = savedExecModeType;
                if (typeof updateExecutionModeType === 'function') {
                    updateExecutionModeType();
                }
            }
            console.log('✅ Execution mode type restored:', savedExecModeType);
        }

        console.log('✅ All saved data loaded');
    }

    // Initialize on load
    setTimeout(() => {
        loadAllSavedData();
        updateOptions();
    }, 100);

