    // Update Homepage Option
    window.updateHomepageOption = function updateHomepageOption() {
        console.log('🏠 updateHomepageOption() called');

        const checkbox = document.getElementById('createNewHomepage');
        console.log('   Checkbox found:', !!checkbox);
        console.log('   Checkbox checked:', checkbox ? checkbox.checked : 'N/A');

        createNewHomepage = checkbox ? checkbox.checked : false;

        // Toggle info boxes
        const infoUnchecked = document.getElementById('homepageInfoUnchecked');
        const infoChecked = document.getElementById('homepageInfoChecked');
        const targetPagePicker = document.getElementById('targetPagePicker');

        console.log('   Target page picker found:', !!targetPagePicker);

        if (createNewHomepage) {
            console.log('   Showing target page picker...');
            if (infoUnchecked) infoUnchecked.style.display = 'none';
            if (infoChecked) infoChecked.style.display = 'flex';
            if (targetPagePicker) {
                targetPagePicker.style.display = 'block';
                console.log('   ✅ Target page picker displayed');
            }
        } else {
            console.log('   Hiding target page picker...');
            if (infoUnchecked) infoUnchecked.style.display = 'flex';
            if (infoChecked) infoChecked.style.display = 'none';
            if (targetPagePicker) {
                targetPagePicker.style.display = 'none';
            }
        }

        // Save to localStorage
        localStorage.setItem('createNewHomepage', createNewHomepage);

        // Update homepage integration note for pages creation
        if (typeof updateHomepageIntegrationNote === 'function') {
            updateHomepageIntegrationNote();
        }

        console.log('✅ Homepage option updated:', createNewHomepage ? 'Create New' : 'Enhance Existing');
    }

    // Handle Target Page Selection
    window.handleTargetPageSelection = function handleTargetPageSelection() {
        const fileInput = document.getElementById('targetPageFile');
        const fileNameDisplay = document.getElementById('targetPageFileName');
        const fileLabel = document.querySelector('.file-picker-label');
        const clearBtn = document.getElementById('clearTargetBtn');

        if (fileInput && fileInput.files && fileInput.files.length > 0) {
            targetPageFile = fileInput.files[0];
            targetPageFileName = targetPageFile.name;

            // Update UI
            if (fileNameDisplay) {
                fileNameDisplay.textContent = targetPageFileName;
            }
            if (fileLabel) {
                fileLabel.classList.add('has-file');
            }
            if (clearBtn) {
                clearBtn.style.display = 'inline-flex';
            }

            // Save to localStorage
            localStorage.setItem('targetPageFileName', targetPageFileName);

            showNotification(`✅ Target page selected: ${targetPageFileName}`, 'success');
            console.log('Target page selected:', targetPageFileName);
        }
    }

    // Clear Target Page
    window.clearTargetPage = function clearTargetPage() {
        const fileInput = document.getElementById('targetPageFile');
        const fileNameDisplay = document.getElementById('targetPageFileName');
        const fileLabel = document.querySelector('.file-picker-label');
        const clearBtn = document.getElementById('clearTargetBtn');

        // Reset file input
        if (fileInput) {
            fileInput.value = '';
        }

        // Reset state
        targetPageFile = null;
        targetPageFileName = '';

        // Update UI
        if (fileNameDisplay) {
            fileNameDisplay.textContent = 'No file selected (will use current homepage)';
        }
        if (fileLabel) {
            fileLabel.classList.remove('has-file');
        }
        if (clearBtn) {
            clearBtn.style.display = 'none';
        }

        // Clear localStorage
        localStorage.removeItem('targetPageFileName');

        showNotification('Target page cleared', 'info');
        console.log('Target page cleared');
    }

    // ============================================
    // PAGES CREATION SYSTEM
    // ============================================

    // Global variable to store selected pages
    let selectedPagesToCreate = [];

    // Toggle Pages Creation Section
    window.togglePagesCreation = function togglePagesCreation() {
        console.log('📄 togglePagesCreation() called');

        const checkbox = document.getElementById('enablePagesCreation');
        const container = document.getElementById('pagesSelectionContainer');
        const integrationNote = document.getElementById('homepageIntegrationNote');

        console.log('   Checkbox found:', !!checkbox);
        console.log('   Checkbox checked:', checkbox ? checkbox.checked : 'N/A');
        console.log('   Container found:', !!container);

        if (checkbox && container) {
            if (checkbox.checked) {
                console.log('   Showing pages selection container...');
                container.style.display = 'block';
                // Animate in
                container.style.opacity = '0';
                container.style.transform = 'translateY(-10px)';
                setTimeout(() => {
                    container.style.transition = 'all 0.3s ease';
                    container.style.opacity = '1';
                    container.style.transform = 'translateY(0)';
                }, 10);
                console.log('   ✅ Pages container displayed');
                showNotification('📄 Page creation enabled - select pages to create', 'info');
            } else {
                console.log('   Hiding pages selection container...');
                container.style.display = 'none';
                // Uncheck all pages when disabling
                uncheckAllPages();
            }

            // Update integration note visibility
            if (typeof updateHomepageIntegrationNote === 'function') {
                updateHomepageIntegrationNote();
            }
        } else {
            console.error('   ❌ Checkbox or container not found!');
        }

        // Save state
        localStorage.setItem('enablePagesCreation', checkbox ? checkbox.checked : false);

        console.log('✅ Pages creation:', checkbox && checkbox.checked ? 'Enabled' : 'Disabled');
    }

    // Check All Pages
    window.checkAllPages = function checkAllPages() {
        const checkboxes = document.querySelectorAll('input[name="create_pages"]');
        checkboxes.forEach(checkbox => {
            checkbox.checked = true;
            // Trigger visual update
            const item = checkbox.closest('.page-checkbox-item');
            if (item) {
                item.classList.add('checked');
            }
        });
        updateSelectedPagesCount();
        updateHomepageIntegrationNote();
        showNotification('✅ All pages selected', 'success');
    }

    // Uncheck All Pages
    window.uncheckAllPages = function uncheckAllPages() {
        const checkboxes = document.querySelectorAll('input[name="create_pages"]');
        checkboxes.forEach(checkbox => {
            checkbox.checked = false;
            // Trigger visual update
            const item = checkbox.closest('.page-checkbox-item');
            if (item) {
                item.classList.remove('checked');
            }
        });
        updateSelectedPagesCount();
        updateHomepageIntegrationNote();
    }

    // Update Selected Pages Count (includes both predefined and custom pages)
    window.updateSelectedPagesCount = function updateSelectedPagesCount() {
        // Count predefined pages
        const predefinedCheckboxes = document.querySelectorAll('input[name="create_pages"]:checked');
        const predefinedCount = predefinedCheckboxes.length;

        // Count custom pages
        const customPagesCount = typeof customPages !== 'undefined' ? customPages.filter(p => p.checked).length : 0;

        // Total count
        const totalCount = predefinedCount + customPagesCount;

        const countDisplay = document.getElementById('selectedPagesCount');

        selectedPagesToCreate = Array.from(predefinedCheckboxes).map(cb => cb.value);

        if (countDisplay) {
            let countText = `<i class="fas fa-file"></i> ${totalCount} page${totalCount !== 1 ? 's' : ''} selected`;
            if (customPagesCount > 0) {
                countText += ` <span style="opacity: 0.7; font-size: 0.85em;">(${customPagesCount} custom)</span>`;
            }
            countDisplay.innerHTML = countText;
            countDisplay.style.color = totalCount > 0 ? '#10b981' : 'var(--text-muted)';
        }

        // Save to localStorage
        localStorage.setItem('selectedPagesToCreate', JSON.stringify(selectedPagesToCreate));

        // Save skip existing pages setting
        const skipExistingCheckbox = document.getElementById('skipExistingPages');
        if (skipExistingCheckbox) {
            localStorage.setItem('skipExistingPages', skipExistingCheckbox.checked);
        }

        // Show/hide How It Works AI Content box based on how-it-works page selection
        const howItWorksPageCheckbox = document.querySelector('input[name="create_pages"][value="how-it-works"]');
        const howItWorksAIContentBox = document.getElementById('howItWorksAIContentBox');
        if (howItWorksAIContentBox) {
            if (howItWorksPageCheckbox && howItWorksPageCheckbox.checked) {
                howItWorksAIContentBox.style.display = 'block';
            } else {
                howItWorksAIContentBox.style.display = 'none';
            }
        }

        // Update homepage integration note
        updateHomepageIntegrationNote();

        console.log('Selected pages:', selectedPagesToCreate, '+ custom:', customPagesCount);
    }

    // Toggle How It Works AI Content visual state
    window.toggleHowItWorksAIContent = function(label) {
        const checkbox = label.querySelector('input[type="checkbox"]');
        if (checkbox) {
            setTimeout(() => {
                if (checkbox.checked) {
                    label.classList.add('checked');
                } else {
                    label.classList.remove('checked');
                }
            }, 10);
        }
    };

    // Update How It Works AI Content option
    window.updateHowItWorksAIContent = function() {
        const checkbox = document.getElementById('howItWorksAIContent');
        if (checkbox) {
            const label = checkbox.closest('.checkbox-item');
            if (label) {
                label.classList.toggle('checked', checkbox.checked);
            }
            // Save to localStorage
            localStorage.setItem('howItWorksAIContent', checkbox.checked);
            console.log('✅ How It Works AI Content option:', checkbox.checked);
        }
    };

    // Check if How It Works AI Content is enabled
    window.isHowItWorksAIContentEnabled = function() {
        const howItWorksPageCheckbox = document.querySelector('input[name="create_pages"][value="how-it-works"]');
        const howItWorksAIContentCheckbox = document.getElementById('howItWorksAIContent');

        // Only enabled if both the page is selected AND the AI content option is checked
        return howItWorksPageCheckbox && howItWorksPageCheckbox.checked &&
            howItWorksAIContentCheckbox && howItWorksAIContentCheckbox.checked;
    };

    // Toggle Feed from Documentation visual state
    window.toggleFeedFromDocumentation = function(label) {
        const checkbox = label.querySelector('input[type="checkbox"]');
        if (checkbox) {
            setTimeout(() => {
                if (checkbox.checked) {
                    label.classList.add('checked');
                } else {
                    label.classList.remove('checked');
                }
            }, 10);
        }
    };

    // Update Feed from Documentation option
    window.updateFeedFromDocumentation = function() {
        const checkbox = document.getElementById('feedFromDocumentation');
        const statusText = document.getElementById('feedDocStatusText');

        if (checkbox) {
            const label = checkbox.closest('.checkbox-item');
            if (label) {
                label.classList.toggle('checked', checkbox.checked);
            }

            // Update status text
            if (statusText) {
                if (checkbox.checked) {
                    statusText.innerHTML =
                        'If no documentation uploaded, AI will generate content based on its best understanding.';
                } else {
                    statusText.innerHTML =
                        '<strong style="color: #f59e0b;">⚠️ Manual Mode:</strong> AI will try its best to generate content without documentation guidance.';
                }
            }

            // Save to localStorage
            localStorage.setItem('feedFromDocumentation', checkbox.checked);
            console.log('✅ Feed from Documentation option:', checkbox.checked);
        }
    };

    // Check if Feed from Documentation is enabled
    window.isFeedFromDocumentationEnabled = function() {
        const checkbox = document.getElementById('feedFromDocumentation');
        return checkbox && checkbox.checked;
    };

    // Check if documentation file is uploaded
    window.hasDocumentationFile = function() {
        return documentationFileContent && documentationFileContent.trim().length > 0;
    }

    // Update Homepage Integration Note
    function updateHomepageIntegrationNote() {
        const note = document.getElementById('homepageIntegrationNote');
        const createNewHomepageCheckbox = document.getElementById('createNewHomepage');
        const homePageCheckbox = document.querySelector('input[name="create_pages"][value="home"]');

        if (note) {
            // Show note if both "Create New Landing Page" and "Home" page are selected
            if (createNewHomepageCheckbox && createNewHomepageCheckbox.checked &&
                homePageCheckbox && homePageCheckbox.checked) {
                note.style.display = 'inline';
            } else {
                note.style.display = 'none';
            }
        }
    }

    // Get Selected Pages for Prompt (includes both predefined and custom pages)
    function getSelectedPagesToCreate() {
        const enableCheckbox = document.getElementById('enablePagesCreation');
        if (!enableCheckbox || !enableCheckbox.checked) {
            return [];
        }

        // Get predefined pages
        const checkboxes = document.querySelectorAll('input[name="create_pages"]:checked');
        const predefinedPages = Array.from(checkboxes).map(cb => {
            const label = cb.closest('.page-checkbox-item').querySelector('span');
            return {
                value: cb.value,
                name: label ? label.textContent.trim() : cb.value,
                isCustom: false
            };
        });

        // Get custom pages (use window.getSelectedCustomPages which is defined later)
        let customPagesSelected = [];
        if (typeof window.getSelectedCustomPages === 'function') {
            customPagesSelected = window.getSelectedCustomPages();
            console.log('📋 Custom pages retrieved:', customPagesSelected.length, customPagesSelected.map(p => p.name));
        } else {
            console.warn('⚠️ getSelectedCustomPages function not found');
        }

        // Combine both arrays
        const allPages = [...predefinedPages, ...customPagesSelected];
        console.log('📋 Total pages to create:', allPages.length, '(Predefined:', predefinedPages.length, '+ Custom:', customPagesSelected.length, ')');
        return allPages;
    }

