    // Load saved pages selection on page load
    function loadSavedPagesSelection() {
        // Load enable state
        const savedEnableState = localStorage.getItem('enablePagesCreation');
        if (savedEnableState === 'true') {
            const checkbox = document.getElementById('enablePagesCreation');
            if (checkbox) {
                checkbox.checked = true;
                togglePagesCreation();
            }
        }

        // Load selected pages
        const savedPages = localStorage.getItem('selectedPagesToCreate');
        if (savedPages) {
            try {
                const pages = JSON.parse(savedPages);
                // First uncheck all pages
                document.querySelectorAll('input[name="create_pages"]').forEach(cb => {
                    cb.checked = false;
                    const item = cb.closest('.page-checkbox-item');
                    if (item) item.classList.remove('checked');
                });
                // Then check only saved pages
                pages.forEach(pageValue => {
                    const checkbox = document.querySelector(`input[name="create_pages"][value="${pageValue}"]`);
                    if (checkbox) {
                        checkbox.checked = true;
                        const item = checkbox.closest('.page-checkbox-item');
                        if (item) item.classList.add('checked');
                    }
                });
                updateSelectedPagesCount();
            } catch (e) {
                console.error('Error loading saved pages:', e);
            }
        } else {
            // No saved state - all pages start unchecked by default
            updateSelectedPagesCount();
        }

        // Load How It Works AI Content checkbox state
        const savedHowItWorksAIContent = localStorage.getItem('howItWorksAIContent');
        const howItWorksAIContentCheckbox = document.getElementById('howItWorksAIContent');
        const howItWorksAIContentBox = document.getElementById('howItWorksAIContentBox');

        if (howItWorksAIContentCheckbox) {
            // Default to true if not saved
            howItWorksAIContentCheckbox.checked = savedHowItWorksAIContent !== 'false';
            const label = howItWorksAIContentCheckbox.closest('.checkbox-item');
            if (label) label.classList.toggle('checked', howItWorksAIContentCheckbox.checked);
        }

        // Show/hide based on how-it-works page selection
        const howItWorksPageCheckbox = document.querySelector('input[name="create_pages"][value="how-it-works"]');
        if (howItWorksAIContentBox) {
            howItWorksAIContentBox.style.display = (howItWorksPageCheckbox && howItWorksPageCheckbox.checked) ?
                'block' : 'none';
        }

        // Load Feed from Documentation checkbox state
        const savedFeedFromDoc = localStorage.getItem('feedFromDocumentation');
        const feedFromDocCheckbox = document.getElementById('feedFromDocumentation');
        const feedDocStatusText = document.getElementById('feedDocStatusText');

        if (feedFromDocCheckbox) {
            // Default to true if not saved
            feedFromDocCheckbox.checked = savedFeedFromDoc !== 'false';
            const label = feedFromDocCheckbox.closest('.checkbox-item');
            if (label) label.classList.toggle('checked', feedFromDocCheckbox.checked);

            // Update status text based on state
            if (feedDocStatusText) {
                if (feedFromDocCheckbox.checked) {
                    feedDocStatusText.innerHTML =
                        'If no documentation uploaded, AI will generate content based on its best understanding.';
                } else {
                    feedDocStatusText.innerHTML =
                        '<strong style="color: #f59e0b;">⚠️ Manual Mode:</strong> AI will try its best to generate content without documentation guidance.';
                }
            }
        }

        // Load skip existing pages setting
        const savedSkipExisting = localStorage.getItem('skipExistingPages');
        const skipExistingCheckbox = document.getElementById('skipExistingPages');
        if (skipExistingCheckbox && savedSkipExisting !== null) {
            skipExistingCheckbox.checked = savedSkipExisting === 'true';
        }
    }

    // Initialize pages selection on DOM ready
    document.addEventListener('DOMContentLoaded', function() {
        setTimeout(loadSavedPagesSelection, 300);
        setTimeout(loadCustomPages, 350);
    });

