        '📦 3PL & Fulfillment': ['fulfillment-services', 'warehouse-management-3pl', 'order-management-3pl', 'returns-processing', 'kitting-assembly', 'inventory-visibility', 'shipping-integration', 'reporting-analytics-3pl', 'client-portal-3pl', 'onboarding-3pl'],
