        '🖨️ 3D Printing Services': ['print-services', 'materials-3d', 'instant-quote', 'design-services-3d', 'file-requirements', 'finishing-options', 'prototyping', 'production-runs', 'industry-applications', 'technology-3d'],
        '🔬 Testing Laboratory': ['testing-services-lab', 'sample-submission', 'test-methods', 'turnaround-times', 'accreditations', 'results-portal', 'chain-of-custody', 'industries-served', 'quality-system', 'consulting-lab'],
        '⚖️ Calibration Services': ['calibration-services', 'equipment-types', 'calibration-intervals', 'certificates', 'traceability', 'on-site-calibration', 'repair-services-cal', 'asset-management-cal', 'scheduling-cal', 'standards-maintained']
    };
    
    // Currently selected template
    let selectedTemplateId = null;
    
    // Get category for a template
    function getTemplateCategory(templateId) {
        for (const [category, templates] of Object.entries(templateCategories)) {
            if (templates.includes(templateId)) {
                return category;
            }
        }
        return '📄 Other';
    }
    
    // Search templates dynamically
    window.searchTemplates = function(query) {
        const resultsContainer = document.getElementById('templateSearchResults');
        const searchQuery = query.toLowerCase().trim();
        
        if (!searchQuery) {
            // Show all templates grouped by category when empty
            showAllTemplates();
            return;
        }
        
        // Filter templates
        const matches = [];
        for (const [id, template] of Object.entries(pageTemplates)) {
            const nameMatch = template.name.toLowerCase().includes(searchQuery);
            const descMatch = template.description.toLowerCase().includes(searchQuery);
            const idMatch = id.includes(searchQuery);
            
            if (nameMatch || descMatch || idMatch) {
                matches.push({
                    id: id,
                    template: template,
                    category: getTemplateCategory(id),
                    relevance: nameMatch ? 3 : (idMatch ? 2 : 1)
                });
            }
        }
        
        // Sort by relevance
        matches.sort((a, b) => b.relevance - a.relevance);
        
        // Render results
        renderSearchResults(matches, searchQuery);
    };
    
    // Show all templates grouped by category
    function showAllTemplates() {
        const resultsContainer = document.getElementById('templateSearchResults');
        let html = '';
        
        for (const [category, templateIds] of Object.entries(templateCategories)) {
            html += `<div style="
                padding: 0.4rem 0.75rem;
                background: rgba(99, 102, 241, 0.1);
                font-size: 0.72rem;
                font-weight: 600;
                color: #818cf8;
                border-bottom: 1px solid rgba(99, 102, 241, 0.15);
                position: sticky;
                top: 0;
            ">${category}</div>`;
            
            templateIds.forEach(id => {
                const template = pageTemplates[id];
                if (template) {
                    html += renderTemplateItem(id, template, '');
                }
            });
        }
        
        resultsContainer.innerHTML = html;
        resultsContainer.style.display = 'block';
        updateResultsCount(Object.keys(pageTemplates).length);
    }
    
    // Render filtered search results
    function renderSearchResults(matches, query) {
        const resultsContainer = document.getElementById('templateSearchResults');
        
        if (matches.length === 0) {
            resultsContainer.innerHTML = `
                <div style="padding: 1rem; text-align: center; color: var(--text-muted);">
                    <i class="fas fa-search" style="font-size: 1.5rem; margin-bottom: 0.5rem; display: block; opacity: 0.5;"></i>
                    No templates found for "<strong>${query}</strong>"
                </div>
            `;
            resultsContainer.style.display = 'block';
            updateResultsCount(0);
            return;
        }
        
        let html = '';
        let currentCategory = '';
        
        matches.forEach(match => {
            if (match.category !== currentCategory) {
                currentCategory = match.category;
                html += `<div style="
                    padding: 0.4rem 0.75rem;
                    background: rgba(99, 102, 241, 0.1);
                    font-size: 0.72rem;
                    font-weight: 600;
                    color: #818cf8;
                    border-bottom: 1px solid rgba(99, 102, 241, 0.15);
                ">${currentCategory}</div>`;
            }
            html += renderTemplateItem(match.id, match.template, query);
        });
        
        resultsContainer.innerHTML = html;
        resultsContainer.style.display = 'block';
        updateResultsCount(matches.length);
    }
    
    // Render a single template item
    function renderTemplateItem(id, template, query) {
        const isSelected = selectedTemplateId === id;
        const highlightedName = query ? highlightMatch(template.name, query) : template.name;
        
        return `
            <div class="template-result-item" 
                onclick="selectTemplate('${id}')"
                style="
                    padding: 0.5rem 0.75rem;
                    cursor: pointer;
                    border-bottom: 1px solid rgba(99, 102, 241, 0.08);
                    transition: all 0.15s ease;
                    background: ${isSelected ? 'rgba(34, 197, 94, 0.1)' : 'transparent'};
                    border-left: 3px solid ${isSelected ? '#22c55e' : 'transparent'};
                "
                onmouseenter="this.style.background='rgba(99, 102, 241, 0.1)'"
                onmouseleave="this.style.background='${isSelected ? 'rgba(34, 197, 94, 0.1)' : 'transparent'}'">
                <div style="display: flex; align-items: center; justify-content: space-between;">
                    <span style="font-size: 0.85rem; font-weight: 500; color: var(--text-primary);">
                        ${isSelected ? '<i class="fas fa-check-circle" style="color: #22c55e; margin-right: 0.3rem;"></i>' : ''}
                        ${highlightedName}
                    </span>
                </div>
            </div>
        `;
    }
    
    // Highlight matching text
    function highlightMatch(text, query) {
        if (!query) return text;
        const regex = new RegExp(`(${query})`, 'gi');
        return text.replace(regex, '<mark style="background: rgba(99, 102, 241, 0.3); color: inherit; padding: 0 2px; border-radius: 2px;">$1</mark>');
    }
    
    // Update results count badge
    function updateResultsCount(count) {
        const badge = document.getElementById('templateCountBadge');
        if (badge) {
            badge.textContent = count > 0 ? `${count} found` : 'No results';
            badge.style.background = count > 0 ? 'rgba(99, 102, 241, 0.15)' : 'rgba(239, 68, 68, 0.15)';
            badge.style.color = count > 0 ? '#818cf8' : '#f87171';
        }
    }
    
    // Select a template
    window.selectTemplate = function(templateId) {
        selectedTemplateId = templateId;
        const template = pageTemplates[templateId];
        
        if (!template) return;
        
        // Update search input
        const searchInput = document.getElementById('templateSearchInput');
        searchInput.value = template.name;
        
        // Update selected display
        const selectedDisplay = document.getElementById('selectedTemplateDisplay');
        const selectedName = document.getElementById('selectedTemplateName');
        selectedDisplay.style.display = 'block';
        selectedName.textContent = template.name;
        
        // Update preview
        const preview = document.getElementById('pageTemplatePreview');
        preview.innerHTML = `<strong>${template.name}:</strong> ${template.description}`;
        preview.style.display = 'block';
        
        // Enable apply button
        const applyBtn = document.getElementById('applyTemplateBtn');
        applyBtn.style.opacity = '1';
        
        // Hide results
        hideTemplateResults();
        
        // Re-render to show selection
        searchTemplates(searchInput.value);
    };
    
    // Clear selected template
    window.clearSelectedTemplate = function() {
        selectedTemplateId = null;
        
        document.getElementById('templateSearchInput').value = '';
        document.getElementById('selectedTemplateDisplay').style.display = 'none';
        document.getElementById('pageTemplatePreview').style.display = 'none';
        document.getElementById('applyTemplateBtn').style.opacity = '0.6';
        document.getElementById('templateCountBadge').textContent = '1150+ pages';
        document.getElementById('templateCountBadge').style.background = 'rgba(99, 102, 241, 0.15)';
        document.getElementById('templateCountBadge').style.color = '#818cf8';
    };
    
    // Show template results dropdown
    window.showTemplateResults = function() {
        const searchInput = document.getElementById('templateSearchInput');
        if (!searchInput.value.trim()) {
            showAllTemplates();
        } else {
            searchTemplates(searchInput.value);
        }
    };
    
    // Hide template results dropdown
    window.hideTemplateResults = function() {
        document.getElementById('templateSearchResults').style.display = 'none';
    };
    
    // Apply selected template to input fields
    window.applySelectedTemplate = function() {
        if (!selectedTemplateId || !pageTemplates[selectedTemplateId]) {
            if (typeof showNotification === 'function') {
                showNotification('⚠️ Please search and select a template first', 'warning');
            }
            return;
        }
        
        const template = pageTemplates[selectedTemplateId];
        const nameInput = document.getElementById('customPageNameInput');
        const descInput = document.getElementById('customPageDescInput');
        
        // Fill the input fields
        nameInput.value = template.name;
        if (descInput) {
            descInput.value = template.description;
        }
        
        // Clear selection
        clearSelectedTemplate();
        
        // Focus on name input
        nameInput.focus();
        
        // Visual feedback
        nameInput.style.borderColor = '#22c55e';
        nameInput.style.boxShadow = '0 0 0 3px rgba(34, 197, 94, 0.2)';
        if (descInput) {
            descInput.style.borderColor = '#22c55e';
            descInput.style.boxShadow = '0 0 0 3px rgba(34, 197, 94, 0.2)';
        }
        
        setTimeout(() => {
            nameInput.style.borderColor = 'rgba(249, 115, 22, 0.2)';
            nameInput.style.boxShadow = 'none';
            if (descInput) {
                descInput.style.borderColor = 'rgba(249, 115, 22, 0.15)';
                descInput.style.boxShadow = 'none';
            }
        }, 1000);
        
        if (typeof showNotification === 'function') {
            showNotification(`✅ "${template.name}" template applied! Click "Add Page" to add it.`, 'success');
        }
    };
    
    // Legacy function for compatibility
    window.applyPageTemplate = window.applySelectedTemplate;
    window.previewPageTemplate = function() {};

    // Add a new custom page
    window.addCustomPage = function() {
        const nameInput = document.getElementById('customPageNameInput');
        const descInput = document.getElementById('customPageDescInput');
        const pageName = nameInput.value.trim();
        const pageDesc = descInput ? descInput.value.trim() : '';

        if (!pageName) {
            showNotification('⚠️ Please enter a page name', 'warning');
            nameInput.focus();
            return;
        }

        // Validate page name (alphanumeric, spaces, hyphens, underscores)
        const validName = /^[a-zA-Z0-9\s\-_]+$/;
        if (!validName.test(pageName)) {
            showNotification('⚠️ Page name can only contain letters, numbers, spaces, hyphens, and underscores', 'warning');
            return;
        }

        // Check for duplicates (in custom pages and predefined pages)
        const normalizedName = pageName.toLowerCase().replace(/\s+/g, '-');
        const existsInCustom = customPages.some(p => p.id === normalizedName);
        const existsInPredefined = document.querySelector(`input[name="create_pages"][value="${normalizedName}"]`);

        if (existsInCustom || existsInPredefined) {
            showNotification('⚠️ A page with this name already exists', 'warning');
            return;
        }

        // Create new custom page object with description
        const newPage = {
            id: normalizedName,
            name: pageName,
            description: pageDesc,
            checked: true,
            createdAt: Date.now()
        };

        customPages.push(newPage);
        renderCustomPageItem(newPage);
        saveCustomPages();
        updateCustomPagesUI();

        // Clear inputs
        nameInput.value = '';
        if (descInput) descInput.value = '';
        nameInput.focus();

        const descInfo = pageDesc ? ' with description' : '';
        showNotification(`✅ "${pageName}" page added${descInfo}!`, 'success');
        console.log('✅ Custom page added:', newPage);
    };

    // Render a single custom page item with always-visible description
    function renderCustomPageItem(page) {
        const list = document.getElementById('customPagesList');
        
        const item = document.createElement('div');
        item.className = 'custom-page-item-wrapper';
        item.dataset.pageId = page.id;

        item.innerHTML = `
            <div class="custom-page-card ${page.checked ? 'checked' : ''}">
                <!-- Page Header Row -->
                <div class="custom-page-header">
                    <input type="checkbox" 
                           name="create_custom_pages" 
                           value="${page.id}" 
                           ${page.checked ? 'checked' : ''}
                           onchange="toggleCustomPage('${page.id}', this.checked)">
                    <div class="custom-page-icon">
                        <i class="fas fa-file-alt"></i>
                    </div>
                    <input type="text" 
                           class="custom-page-name" 
                           value="${page.name}" 
                           data-page-id="${page.id}"
                           onchange="renameCustomPage('${page.id}', this.value)"
                           onblur="renameCustomPage('${page.id}', this.value)"
                           placeholder="Page name"
                           title="Click to edit page name">
                    <div class="custom-page-actions">
                        <button class="custom-page-btn edit-btn" 
                                onclick="focusCustomPageName('${page.id}')" 
                                title="Edit name">
                            <i class="fas fa-pen"></i>
                        </button>
                        <button class="custom-page-btn delete-btn" 
                                onclick="deleteCustomPage('${page.id}')" 
                                title="Delete page">
                            <i class="fas fa-trash"></i>
                        </button>
                    </div>
                </div>
                
                <!-- Page Description (Always Visible) -->
                <div class="custom-page-desc-section">
                    <label class="custom-page-desc-label">
                        <i class="fas fa-align-left"></i>
                        What is this page about?
                    </label>
                    <textarea 
                        class="custom-page-desc-textarea"
                        data-page-id="${page.id}"
                        placeholder="Describe this page in detail... Example: 'A page showcasing our business partners with company logos, partnership benefits, testimonials from partners, and a contact form for potential partnership inquiries.'"
                        onchange="updateCustomPageDesc('${page.id}', this.value)"
                        onblur="updateCustomPageDesc('${page.id}', this.value)"
                    >${page.description || ''}</textarea>
                    <div class="custom-page-desc-hint">
                        <i class="fas fa-magic"></i>
                        This description tells the AI exactly what content and sections to create for this page.
                    </div>
                </div>
            </div>
        `;

        list.appendChild(item);
    }

    // Toggle custom page checked state
    window.toggleCustomPage = function(pageId, checked) {
        const page = customPages.find(p => p.id === pageId);
        if (page) {
            page.checked = checked;
            saveCustomPages();
            
            // Update visual state (new card structure)
            const wrapper = document.querySelector(`.custom-page-item-wrapper[data-page-id="${pageId}"]`);
            const card = wrapper ? wrapper.querySelector('.custom-page-card') : null;
            if (card) {
                if (checked) {
                    card.classList.add('checked');
                } else {
                    card.classList.remove('checked');
                }
            }
            
            updateCustomPagesUI();
            updateSelectedPagesCount();
        }
    };

    // Update custom page description
    window.updateCustomPageDesc = function(pageId, description) {
        const page = customPages.find(p => p.id === pageId);
        if (page) {
            page.description = description.trim();
            saveCustomPages();
            console.log('✅ Custom page description updated:', pageId, '- Length:', page.description.length);
        }
    };

    // Rename custom page
    window.renameCustomPage = function(pageId, newName) {
        const page = customPages.find(p => p.id === pageId);
        if (page && newName.trim()) {
            const trimmedName = newName.trim();
            
            // Validate
            const validName = /^[a-zA-Z0-9\s\-_]+$/;
            if (!validName.test(trimmedName)) {
                showNotification('⚠️ Invalid characters in page name', 'warning');
                // Reset to original
                const input = document.querySelector(`.custom-page-name[data-page-id="${pageId}"]`);
                if (input) input.value = page.name;
                return;
            }
            
            page.name = trimmedName;
            saveCustomPages();
            console.log('✅ Custom page renamed:', pageId, '→', trimmedName);
        }
    };

    // Focus on custom page name input for editing
    window.focusCustomPageName = function(pageId) {
        const input = document.querySelector(`.custom-page-name[data-page-id="${pageId}"]`);
        if (input) {
            input.focus();
            input.select();
        }
    };

    // Delete custom page
    window.deleteCustomPage = function(pageId) {
        const page = customPages.find(p => p.id === pageId);
        if (!page) return;

        // Remove from array
        customPages = customPages.filter(p => p.id !== pageId);
        
        // Remove from DOM with animation (use wrapper)
        const wrapper = document.querySelector(`.custom-page-item-wrapper[data-page-id="${pageId}"]`);
        if (wrapper) {
            wrapper.style.transition = 'all 0.3s ease';
            wrapper.style.opacity = '0';
            wrapper.style.transform = 'translateX(20px)';
            setTimeout(() => wrapper.remove(), 300);
        }

        saveCustomPages();
        updateCustomPagesUI();
        updateSelectedPagesCount();

        showNotification(`🗑️ "${page.name}" page removed`, 'info');
        console.log('🗑️ Custom page deleted:', pageId);
    };

    // Save custom pages to localStorage
    function saveCustomPages() {
        localStorage.setItem('customPages', JSON.stringify(customPages));
    }

    // Load custom pages from localStorage
    window.loadCustomPages = function() {
        const saved = localStorage.getItem('customPages');
        if (saved) {
            try {
                customPages = JSON.parse(saved);
                const list = document.getElementById('customPagesList');
                list.innerHTML = ''; // Clear existing
                
                customPages.forEach(page => {
                    renderCustomPageItem(page);
                });
                
                updateCustomPagesUI();
                console.log('✅ Custom pages loaded:', customPages.length);
            } catch (e) {
                console.error('Error loading custom pages:', e);
                customPages = [];
            }
        }
    };

    // Update custom pages UI (show/hide elements, update counts)
    function updateCustomPagesUI() {
        const list = document.getElementById('customPagesList');
        const emptyState = document.getElementById('customPagesEmptyState');
        const countBadge = document.getElementById('customPagesCountBadge');
        
        const checkedCount = customPages.filter(p => p.checked).length;
        const totalCount = customPages.length;

        if (totalCount > 0) {
            list.style.display = 'flex';
            emptyState.style.display = 'none';
            countBadge.style.display = 'inline-flex';
            countBadge.textContent = `${checkedCount}/${totalCount} custom`;
        } else {
            list.style.display = 'none';
            emptyState.style.display = 'block';
            countBadge.style.display = 'none';
        }
    }

    // Get selected custom pages for prompt generation
    window.getSelectedCustomPages = function() {
        return customPages.filter(p => p.checked).map(p => ({
            value: p.id,
            name: p.name,
            description: p.description || '',
            isCustom: true
        }));
    };

    // Clear all custom pages
    window.clearAllCustomPages = function() {
        customPages = [];
        document.getElementById('customPagesList').innerHTML = '';
        saveCustomPages();
        updateCustomPagesUI();
        updateSelectedPagesCount();
        showNotification('🗑️ All custom pages cleared', 'info');
    };

    // ============================================
    // END PAGES CREATION SYSTEM
    // ============================================

    // Update Theme Selection - NOW SUPPORTS MULTI-SELECTION
    function updateThemeSelection(checkboxElement) {
        const value = checkboxElement.value;
        const isChecked = checkboxElement.checked;

        // Update selectedThemes array
        if (isChecked) {
            if (!selectedThemes.includes(value)) {
                selectedThemes.push(value);
            }
        } else {
            selectedThemes = selectedThemes.filter(t => t !== value);
        }

        // Update UI - add/remove 'selected' class
        const option = checkboxElement.closest('.theme-option');
        if (option) {
            if (isChecked) {
                option.classList.add('selected');
            } else {
                option.classList.remove('selected');
            }
        }

        // Keep backward compatibility
        selectedTheme = selectedThemes.length > 0 ? selectedThemes[0] : 'ai-decision';

        // Update badge count
        updateThemeCountBadge();

        // Update mix indicator
        updateThemeMixIndicator();

        // Save to localStorage
        localStorage.setItem('selectedThemes', JSON.stringify(selectedThemes));
        localStorage.setItem('selectedTheme', selectedTheme);

        // Show notification
        const themeName = option ? option.querySelector('.theme-name').textContent.trim() : value;
        if (isChecked) {
            showNotification(`✨ Theme added: ${themeName}`, 'success');
        } else {
            showNotification(`Theme removed: ${themeName}`, 'info');
        }

        console.log('Themes selected:', selectedThemes);

        // Update Read First checkbox based on AI Decision
        if (typeof updateReadFirstCheckbox === 'function') {
            updateReadFirstCheckbox();
        }
    }

    // Update theme count badge
    function updateThemeCountBadge() {
        const badge = document.getElementById('themeCountBadge');
        const countText = document.getElementById('themeCountText');

        if (badge && countText) {
            if (selectedThemes.length > 0) {
                badge.style.display = 'flex';
                badge.style.alignItems = 'center';
                badge.style.gap = '0.4rem';
                countText.textContent =
                    `${selectedThemes.length} theme${selectedThemes.length > 1 ? 's' : ''} selected`;
            } else {
                badge.style.display = 'none';
            }
        }
    }

    // Update theme mix indicator
    function updateThemeMixIndicator() {
        const indicator = document.getElementById('themeMixIndicator');
        const mixText = document.getElementById('themeMixText');

        if (indicator && mixText) {
            if (selectedThemes.length > 1) {
                indicator.style.display = 'flex';
                indicator.style.alignItems = 'center';
                indicator.style.gap = '0.5rem';

                const hasAI = selectedThemes.includes('ai-decision');
                if (hasAI) {
                    mixText.innerHTML =
                        `<strong style="color: #667eea;">🤖 AI-Powered Artistic Mix:</strong> AI will intelligently blend ${selectedThemes.length} themes harmoniously`;
                    indicator.style.borderColor = 'rgba(102, 126, 234, 0.5)';
                    indicator.style.background = 'rgba(102, 126, 234, 0.15)';
                } else {
                    const percentage = Math.round(100 / selectedThemes.length);
                    mixText.innerHTML =
                        `<strong style="color: #f59e0b;">⚖️ Equal Mix:</strong> ${selectedThemes.length} themes @ ~${percentage}% each`;
                    indicator.style.borderColor = 'rgba(245, 158, 11, 0.5)';
                    indicator.style.background = 'rgba(245, 158, 11, 0.15)';
                }
            } else {
                indicator.style.display = 'none';
            }
        }
    }

    // Reset theme selection
    function resetThemeSelection() {
        // Uncheck all theme checkboxes
        document.querySelectorAll('input[name="design_theme"]').forEach(cb => {
            cb.checked = false;
        });

        // Check only AI Decision
        const aiDecision = document.querySelector('input[name="design_theme"][value="ai-decision"]');
        if (aiDecision) {
            aiDecision.checked = true;
        }

        // Reset array
        selectedThemes = ['ai-decision'];
        selectedTheme = 'ai-decision';

        // Update all UI elements
        document.querySelectorAll('.theme-option').forEach(option => {
            option.classList.remove('selected');
        });
        const aiOption = aiDecision ? aiDecision.closest('.theme-option') : null;
        if (aiOption) {
            aiOption.classList.add('selected');
        }

        // Update indicators
        updateThemeCountBadge();
        updateThemeMixIndicator();

        // Save
        localStorage.setItem('selectedThemes', JSON.stringify(selectedThemes));
        localStorage.setItem('selectedTheme', selectedTheme);

        showNotification('🔄 Themes reset to AI Decision', 'info');

        // Update Read First checkbox
        if (typeof updateReadFirstCheckbox === 'function') {
            updateReadFirstCheckbox();
        }
    }

    // Update Layout Selection - NOW SUPPORTS MULTI-SELECTION
    function updateLayoutSelection(checkboxElement) {
        const value = checkboxElement.value;
        const isChecked = checkboxElement.checked;

        // Update selectedLayouts array
        if (isChecked) {
            if (!selectedLayouts.includes(value)) {
                selectedLayouts.push(value);
            }
        } else {
            selectedLayouts = selectedLayouts.filter(l => l !== value);
        }

        // Update UI - add/remove 'selected' class
        const option = checkboxElement.closest('.layout-option');
        if (option) {
            if (isChecked) {
                option.classList.add('selected');
            } else {
                option.classList.remove('selected');
            }
        }

        // Keep backward compatibility
        selectedLayout = selectedLayouts.length > 0 ? selectedLayouts[0] : 'ai-decision';

        // Update badge count
        updateLayoutCountBadge();

        // Update mix indicator
        updateLayoutMixIndicator();

        // Save to localStorage
        localStorage.setItem('selectedLayouts', JSON.stringify(selectedLayouts));
        localStorage.setItem('selectedLayout', selectedLayout);

        // Show notification
        const layoutName = option ? option.querySelector('.layout-name').textContent.trim() : value;
        if (isChecked) {
            showNotification(`🏗️ Layout added: ${layoutName}`, 'success');
        } else {
            showNotification(`Layout removed: ${layoutName}`, 'info');
        }

        console.log('Layouts selected:', selectedLayouts);

        // Update Read First checkbox based on AI Decision
        if (typeof updateReadFirstCheckbox === 'function') {
            updateReadFirstCheckbox();
        }
    }

    // Update layout count badge
    function updateLayoutCountBadge() {
        const badge = document.getElementById('layoutCountBadge');
        const countText = document.getElementById('layoutCountText');

        if (badge && countText) {
            if (selectedLayouts.length > 0) {
                badge.style.display = 'flex';
                badge.style.alignItems = 'center';
                badge.style.gap = '0.4rem';
                countText.textContent =
                    `${selectedLayouts.length} layout${selectedLayouts.length > 1 ? 's' : ''} selected`;
            } else {
                badge.style.display = 'none';
            }
        }
    }

    // Update layout mix indicator
    function updateLayoutMixIndicator() {
        const indicator = document.getElementById('layoutMixIndicator');
        const mixText = document.getElementById('layoutMixText');

        if (indicator && mixText) {
            if (selectedLayouts.length > 1) {
                indicator.style.display = 'flex';
                indicator.style.alignItems = 'center';
                indicator.style.gap = '0.5rem';

                const hasAI = selectedLayouts.includes('ai-decision');
                if (hasAI) {
                    mixText.innerHTML =
                        `<strong style="color: #f97316;">🤖 AI-Powered Structural Fusion:</strong> AI will intelligently combine ${selectedLayouts.length} layouts`;
                    indicator.style.borderColor = 'rgba(249, 115, 22, 0.5)';
                    indicator.style.background = 'rgba(249, 115, 22, 0.15)';
                } else {
                    const percentage = Math.round(100 / selectedLayouts.length);
                    mixText.innerHTML =
                        `<strong style="color: #10b981;">⚖️ Balanced Hybrid:</strong> ${selectedLayouts.length} layouts @ ~${percentage}% each`;
                    indicator.style.borderColor = 'rgba(16, 185, 129, 0.5)';
                    indicator.style.background = 'rgba(16, 185, 129, 0.15)';
                }
            } else {
                indicator.style.display = 'none';
            }
        }
    }

    // Reset layout selection
    function resetLayoutSelection() {
        // Uncheck all layout checkboxes
        document.querySelectorAll('input[name="page_layout"]').forEach(cb => {
            cb.checked = false;
        });

        // Check only AI Decision
        const aiDecision = document.querySelector('input[name="page_layout"][value="ai-decision"]');
        if (aiDecision) {
            aiDecision.checked = true;
        }

        // Reset array
        selectedLayouts = ['ai-decision'];
        selectedLayout = 'ai-decision';

        // Update all UI elements
        document.querySelectorAll('.layout-option').forEach(option => {
            option.classList.remove('selected');
        });
        const aiOption = aiDecision ? aiDecision.closest('.layout-option') : null;
        if (aiOption) {
            aiOption.classList.add('selected');
        }

        // Update indicators
        updateLayoutCountBadge();
        updateLayoutMixIndicator();

        // Save
        localStorage.setItem('selectedLayouts', JSON.stringify(selectedLayouts));
        localStorage.setItem('selectedLayout', selectedLayout);

        showNotification('🔄 Layouts reset to AI Decision', 'info');

        // Update Read First checkbox
        if (typeof updateReadFirstCheckbox === 'function') {
            updateReadFirstCheckbox();
        }
    }

    // Initialize Reference Image Uploader
    function initReferenceUploader() {
        const dropZone = document.getElementById('referenceDropZone');
        const fileInput = document.getElementById('referenceImageInput');

        // Click to upload
        dropZone.addEventListener('click', () => {
            fileInput.click();
        });

        // File selection
        fileInput.addEventListener('change', (e) => {
            handleReferenceFiles(e.target.files);
        });

        // Drag and drop
        dropZone.addEventListener('dragover', (e) => {
            e.preventDefault();
            dropZone.classList.add('drag-over');
        });

        dropZone.addEventListener('dragleave', () => {
            dropZone.classList.remove('drag-over');
        });

        dropZone.addEventListener('drop', (e) => {
            e.preventDefault();
            dropZone.classList.remove('drag-over');
            handleReferenceFiles(e.dataTransfer.files);
        });
    }

    // Initialize Logo Uploader
    function initLogoUploader() {
        const logoDropZone = document.getElementById('logoDropZone');
        const logoFileInput = document.getElementById('logoFileInput');

        if (!logoDropZone || !logoFileInput) {
            console.log('⚠️ Logo uploader elements not found');
            return;
        }

        // Drag and drop
        logoDropZone.addEventListener('dragover', (e) => {
            e.preventDefault();
            e.stopPropagation();
            logoDropZone.classList.add('drag-over');
        });

        logoDropZone.addEventListener('dragleave', (e) => {
            e.preventDefault();
            e.stopPropagation();
            logoDropZone.classList.remove('drag-over');
        });

        logoDropZone.addEventListener('drop', (e) => {
            e.preventDefault();
            e.stopPropagation();
            logoDropZone.classList.remove('drag-over');

            const files = e.dataTransfer.files;
            if (files && files.length > 0) {
                // Set the file to the input and trigger the handler
                const dataTransfer = new DataTransfer();
                dataTransfer.items.add(files[0]);
                logoFileInput.files = dataTransfer.files;
                window.handleLogoUpload(logoFileInput);
            }
        });

        console.log('✅ Logo uploader initialized');
    }

    // Handle Reference Files
    function handleReferenceFiles(files) {
        const imageFiles = Array.from(files).filter(file => file.type.startsWith('image/'));

        if (imageFiles.length === 0) {
            showNotification('⚠️ Please upload image files only', 'warning');
            return;
        }

        imageFiles.forEach(file => {
            const reader = new FileReader();
            reader.onload = (e) => {
                referenceImages.push({
                    name: file.name,
                    data: e.target.result,
                    size: file.size
                });

                updateReferenceGallery();
                saveReferenceToStorage();
            };
            reader.readAsDataURL(file);
        });

        showNotification(`✅ ${imageFiles.length} reference image(s) uploaded`, 'success');
    }

    // Update Reference Gallery
    function updateReferenceGallery() {
        const gallery = document.getElementById('referenceGallery');
        const grid = document.getElementById('referenceImagesGrid');

        if (referenceImages.length > 0) {
            gallery.classList.add('show');

            grid.innerHTML = referenceImages.map((img, index) => `
                    <div class="reference-image-card">
                        <img src="${img.data}" alt="${img.name}" class="reference-image-preview">
                        <div class="reference-image-overlay">${img.name}</div>
                        <button class="reference-image-remove" onclick="removeReferenceImage(${index})" title="Remove">
                            <i class="fas fa-times"></i>
                        </button>
                    </div>
                `).join('');
        } else {
            gallery.classList.remove('show');
        }
    }

    // Remove Reference Image
    function removeReferenceImage(index) {
        referenceImages.splice(index, 1);
        updateReferenceGallery();
        saveReferenceToStorage();
        showNotification('🗑️ Reference image removed', 'info');
    }

    // Clear All Reference Images
    function clearReferenceImages() {
        if (referenceImages.length === 0) {
            showNotification('⚠️ No reference images to clear', 'warning');
            return;
        }

        if (confirm(`Are you sure you want to remove all ${referenceImages.length} reference images?`)) {
            referenceImages = [];
            updateReferenceGallery();
            saveReferenceToStorage();
            document.getElementById('referenceImageInput').value = '';
            showNotification('✅ All reference images cleared', 'success');
        }
    }

    // Update Reference Mode
    function updateReferenceMode(radioElement) {
        referenceMode = radioElement.value;

        // Remove 'selected' class from all mode options
        document.querySelectorAll('.reference-mode-option').forEach(option => {
            option.classList.remove('selected');
        });

        // Add 'selected' class to the chosen mode
        const selectedOption = radioElement.closest('.reference-mode-option');
        if (selectedOption) {
            selectedOption.classList.add('selected');
        }

        // Save to localStorage
        localStorage.setItem('referenceMode', referenceMode);

        // Show notification
        const modeName = radioElement.value === 'ai-inspiration' ? 'AI Inspiration Mode' : 'Exact Replication Mode';
        showNotification(`🎨 Reference mode: ${modeName}`, 'success');

        console.log('Reference mode selected:', referenceMode);
    }

    // Save Reference to LocalStorage
    function saveReferenceToStorage() {
        try {
            localStorage.setItem('referenceImages', JSON.stringify(referenceImages));
            console.log('Reference images saved to storage:', referenceImages.length);
        } catch (e) {
            console.warn('Failed to save reference images:', e);
            if (e.name === 'QuotaExceededError') {
                showNotification('⚠️ Storage limit reached. Consider using fewer or smaller images.', 'warning');
            }
        }
    }

    // Load Reference from LocalStorage
    function loadReferenceFromStorage() {
        const savedReferences = localStorage.getItem('referenceImages');
        const savedMode = localStorage.getItem('referenceMode');

        if (savedReferences) {
            try {
                referenceImages = JSON.parse(savedReferences);
                updateReferenceGallery();
                console.log('Loaded reference images:', referenceImages.length);
            } catch (e) {
                console.warn('Failed to load reference images:', e);
            }
        }

        if (savedMode) {
            referenceMode = savedMode;
            const modeRadio = document.querySelector(`input[name="reference_mode"][value="${savedMode}"]`);
            if (modeRadio) {
                modeRadio.checked = true;
                document.querySelectorAll('.reference-mode-option').forEach(option => {
                    option.classList.remove('selected');
                });
                const selectedOption = modeRadio.closest('.reference-mode-option');
                if (selectedOption) {
                    selectedOption.classList.add('selected');
                }
            }
        }
    }

    // Initialize Exclusion Manager
    function initExclusionManager() {
        const filePicker = document.getElementById('exclusionFilePicker');
        const fileInput = document.getElementById('exclusionFileInput');

        filePicker.addEventListener('click', () => {
            fileInput.click();
        });

        fileInput.addEventListener('change', (e) => {
            handleExclusionFiles(e.target.files);
        });
    }

    // Handle Exclusion Files
    function handleExclusionFiles(files) {
        const htmlPhpFiles = Array.from(files).filter(file =>
            file.name.endsWith('.html') || file.name.endsWith('.php') || file.name.endsWith('.htm')
        );

        if (htmlPhpFiles.length === 0) {
            showNotification('⚠️ Please select HTML or PHP files only', 'warning');
            return;
        }

        htmlPhpFiles.forEach(file => {
            // Check if file already excluded
            const exists = excludedFiles.some(f => f.name === file.name);
            if (!exists) {
                excludedFiles.push({
                    name: file.name,
                    excludeTheme: false,
                    excludeLayout: false
                });
            }
        });

        updateExcludedFilesList();
        saveExclusionsToStorage();
        showNotification(`✅ ${htmlPhpFiles.length} file(s) added to exclusion list`, 'success');
    }

    // Update Excluded Files List
    function updateExcludedFilesList() {
        const container = document.getElementById('excludedFilesContainer');
        const list = document.getElementById('excludedFilesList');

        if (excludedFiles.length > 0) {
            list.classList.add('show');

            container.innerHTML = excludedFiles.map((file, index) => {
                const statuses = [];
                if (file.excludeTheme) statuses.push(
                    '<span class="exclusion-status theme-excluded"><i class="fas fa-palette"></i> Theme Excluded</span>'
                );
                if (file.excludeLayout) statuses.push(
                    '<span class="exclusion-status layout-excluded"><i class="fas fa-th-large"></i> Layout Excluded</span>'
                );
                if (file.excludeTheme && file.excludeLayout) {
                    statuses.length = 0;
                    statuses.push(
                        '<span class="exclusion-status both-excluded"><i class="fas fa-ban"></i> Both Excluded</span>'
                    );
                }

                return `
                        <div class="excluded-file-item">
                            <div class="excluded-file-header">
                                <div class="excluded-file-name">
                                    <i class="fas fa-file-code"></i>
                                    ${file.name}
                                </div>
                                <button class="excluded-file-remove" onclick="removeExcludedFile(${index})">
                                    <i class="fas fa-times"></i>
                                    Remove
                                </button>
                            </div>
                            
                            <div class="exclusion-options">
                                <div class="exclusion-option">
                                    <label class="exclusion-checkbox-label ${file.excludeTheme ? 'checked' : ''}" onclick="toggleExclusionOption(${index}, 'theme', event)">
                                        <input type="checkbox" ${file.excludeTheme ? 'checked' : ''} onchange="event.stopPropagation()">
                                        <div class="exclusion-label-content">
                                            <div class="exclusion-label-title">
                                                <i class="fas fa-palette"></i> Exclude Theme
                                            </div>
                                            <div class="exclusion-label-desc">
                                                Keep original colors, styles, and visual design
                                            </div>
                                        </div>
                                    </label>
                                </div>
                                
                                <div class="exclusion-option">
                                    <label class="exclusion-checkbox-label ${file.excludeLayout ? 'checked' : ''}" onclick="toggleExclusionOption(${index}, 'layout', event)">
                                        <input type="checkbox" ${file.excludeLayout ? 'checked' : ''} onchange="event.stopPropagation()">
                                        <div class="exclusion-label-content">
                                            <div class="exclusion-label-title">
                                                <i class="fas fa-th-large"></i> Exclude Layout
                                            </div>
                                            <div class="exclusion-label-desc">
                                                Keep original structure, grid, and positioning
                                            </div>
                                        </div>
                                    </label>
                                </div>
                            </div>
                            
                            ${statuses.length > 0 ? '<div>' + statuses.join(' ') + '</div>' : ''}
                        </div>
                    `;
            }).join('');
        } else {
            list.classList.remove('show');
        }
    }

    // Toggle Exclusion Option
    function toggleExclusionOption(index, type, event) {
        event.preventDefault();

        if (type === 'theme') {
            excludedFiles[index].excludeTheme = !excludedFiles[index].excludeTheme;
        } else if (type === 'layout') {
            excludedFiles[index].excludeLayout = !excludedFiles[index].excludeLayout;
        }

        updateExcludedFilesList();
        saveExclusionsToStorage();

        const typeName = type === 'theme' ? 'Theme' : 'Layout';
        const action = excludedFiles[index][type === 'theme' ? 'excludeTheme' : 'excludeLayout'] ? 'excluded' :
            'included';
        showNotification(`${typeName} ${action} for ${excludedFiles[index].name}`, 'info');
    }

    // Remove Excluded File
    function removeExcludedFile(index) {
        const fileName = excludedFiles[index].name;
        excludedFiles.splice(index, 1);
        updateExcludedFilesList();
        saveExclusionsToStorage();
        showNotification(`🗑️ ${fileName} removed from exclusion list`, 'info');
    }

    // Clear All Exclusions
    function clearAllExclusions() {
        if (excludedFiles.length === 0) {
            showNotification('⚠️ No files to clear', 'warning');
            return;
        }

        if (confirm(`Are you sure you want to remove all ${excludedFiles.length} excluded file(s)?`)) {
            excludedFiles = [];
            updateExcludedFilesList();
            saveExclusionsToStorage();
            document.getElementById('exclusionFileInput').value = '';
            showNotification('✅ All exclusions cleared', 'success');
        }
    }

    // Save Exclusions to LocalStorage
    function saveExclusionsToStorage() {
        try {
            localStorage.setItem('excludedFiles', JSON.stringify(excludedFiles));
            console.log('Exclusions saved:', excludedFiles.length);
        } catch (e) {
            console.warn('Failed to save exclusions:', e);
        }
    }

    // Load Exclusions from LocalStorage
    function loadExclusionsFromStorage() {
        const saved = localStorage.getItem('excludedFiles');
        if (saved) {
            try {
                excludedFiles = JSON.parse(saved);
                updateExcludedFilesList();
                console.log('Loaded exclusions:', excludedFiles.length);
            } catch (e) {
                console.warn('Failed to load exclusions:', e);
            }
        }
    }

    // Update Task Parts
    function updateTaskParts(value) {
        taskParts = parseInt(value);
        const valueDisplay = document.getElementById('taskPartsValue');
        if (valueDisplay) {
            valueDisplay.textContent = taskParts;
        }

        // Save to localStorage
        localStorage.setItem('taskParts', taskParts);

        console.log('Task parts updated:', taskParts);
    }

    // Save Execution Mode
    function saveExecutionMode() {
        const stepByStep = document.getElementById('stepByStepMode');
        const automatic = document.getElementById('automaticMode');

        if (stepByStep && stepByStep.checked) {
            executionMode = 'step-by-step';
        } else if (automatic && automatic.checked) {
            executionMode = 'automatic';
        }

        // Save to localStorage
        localStorage.setItem('executionMode', executionMode);

        console.log('Execution mode updated:', executionMode);
    }
    
    // Toggle Optimize Token Limit checkbox visual state
    function toggleOptimizeTokenLimit(label) {
        const checkbox = label.querySelector('input[type="checkbox"]');
        if (checkbox) {
            setTimeout(() => {
                if (checkbox.checked) {
                    label.classList.add('checked');
                    label.style.borderColor = 'rgba(34, 197, 94, 0.5)';
                    label.style.background = 'linear-gradient(135deg, rgba(34, 197, 94, 0.15) 0%, rgba(16, 185, 129, 0.1) 100%)';
                } else {
                    label.classList.remove('checked');
                    label.style.borderColor = 'rgba(148, 163, 184, 0.3)';
                    label.style.background = 'rgba(148, 163, 184, 0.05)';
                }
            }, 10);
        }
    }
    
    // Save Optimize Token Limit setting
    function saveOptimizeTokenLimit() {
        const checkbox = document.getElementById('optimizeTokenLimit');
        if (checkbox) {
            optimizeTokenLimit = checkbox.checked;
            localStorage.setItem('optimizeTokenLimit', optimizeTokenLimit);
            console.log('Optimize Token Limit updated:', optimizeTokenLimit);
        }
    }
    
    // Load Optimize Token Limit setting
    function loadOptimizeTokenLimit() {
        const saved = localStorage.getItem('optimizeTokenLimit');
        // Default to true if not saved
        optimizeTokenLimit = saved === null ? true : saved === 'true';
        
        const checkbox = document.getElementById('optimizeTokenLimit');
        if (checkbox) {
            checkbox.checked = optimizeTokenLimit;
            const label = checkbox.closest('label');
            if (label) {
                if (optimizeTokenLimit) {
                    label.classList.add('checked');
                    label.style.borderColor = 'rgba(34, 197, 94, 0.5)';
                    label.style.background = 'linear-gradient(135deg, rgba(34, 197, 94, 0.15) 0%, rgba(16, 185, 129, 0.1) 100%)';
                } else {
                    label.classList.remove('checked');
                    label.style.borderColor = 'rgba(148, 163, 184, 0.3)';
                    label.style.background = 'rgba(148, 163, 184, 0.05)';
                }
            }
        }
    }

    // Load Task Breakdown settings
    function loadTaskBreakdownSettings() {
        // Load task parts
        const savedParts = localStorage.getItem('taskParts');
        if (savedParts) {
            taskParts = parseInt(savedParts);
            const slider = document.getElementById('taskPartsSlider');
            const valueDisplay = document.getElementById('taskPartsValue');
            if (slider) slider.value = taskParts;
            if (valueDisplay) valueDisplay.textContent = taskParts;
        }

        // Load execution mode
        const savedMode = localStorage.getItem('executionMode');
        if (savedMode) {
            executionMode = savedMode;
            if (executionMode === 'step-by-step') {
                const radio = document.getElementById('stepByStepMode');
                if (radio) radio.checked = true;
            } else if (executionMode === 'automatic') {
                const radio = document.getElementById('automaticMode');
                if (radio) radio.checked = true;
            }
        }

        // Load homepage option
        const savedHomepage = localStorage.getItem('createNewHomepage');
        if (savedHomepage) {
            createNewHomepage = savedHomepage === 'true';
            const checkbox = document.getElementById('createNewHomepage');
            if (checkbox) {
                checkbox.checked = createNewHomepage;
                updateHomepageOption();
            }
        }

        // Load target page filename
        const savedTargetPage = localStorage.getItem('targetPageFileName');
        if (savedTargetPage && createNewHomepage) {
            targetPageFileName = savedTargetPage;
            const fileNameDisplay = document.getElementById('targetPageFileName');
            const fileLabel = document.querySelector('.file-picker-label');
            const clearBtn = document.getElementById('clearTargetBtn');

            if (fileNameDisplay) {
                fileNameDisplay.textContent = targetPageFileName;
            }
            if (fileLabel) {
                fileLabel.classList.add('has-file');
            }
            if (clearBtn) {
                clearBtn.style.display = 'inline-flex';
            }
        }

        // Load selected themes (MULTI-SELECTION)
        const savedThemesJson = localStorage.getItem('selectedThemes');
        if (savedThemesJson) {
            try {
                selectedThemes = JSON.parse(savedThemesJson);
                selectedTheme = selectedThemes.length > 0 ? selectedThemes[0] : 'ai-decision';
            } catch (e) {
                // Fallback to single theme from old format
                const savedTheme = localStorage.getItem('selectedTheme');
                selectedThemes = savedTheme ? [savedTheme] : ['ai-decision'];
                selectedTheme = selectedThemes[0];
            }

            // Uncheck all first
            document.querySelectorAll('input[name="design_theme"]').forEach(cb => {
                cb.checked = false;
            });
            document.querySelectorAll('.theme-option').forEach(option => {
                option.classList.remove('selected');
            });

            // Check saved themes
            selectedThemes.forEach(themeValue => {
                const themeCheckbox = document.querySelector(
                    `input[name="design_theme"][value="${themeValue}"]`);
                if (themeCheckbox) {
                    themeCheckbox.checked = true;
                    const selectedOption = themeCheckbox.closest('.theme-option');
                    if (selectedOption) {
                        selectedOption.classList.add('selected');
                    }
                }
            });

            // Update indicators
            if (typeof updateThemeCountBadge === 'function') updateThemeCountBadge();
            if (typeof updateThemeMixIndicator === 'function') updateThemeMixIndicator();
        }

        // Load selected layouts (MULTI-SELECTION)
        const savedLayoutsJson = localStorage.getItem('selectedLayouts');
        if (savedLayoutsJson) {
            try {
                selectedLayouts = JSON.parse(savedLayoutsJson);
                selectedLayout = selectedLayouts.length > 0 ? selectedLayouts[0] : 'ai-decision';
            } catch (e) {
                // Fallback to single layout from old format
                const savedLayout = localStorage.getItem('selectedLayout');
                selectedLayouts = savedLayout ? [savedLayout] : ['ai-decision'];
                selectedLayout = selectedLayouts[0];
            }

            // Uncheck all first
            document.querySelectorAll('input[name="page_layout"]').forEach(cb => {
                cb.checked = false;
            });
            document.querySelectorAll('.layout-option').forEach(option => {
                option.classList.remove('selected');
            });

            // Check saved layouts
            selectedLayouts.forEach(layoutValue => {
                const layoutCheckbox = document.querySelector(
                    `input[name="page_layout"][value="${layoutValue}"]`);
                if (layoutCheckbox) {
                    layoutCheckbox.checked = true;
                    const selectedOption = layoutCheckbox.closest('.layout-option');
                    if (selectedOption) {
                        selectedOption.classList.add('selected');
