    // ============================================
    // EXECUTION MODE TYPE SYSTEM
    // ============================================

    // Global state for Execution Mode Type
    let executionModeType = 'read-before'; // Default: Read Before Executing

    // Update Execution Mode Type (Dropdown version)
    function updateExecutionModeType() {
        const select = document.getElementById('executionModeSelect');
        const readBeforeDesc = document.getElementById('readBeforeDescription');
        const defaultProcessDesc = document.getElementById('defaultProcessDescription');

        if (!select) {
            console.error('❌ Execution Mode select not found!');
            return;
        }

        const selectedValue = select.value;
        console.log('🔄 Updating Execution Mode Type:', selectedValue);

        // Update global variable
        executionModeType = selectedValue;

        // Toggle description visibility
        if (selectedValue === 'read-before') {
            if (readBeforeDesc) {
                readBeforeDesc.style.display = 'block';
                readBeforeDesc.classList.add('active');
            }
            if (defaultProcessDesc) {
                defaultProcessDesc.style.display = 'none';
                defaultProcessDesc.classList.remove('active');
            }
            showNotification('📖 Read Before Executing mode enabled', 'success');
            console.log('   ✅ Read Before Executing selected');
        } else if (selectedValue === 'default-process') {
            if (readBeforeDesc) {
                readBeforeDesc.style.display = 'none';
                readBeforeDesc.classList.remove('active');
            }
            if (defaultProcessDesc) {
                defaultProcessDesc.style.display = 'block';
                defaultProcessDesc.classList.add('active');
            }
            showNotification('⚡ Default Process mode enabled', 'info');
            console.log('   ✅ Default Process selected');
        }

        // Save to localStorage
        localStorage.setItem('executionModeType', executionModeType);
    }

    // Load Execution Mode Type from localStorage (Dropdown version)
    function loadExecutionModeType() {
        const saved = localStorage.getItem('executionModeType');
        const select = document.getElementById('executionModeSelect');
        const readBeforeDesc = document.getElementById('readBeforeDescription');
        const defaultProcessDesc = document.getElementById('defaultProcessDescription');

        console.log('📖 Loading Execution Mode Type from storage:', saved || 'read-before (default)');

        if (saved === 'default-process') {
            executionModeType = 'default-process';
            if (select) select.value = 'default-process';
            if (readBeforeDesc) {
                readBeforeDesc.style.display = 'none';
                readBeforeDesc.classList.remove('active');
            }
            if (defaultProcessDesc) {
                defaultProcessDesc.style.display = 'block';
                defaultProcessDesc.classList.add('active');
            }
            console.log('   Loaded: Default Process (from storage)');
        } else {
            // Default: read-before
            executionModeType = 'read-before';
            if (select) select.value = 'read-before';
            if (readBeforeDesc) {
                readBeforeDesc.style.display = 'block';
                readBeforeDesc.classList.add('active');
            }
            if (defaultProcessDesc) {
                defaultProcessDesc.style.display = 'none';
                defaultProcessDesc.classList.remove('active');
            }
            console.log('   Loaded: Read Before Executing (default)');
        }
    }

    // Calculate reading steps based on task parts
    function getReadingStepsCount() {
        if (executionModeType !== 'read-before') return 0;

        // Allocate reading steps based on total task parts
        // 1-3 parts: 1 reading step
        // 4-6 parts: 2 reading steps
        // 7-12 parts: 3 reading steps
        // 13-20 parts: 4 reading steps
        if (taskParts <= 3) return 1;
        if (taskParts <= 6) return 2;
        if (taskParts <= 12) return 3;
        return 4;
    }

    // Check if Read Before mode is enabled
    function isReadBeforeModeEnabled() {
        return executionModeType === 'read-before';
    }

    // Initialize Execution Mode Type on DOM ready
    document.addEventListener('DOMContentLoaded', function() {
        setTimeout(() => {
            loadExecutionModeType();
            console.log('✅ Execution Mode dropdown initialized');
        }, 200);
    });

