    // Global state for Read First enforcement (now linked to executionModeType)
    let enforceReadFirst = true; // Default checked (because read-before is default)
    let isAnyAIDecisionSelected = true; // Default true because AI Decision is selected by default

    // Check if any AI Decision option is selected
    function checkAIDecisionStatus() {
        // Check Theme AI Decision
        const themeAI = document.querySelector('input[name="design_theme"][value="ai-decision"]');
        const isThemeAI = themeAI && themeAI.checked;

        // Check Layout AI Decision
        const layoutAI = document.querySelector('input[name="page_layout"][value="ai-decision"]');
        const isLayoutAI = layoutAI && layoutAI.checked;

        // Check Style AI Choice (in enhancement styles)
        const styleAI = document.querySelector('input[name="enhancement_style"][value="ai-choice"]');
        const isStyleAI = styleAI && styleAI.checked;

        console.log('🤖 AI Decision Status Check:');
        console.log('   Theme AI:', isThemeAI);
        console.log('   Layout AI:', isLayoutAI);
        console.log('   Style AI:', isStyleAI);

        // Return true if ANY AI Decision is selected
        const hasAI = isThemeAI || isLayoutAI || isStyleAI;
        console.log('   Any AI Decision Selected:', hasAI);

        return hasAI;
    }

    // Update Read First checkbox based on AI Decision selections
    function updateReadFirstCheckbox() {
        // LEGACY FUNCTION - Read First is now controlled by Execution Mode Type
        // This function is kept for backward compatibility but now just updates the global state

        // Check if any AI Decision is selected
        const hasAIDecision = checkAIDecisionStatus();
        isAnyAIDecisionSelected = hasAIDecision;

        // Link to new execution mode type
        enforceReadFirst = isReadBeforeModeEnabled();

        console.log('📖 Read First state synced with Execution Mode Type:', enforceReadFirst);
        return; // Early return - old UI elements no longer exist

        if (hasAIDecision) {
            // AI Decision is selected - LOCK checkbox as checked
            checkbox.checked = true;
            checkbox.disabled = true; // Disable manual unchecking
            enforceReadFirst = true;

            // Update container style
            container.style.borderColor = 'rgba(37, 99, 235, 0.5)';
            container.style.background = 'rgba(37, 99, 235, 0.08)';
            container.style.boxShadow = '0 0 20px rgba(37, 99, 235, 0.15)';

            // Update status message
            statusDiv.style.display = 'block';
            statusDiv.style.background = 'rgba(16, 185, 129, 0.1)';
            statusDiv.style.borderLeftColor = '#10b981';
            statusDiv.innerHTML = `
                    <i class="fas fa-lock" style="color: #10b981;"></i>
                    <strong style="color: #10b981;">Auto-Locked:</strong> This checkbox is automatically enabled and locked because "AI Decision" is selected. AI MUST read all files before making decisions.
                `;

            console.log('🔒 Read First checkbox LOCKED (AI Decision selected)');
        } else {
            // No AI Decision - allow manual control
            checkbox.disabled = false;
            enforceReadFirst = checkbox.checked;

            // Update container style
            if (checkbox.checked) {
                container.style.borderColor = 'rgba(102, 126, 234, 0.4)';
                container.style.background = 'var(--surface-dark)';
                container.style.boxShadow = 'none';
            } else {
                container.style.borderColor = 'var(--glass-border)';
                container.style.background = 'var(--surface-dark)';
                container.style.boxShadow = 'none';
            }

            // Update status message
            statusDiv.style.display = 'block';
            statusDiv.style.background = 'rgba(245, 158, 11, 0.1)';
            statusDiv.style.borderLeftColor = '#f59e0b';
            statusDiv.innerHTML = `
                    <i class="fas fa-toggle-on" style="color: #f59e0b;"></i>
                    <strong style="color: #f59e0b;">Manual Control:</strong> No "AI Decision" selected. You can toggle this checkbox on/off manually. When enabled, AI will be instructed to read all files before starting work.
                `;

            console.log('🔓 Read First checkbox UNLOCKED (No AI Decision)');
            console.log('   Current state:', checkbox.checked ? 'Checked' : 'Unchecked');
        }

        // Save state
        localStorage.setItem('enforceReadFirst', checkbox.checked);
        localStorage.setItem('isAnyAIDecisionSelected', hasAIDecision);
    }

