    window.closeStyleModal = function() {
        const modal = document.getElementById('styleSampleModal');
        modal.classList.remove('show');
        document.body.style.overflow = 'auto';
    };

    // Close modal on Escape key
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') {
            closeStyleModal();
        }
    });

    // ============================================
    // REFRESH BUTTONS FUNCTIONS
    // ============================================

    // Refresh Keep Data - Reloads page but keeps all localStorage
    function refreshKeepData() {
        if (confirm(
                '🔄 Refresh page and keep all your selections?\n\nAll your current settings will be preserved in localStorage.'
            )) {
            // Make sure everything is saved before refresh
            updateOptions();
            saveExecutionMode();
            saveExclusionsToStorage();
            saveReferenceToStorage();

            // Set a flag to indicate we want to keep data
            localStorage.setItem('refreshKeepData', 'true');

            showNotification('🔄 Refreshing page with data preserved...', 'success');

            // Reload page after brief delay
            setTimeout(() => {
                location.reload();
            }, 500);
        }
    }

    // Refresh Clear All - Reloads page and clears all localStorage
    function refreshClearAll() {
        if (confirm(
                '⚠️ Refresh page and clear ALL data?\n\nThis will remove all your selections, uploaded files, and settings permanently.'
            )) {
            showNotification('🗑️ Clearing all data and refreshing...', 'warning');

            // Clear all localStorage
            localStorage.clear();

            // Reload page after brief delay
            setTimeout(() => {
                location.reload();
            }, 500);
        }
    }

    // Clear Storage Only - Clears localStorage without refresh
    function clearStorageOnly() {
        if (confirm(
                '🗄️ Clear all localStorage data?\n\nThis will remove all saved selections but will NOT refresh the page.\n\nYou can continue working with current session data until you refresh.'
            )) {
            // Get count of items
            const itemCount = localStorage.length;

            // Clear localStorage
            localStorage.clear();

            showNotification(`✅ Cleared ${itemCount} localStorage item(s). Page NOT refreshed.`, 'success');

            console.log('🗑️ LocalStorage cleared manually (no refresh)');
            console.log(`   Items removed: ${itemCount}`);
            console.log('   Current session data is still active');
            console.log('   Data will reset on next page refresh');
        }
    }

    // Enhanced save functions to ensure everything is in localStorage

    // Save all current state to localStorage
    function saveAllToLocalStorage() {
        try {
            // Save enhancement options
            localStorage.setItem('enhancementOptions', JSON.stringify(enhancementOptions));

            // Save task breakdown
            localStorage.setItem('taskParts', taskParts);
            localStorage.setItem('executionMode', executionMode);

            // Save homepage config
            localStorage.setItem('createNewHomepage', createNewHomepage);
            if (targetPageFileName) {
                localStorage.setItem('targetPageFileName', targetPageFileName);
            }

            // Save theme and layout
            localStorage.setItem('selectedTheme', selectedTheme);
            localStorage.setItem('selectedLayout', selectedLayout);

            // Save reference mode
            localStorage.setItem('referenceMode', referenceMode);

            // Save Read First state
            localStorage.setItem('enforceReadFirst', enforceReadFirst);
            localStorage.setItem('isAnyAIDecisionSelected', isAnyAIDecisionSelected);

            // Integration mode
            localStorage.setItem('integrationMode', integrationMode);

            console.log('💾 All current state saved to localStorage');
            return true;
        } catch (e) {
            console.error('❌ Error saving to localStorage:', e);
            return false;
        }
    }

    // Auto-save on important changes
    function enableAutoSave() {
        // Save when options change
        const originalUpdateOptions = updateOptions;
        updateOptions = function() {
            originalUpdateOptions();
            saveAllToLocalStorage();
        };

        console.log('✅ Auto-save enabled for all changes');
    }

    // Initialize auto-save
    setTimeout(() => {
        enableAutoSave();
        // Initial save
        saveAllToLocalStorage();
    }, 300);

    console.log('✅ Refresh Buttons System - COMPLETE');
    console.log('');
    console.log('🔄 REFRESH OPTIONS:');
    console.log('   🟢 Refresh Keep Data: Reload page, keep all selections');
    console.log('   🔴 Refresh Clear All: Reload page, clear everything');
    console.log('   🟠 Clear Storage: Clear data, NO reload');
    console.log('');
    </script>


