            defaultInstructions: `## HOW IT WORKS PAGE - Content Source Instructions

### ⚠️ SPECIAL PAGE - Derived from Application Functionality

Unlike other pages, "How It Works" content is primarily derived from ANALYZING THE APPLICATION'S CORE FUNCTIONALITY, not from documentation.

### Content Generation Process:
1. **Analyze Application Code:** Examine the uploaded codebase to understand:
   - Main features and capabilities
   - User workflows and journeys
   - Core functionality and processes
   - Integration points and data flow

2. **Create Step-by-Step Guide:**
   - Break down the application into logical steps
   - Explain each step clearly for end users
   - Use numbered or visual process flow
   - Include screenshots/mockup placeholders

3. **When Documentation IS Available:**
   - Use documentation for CONTEXT and terminology
   - Verify technical accuracy against code
   - Fill gaps with code analysis
   - Maintain consistency with docs tone

4. **When Documentation is NOT Available:**
   - Rely entirely on code analysis
   - Create user-friendly explanations
   - Use industry-standard terminology
   - Include helpful visuals and diagrams

### Special Notes:
- Content must reflect ACTUAL application behavior
- Include interactive demos or GIFs placeholders
- Add FAQ specific to "How It Works"
- Consider video tutorial placeholder`
        }
    };
    
    // Stored customizations (loaded from localStorage)
    // Structure: { pageId: { content: "...", savedWithState: { feedFromDoc: true, ... } } }
    let pageInfoCustomizations = {};
    
    // Get current application selections state
    function getCurrentSelectionsState() {
        return {
            feedFromDocumentation: document.getElementById('feedFromDocumentation')?.checked || false,
            integrationMode: document.querySelector('input[name="integration_mode"]:checked')?.value || 'ai-decision',
            homepageCreationEnabled: document.querySelector('[data-section="homepageCreation"] input[type="checkbox"]')?.checked || false
        };
    }
    
    // Check if selections have changed since customization was saved
    function hasSelectionsChanged(savedState) {
        if (!savedState) return false;
        const currentState = getCurrentSelectionsState();
        return (
            savedState.feedFromDocumentation !== currentState.feedFromDocumentation ||
            savedState.integrationMode !== currentState.integrationMode
        );
    }
    
    // Generate dynamic instructions based on current selections
    function generateDynamicInstructions(pageId) {
        const pageConfig = pageInfoDefaults[pageId];
        if (!pageConfig) return null;
        
        const state = getCurrentSelectionsState();
        let instructions = pageConfig.defaultInstructions;
        
        // Add dynamic header showing current state
        const stateHeader = `## 📊 CURRENT APPLICATION STATE
- **Feed from Documentation:** ${state.feedFromDocumentation ? '✅ ENABLED' : '❌ DISABLED'}
- **Integration Mode:** ${state.integrationMode.toUpperCase()}

---

`;
        
        // For special pages, customize based on state
        if (pageId === 'how-it-works') {
            // How It Works always uses app functionality, not docs
            instructions = `## HOW IT WORKS PAGE - Content Source Instructions

### 📊 CURRENT STATE: ${state.feedFromDocumentation ? 'Documentation Enabled' : 'AI Generation Mode'}

### ⚠️ SPECIAL PAGE - Always Derived from Application Functionality

**IMPORTANT:** Regardless of documentation settings, "How It Works" content is ALWAYS derived from ANALYZING THE APPLICATION'S CORE FUNCTIONALITY.

### Content Generation Process:
1. **Analyze Application Code:** Examine the uploaded codebase to understand:
   - Main features and capabilities
   - User workflows and journeys
   - Core functionality and processes
   - Integration points and data flow

2. **Create Step-by-Step Guide:**
   - Break down the application into logical steps
   - Explain each step clearly for end users
   - Use numbered or visual process flow
   - Include screenshots/mockup placeholders

3. **Documentation Context (${state.feedFromDocumentation ? 'AVAILABLE' : 'NOT AVAILABLE'}):**
${state.feedFromDocumentation ? 
`   - Use documentation for CONTEXT and terminology
   - Verify technical accuracy against code
   - Fill gaps with code analysis
   - Maintain consistency with docs tone` :
`   - Rely entirely on code analysis
   - Create user-friendly explanations
   - Use industry-standard terminology
   - Include helpful visuals and diagrams`}

### Special Notes:
- Content must reflect ACTUAL application behavior
- Include interactive demos or GIFs placeholders
- Add FAQ specific to "How It Works"
- Consider video tutorial placeholder`;
        } else {
            // For all other pages, prepend state header
            instructions = stateHeader + instructions;
        }
        
        return instructions;
    }
    
    // Initialize on page load
    document.addEventListener('DOMContentLoaded', function() {
        loadPageInfoCustomizations();
        setupSelectionsListeners();
    });
    
    // Setup listeners for selections that affect page instructions
    function setupSelectionsListeners() {
        // Listen to Feed from Documentation changes
        const feedFromDocCheckbox = document.getElementById('feedFromDocumentation');
        if (feedFromDocCheckbox) {
            feedFromDocCheckbox.addEventListener('change', handleSelectionsChange);
        }
        
        // Listen to Integration Mode changes
        const integrationModeRadios = document.querySelectorAll('input[name="integration_mode"]');
        integrationModeRadios.forEach(radio => {
            radio.addEventListener('change', handleSelectionsChange);
        });
        
        console.log('📋 Page info selections listeners initialized');
    }
    
    // Handle when selections change - invalidate affected customizations
    function handleSelectionsChange() {
        const currentState = getCurrentSelectionsState();
        let invalidatedCount = 0;
        
        // Check each customization and mark if state changed
        Object.keys(pageInfoCustomizations).forEach(pageId => {
            const customization = pageInfoCustomizations[pageId];
            if (customization && customization.savedWithState) {
                if (hasSelectionsChanged(customization.savedWithState)) {
                    // Mark as outdated but don't delete - user can still see old content
                    pageInfoCustomizations[pageId].isOutdated = true;
                    invalidatedCount++;
                }
            }
        });
        
        if (invalidatedCount > 0) {
            savePageInfoCustomizations();
            console.log(`⚠️ ${invalidatedCount} page customization(s) marked as outdated due to selection changes`);
        }
    }
    
    // Load customizations from localStorage
    function loadPageInfoCustomizations() {
        try {
            const saved = localStorage.getItem('pageInfoCustomizations');
            if (saved) {
                pageInfoCustomizations = JSON.parse(saved);
                
                // Check for outdated customizations on load
                const currentState = getCurrentSelectionsState();
                Object.keys(pageInfoCustomizations).forEach(pageId => {
                    const customization = pageInfoCustomizations[pageId];
                    if (customization && customization.savedWithState) {
                        if (hasSelectionsChanged(customization.savedWithState)) {
                            pageInfoCustomizations[pageId].isOutdated = true;
                        }
                    }
                });
                
                console.log('📋 Loaded page info customizations:', Object.keys(pageInfoCustomizations));
            }
        } catch (e) {
            console.error('Error loading page info customizations:', e);
            pageInfoCustomizations = {};
        }
    }
    
    // Save customizations to localStorage
    function savePageInfoCustomizations() {
        try {
            localStorage.setItem('pageInfoCustomizations', JSON.stringify(pageInfoCustomizations));
            console.log('💾 Saved page info customizations');
        } catch (e) {
            console.error('Error saving page info customizations:', e);
        }
    }
    
    // Open the page info modal
    window.openPageInfoModal = function(pageId) {
        currentPageInfoId = pageId;
        const pageConfig = pageInfoDefaults[pageId];
        
        if (!pageConfig) {
            console.error('Unknown page:', pageId);
            return;
        }
        
        // Update modal header
        document.getElementById('pageInfoModalIcon').className = pageConfig.icon;
        document.getElementById('pageInfoModalIcon').style.color = pageConfig.color;
        document.getElementById('pageInfoModalTitle').textContent = `${pageConfig.name} Page - Content Source`;
        
        // Update current state indicators
        const currentState = getCurrentSelectionsState();
        const docsIndicator = document.getElementById('stateIndicatorDocs');
        const modeIndicator = document.getElementById('stateIndicatorMode');
        
        if (docsIndicator) {
            if (currentState.feedFromDocumentation) {
                docsIndicator.textContent = '✅ ON';
                docsIndicator.style.color = 'var(--aurora-green)';
            } else {
                docsIndicator.textContent = '❌ OFF';
                docsIndicator.style.color = '#ef4444';
            }
        }
        
        if (modeIndicator) {
            modeIndicator.textContent = currentState.integrationMode.toUpperCase().replace('-', ' ');
        }
        
        // Check customization status
        const textarea = document.getElementById('pageInfoTextarea');
        const customization = pageInfoCustomizations[pageId];
        const hasCustomization = customization && customization.content;
        const isOutdated = customization && customization.isOutdated;
        
        if (hasCustomization && !isOutdated) {
            // Use saved customization (selections haven't changed)
            textarea.value = customization.content;
            updatePageInfoStatus('custom');
        } else if (isOutdated) {
            // Selections changed - use dynamic instructions, notify user
            textarea.value = generateDynamicInstructions(pageId);
            updatePageInfoStatus('outdated');
            
            // Clear the outdated customization
            delete pageInfoCustomizations[pageId];
            savePageInfoCustomizations();
            
            if (typeof showNotification === 'function') {
                showNotification('⚠️ Settings changed - instructions updated automatically', 'warning');
            }
        } else {
            // No customization - use dynamic instructions
            textarea.value = generateDynamicInstructions(pageId);
            updatePageInfoStatus('default');
        }
        
        // Show modal
        document.getElementById('pageInfoModalOverlay').classList.add('active');
        
        // Focus textarea
        setTimeout(() => textarea.focus(), 300);
    };
    
    // Close the modal
    window.closePageInfoModal = function(event) {
        if (event && event.target !== event.currentTarget && !event.target.closest('.page-info-modal-close')) {
            return;
        }
        document.getElementById('pageInfoModalOverlay').classList.remove('active');
        currentPageInfoId = null;
    };
    
    // Update status indicator
    function updatePageInfoStatus(statusType) {
        const status = document.getElementById('pageInfoStatus');
        
        switch(statusType) {
            case 'custom':
                status.className = 'page-info-status modified';
                status.innerHTML = '<i class="fas fa-pen"></i><span>Custom instructions (saved)</span>';
                break;
            case 'outdated':
                status.className = 'page-info-status';
                status.style.background = 'rgba(245, 158, 11, 0.1)';
                status.style.borderColor = 'rgba(245, 158, 11, 0.3)';
                status.style.color = '#f59e0b';
                status.innerHTML = '<i class="fas fa-sync-alt"></i><span>Auto-updated (settings changed)</span>';
                break;
            default:
                status.className = 'page-info-status';
                status.style.background = '';
                status.style.borderColor = '';
                status.style.color = '';
                status.innerHTML = '<i class="fas fa-check-circle"></i><span>Dynamic instructions (current settings)</span>';
        }
    }
    
    // Save page info
    window.savePageInfo = function() {
        if (!currentPageInfoId) return;
        
        const textarea = document.getElementById('pageInfoTextarea');
        const content = textarea.value.trim();
        const dynamicContent = generateDynamicInstructions(currentPageInfoId);
        
        if (content === dynamicContent) {
            // If content matches dynamic default, remove customization
            delete pageInfoCustomizations[currentPageInfoId];
            updatePageInfoStatus('default');
        } else {
            // Save customization WITH current selections state
            pageInfoCustomizations[currentPageInfoId] = {
                content: content,
                savedWithState: getCurrentSelectionsState(),
                savedAt: new Date().toISOString(),
                isOutdated: false
            };
            updatePageInfoStatus('custom');
        }
        
        savePageInfoCustomizations();
        
        // Show success notification
        if (typeof showNotification === 'function') {
            showNotification('✅ Page instructions saved!', 'success');
        }
        
        // Close modal
        closePageInfoModal({ target: document.getElementById('pageInfoModalOverlay'), currentTarget: document.getElementById('pageInfoModalOverlay') });
    };
    
    // Reset to default (dynamic)
    window.resetPageInfoToDefault = function() {
        if (!currentPageInfoId) return;
        
        // Set textarea to dynamic default
        document.getElementById('pageInfoTextarea').value = generateDynamicInstructions(currentPageInfoId);
        
        // Remove customization
        delete pageInfoCustomizations[currentPageInfoId];
        savePageInfoCustomizations();
        
        // Update status
        updatePageInfoStatus('default');
        
        // Show notification
        if (typeof showNotification === 'function') {
            showNotification('🔄 Reset to dynamic instructions', 'info');
        }
    };
    
    // Get page instructions for prompt generation (uses dynamic if no valid custom)
    window.getPageInstructions = function(pageId) {
        const pageConfig = pageInfoDefaults[pageId];
        if (!pageConfig) return null;
        
        const customization = pageInfoCustomizations[pageId];
        const hasValidCustomization = customization && customization.content && !customization.isOutdated;
        
        if (hasValidCustomization) {
            // Check if selections changed since save
            if (!hasSelectionsChanged(customization.savedWithState)) {
                return {
                    pageId: pageId,
                    pageName: pageConfig.name,
                    instructions: customization.content,
                    isCustomized: true
                };
            }
        }
        
        // Use dynamic instructions
        return {
            pageId: pageId,
            pageName: pageConfig.name,
            instructions: generateDynamicInstructions(pageId),
            isCustomized: false
        };
    };
    
    // Get all page instructions for selected pages (for prompt generation)
    window.getAllSelectedPageInstructions = function() {
        const selectedPages = document.querySelectorAll('input[name="create_pages"]:checked');
        const instructions = [];
        
        selectedPages.forEach(checkbox => {
            const pageId = checkbox.value;
            // Include pages that have info popup configurations
            if (pageInfoDefaults.hasOwnProperty(pageId)) {
                const pageInstructions = getPageInstructions(pageId);
                if (pageInstructions) {
                    instructions.push(pageInstructions);
                }
            }
        });
        
        return instructions;
    };
    
    // Close modal on Escape key
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape' && document.getElementById('pageInfoModalOverlay').classList.contains('active')) {
            closePageInfoModal({ target: document.getElementById('pageInfoModalOverlay'), currentTarget: document.getElementById('pageInfoModalOverlay') });
        }
    });
    </script>

<!-- ════════════════════════════════════════════════════════════════
     DEVELOPMENT DASHBOARD & PROMPT EDITOR JAVASCRIPT
     Imported from Prompt-Manager.php
     ════════════════════════════════════════════════════════════════ -->
<script>
(function() {
    'use strict';
    
    // ══════════════════════════════════════════════════════════════════
    // STATE MANAGEMENT
    // ══════════════════════════════════════════════════════════════════
    
    const DASHBOARD_STORAGE_KEY_DE = 'devDashboardSettingsDE';
    
    // Dashboard state
    let dashboardStateDE = {
        database: {
            selected: '',
            remoteCredentials: false,
            localhostCredentials: false
        },
        backend: [],
        page: [],
        frontend: [],
        currentProject: null
    };
    
    // Projects cache (loaded from database)
    let projectsCacheDE = [];
    let lastSyncTimestampDE = 0;
    
    // Item counters
    let itemCountersDE = {
        backend: 0,
        page: 0,
        frontend: 0
    };
    
    // ══════════════════════════════════════════════════════════════════
    // INITIALIZATION
    // ══════════════════════════════════════════════════════════════════
    
    function initDashboardDE() {
        loadDashboardStateDE();
        loadProjectsListDE();
        updateAllCountsDE();
        console.log('✅ Development Dashboard DE initialized');
    }
    
    // ══════════════════════════════════════════════════════════════════
    // LOCAL STORAGE FUNCTIONS
    // ══════════════════════════════════════════════════════════════════
    
    function saveDashboardStateDE() {
        try {
            localStorage.setItem(DASHBOARD_STORAGE_KEY_DE, JSON.stringify(dashboardStateDE));
        } catch (e) {
            console.error('Error saving dashboard state:', e);
        }
    }
    
    function loadDashboardStateDE() {
        try {
            const saved = localStorage.getItem(DASHBOARD_STORAGE_KEY_DE);
            if (saved) {
                dashboardStateDE = JSON.parse(saved);
                renderAllItemsDE();
            }
        } catch (e) {
            console.error('Error loading dashboard state:', e);
        }
    }
    
    // Load projects list from database (async)
    async function loadProjectsListDE() {
        try {
            const formData = new FormData();
            formData.append('action', 'get_projects_de');
            
            const response = await fetch(window.location.href, {
                method: 'POST',
                body: formData
            });
            
            const result = await response.json();
            
            if (result.success) {
                projectsCacheDE = result.projects || [];
                updateProjectSelectorDE();
                console.log('📦 Projects loaded from database:', projectsCacheDE.length);
            } else {
                console.error('Error loading projects:', result.message);
            }
        } catch (e) {
            console.error('Error loading projects:', e);
        }
    }
    
    // Update project selector dropdown
    function updateProjectSelectorDE() {
        const selector = document.getElementById('projectSelectorDE');
        if (selector) {
            selector.innerHTML = '<option value="">-- No Project --</option>';
            projectsCacheDE.forEach(p => {
                const opt = document.createElement('option');
                opt.value = p.id;
                opt.textContent = p.name;
                if (dashboardStateDE.currentProject == p.id) {
                    opt.selected = true;
                }
                selector.appendChild(opt);
            });
        }
    }
    
    // Get single project from database
    async function getProjectFromDB(id) {
        try {
            const formData = new FormData();
            formData.append('action', 'get_project_de');
            formData.append('id', id);
            
            const response = await fetch(window.location.href, {
                method: 'POST',
                body: formData
            });
            
            const result = await response.json();
            return result.success ? result.project : null;
        } catch (e) {
            console.error('Error getting project:', e);
            return null;
        }
    }
    
    // Save project to database
    async function saveProjectToDB(projectData) {
        try {
            const formData = new FormData();
            formData.append('action', 'save_project_de');
            
            if (projectData.id) formData.append('id', projectData.id);
            formData.append('name', projectData.name || 'Untitled Project');
            formData.append('description', projectData.description || '');
            formData.append('backends', JSON.stringify(dashboardStateDE.backend || []));
            formData.append('pages', JSON.stringify(dashboardStateDE.page || []));
            formData.append('frontends', JSON.stringify(dashboardStateDE.frontend || []));
            formData.append('prompt_content', document.getElementById('promptEditorDE')?.value || '');
            formData.append('database_name', dashboardStateDE.database?.selected || '');
            formData.append('include_remote', dashboardStateDE.database?.remoteCredentials ? 1 : 0);
            formData.append('include_localhost', dashboardStateDE.database?.localhostCredentials ? 1 : 0);
            
            const response = await fetch(window.location.href, {
                method: 'POST',
                body: formData
            });
            
            const result = await response.json();
            
            return result;
        } catch (e) {
            console.error('Error saving project:', e);
            return { success: false, message: e.message };
        }
    }
    
    // Delete project from database
    async function deleteProjectFromDB(id) {
        try {
            const formData = new FormData();
            formData.append('action', 'delete_project_de');
            formData.append('id', id);
            
            const response = await fetch(window.location.href, {
                method: 'POST',
                body: formData
            });
            
            const result = await response.json();
            
            return result;
        } catch (e) {
            console.error('Error deleting project:', e);
            return { success: false, message: e.message };
        }
    }
    
    // ══════════════════════════════════════════════════════════════════
    // DYNAMIC ITEMS (Backend, Pages, Frontend)
    // ══════════════════════════════════════════════════════════════════
    
    window.addDynamicItemDE = function(type) {
        itemCountersDE[type]++;
        const item = {
            id: Date.now() + '_' + itemCountersDE[type],
            name: '',
            prompt: ''
        };
        dashboardStateDE[type].push(item);
        renderItemDE(type, item);
        updateCountDE(type);
        saveDashboardStateDE();
    };
    
    function renderItemDE(type, item) {
        const grid = document.getElementById(`${type}ItemsGridDE`);
        const emptyState = document.getElementById(`${type}EmptyStateDE`);
        
        if (emptyState) emptyState.style.display = 'none';
        
        const itemEl = document.createElement('div');
        itemEl.className = `dynamic-item-de ${type}-item`;
        itemEl.dataset.id = item.id;
        
        itemEl.innerHTML = `
            <div class="dynamic-item-header-de">
                <input type="text" class="dynamic-item-name-de" placeholder="${type.charAt(0).toUpperCase() + type.slice(1)} name..." 
                       value="${item.name || ''}" onchange="updateItemNameDE('${type}', '${item.id}', this.value)">
                <button type="button" class="dynamic-item-delete-de" onclick="deleteItemDE('${type}', '${item.id}')" title="Delete">
                    <i class="fas fa-times"></i>
                </button>
            </div>
            <textarea class="dynamic-item-prompt-de" placeholder="Description or prompt..." 
                      onchange="updateItemPromptDE('${type}', '${item.id}', this.value)">${item.prompt || ''}</textarea>
        `;
        
        grid.appendChild(itemEl);
    }
    
    function renderAllItemsDE() {
        ['backend', 'page', 'frontend'].forEach(type => {
            const grid = document.getElementById(`${type}ItemsGridDE`);
            const emptyState = document.getElementById(`${type}EmptyStateDE`);
            
            // Clear existing items (but keep empty state)
            const items = grid.querySelectorAll('.dynamic-item-de');
            items.forEach(i => i.remove());
            
            if (dashboardStateDE[type].length > 0) {
                if (emptyState) emptyState.style.display = 'none';
                dashboardStateDE[type].forEach(item => renderItemDE(type, item));
            } else {
                if (emptyState) emptyState.style.display = 'flex';
            }
        });
        updateAllCountsDE();
    }
    
    window.updateItemNameDE = function(type, id, value) {
        const item = dashboardStateDE[type].find(i => i.id === id);
        if (item) {
            item.name = value;
            saveDashboardStateDE();
        }
    };
    
    window.updateItemPromptDE = function(type, id, value) {
        const item = dashboardStateDE[type].find(i => i.id === id);
        if (item) {
            item.prompt = value;
            saveDashboardStateDE();
        }
    };
    
    window.deleteItemDE = function(type, id) {
        dashboardStateDE[type] = dashboardStateDE[type].filter(i => i.id !== id);
        
        const grid = document.getElementById(`${type}ItemsGridDE`);
        const itemEl = grid.querySelector(`[data-id="${id}"]`);
        if (itemEl) itemEl.remove();
        
        const emptyState = document.getElementById(`${type}EmptyStateDE`);
        if (dashboardStateDE[type].length === 0 && emptyState) {
            emptyState.style.display = 'flex';
        }
        
        updateCountDE(type);
        saveDashboardStateDE();
    };
    
    function updateCountDE(type) {
        const countEl = document.getElementById(`${type}CountDE`);
        if (countEl) {
            countEl.textContent = dashboardStateDE[type].length;
        }
    }
    
    function updateAllCountsDE() {
        ['backend', 'page', 'frontend'].forEach(updateCountDE);
    }
    
    // ══════════════════════════════════════════════════════════════════
    // DATABASE FUNCTIONS
    // ══════════════════════════════════════════════════════════════════
    
    window.onDatabaseSelectDE = function() {
        const select = document.getElementById('dbDropdownDE');
        if (select) {
            dashboardStateDE.database.selected = select.value;
            saveDashboardStateDE();
        }
    };
    
    window.refreshDatabaseListDE = function() {
        const btn = document.getElementById('dbRefreshBtnDE');
        if (btn) {
            btn.querySelector('i').classList.add('fa-spin');
            setTimeout(() => {
                btn.querySelector('i').classList.remove('fa-spin');
                showNotificationDE('Database list refreshed!', 'success');
            }, 500);
        }
    };
    
    window.openDbManagerDE = function() {
        showNotificationDE('Database Manager - Coming Soon!', 'info');
    };
    
    window.toggleDatabaseCredentialsDE = function(type) {
        if (type === 'remote') {
            dashboardStateDE.database.remoteCredentials = document.getElementById('dbCredentialsCheckboxDE').checked;
            if (dashboardStateDE.database.remoteCredentials) {
                document.getElementById('dbLocalhostCheckboxDE').checked = false;
                dashboardStateDE.database.localhostCredentials = false;
            }
        } else if (type === 'localhost') {
            dashboardStateDE.database.localhostCredentials = document.getElementById('dbLocalhostCheckboxDE').checked;
            if (dashboardStateDE.database.localhostCredentials) {
                document.getElementById('dbCredentialsCheckboxDE').checked = false;
                dashboardStateDE.database.remoteCredentials = false;
            }
        }
        saveDashboardStateDE();
    };
    
    window.generateDatabasePromptDE = function() {
        let prompt = '📦 **DATABASE CONNECTION**\n\n';
        prompt += 'Database: ' + (dashboardStateDE.database.selected || 'Not selected') + '\n';
        prompt += 'Connection Type: ' + (dashboardStateDE.database.remoteCredentials ? 'Remote' : dashboardStateDE.database.localhostCredentials ? 'Localhost' : 'Not specified') + '\n';
        
        appendToEditorDE(prompt);
        showNotificationDE('Database prompt added!', 'success');
    };
    
    window.generateFullDatabasePromptDE = function() {
        let prompt = '📦 **FULL DATABASE PROMPT**\n\n';
        prompt += 'Database: ' + (dashboardStateDE.database.selected || 'Not selected') + '\n';
        prompt += 'Please connect to the database and perform the necessary operations.\n';
        
        appendToEditorDE(prompt);
        showNotificationDE('Full database prompt added!', 'success');
    };
    
    window.appendDatabaseToPromptDE = function() {
        generateDatabasePromptDE();
    };
    
    // ══════════════════════════════════════════════════════════════════
    // SECTION TO PROMPT FUNCTIONS
    // ══════════════════════════════════════════════════════════════════
    
    window.appendSectionToPromptDE = function(type) {
        const items = dashboardStateDE[type];
        if (items.length === 0) {
            showNotificationDE(`No ${type} items to add!`, 'warning');
            return;
        }
        
        const icons = { backend: '🖥️', page: '📄', frontend: '🎨' };
        let prompt = `${icons[type]} **${type.toUpperCase()} SECTION**\n\n`;
        
        items.forEach((item, index) => {
            prompt += `${index + 1}. **${item.name || 'Unnamed'}**\n`;
            if (item.prompt) prompt += `   ${item.prompt}\n`;
            prompt += '\n';
        });
        
        appendToEditorDE(prompt);
        showNotificationDE(`${type.charAt(0).toUpperCase() + type.slice(1)} section added!`, 'success');
    };
    
    window.appendAllSectionsToPromptDE = function() {
        appendDatabaseToPromptDE();
        ['backend', 'page', 'frontend'].forEach(type => {
            if (dashboardStateDE[type].length > 0) {
                appendSectionToPromptDE(type);
            }
        });
        showNotificationDE('All sections added to prompt!', 'success');
    };
    
    // ══════════════════════════════════════════════════════════════════
    // GENERATE COMPREHENSIVE PROMPT
    // ══════════════════════════════════════════════════════════════════
    
    window.generateComprehensivePromptDE = function() {
        let prompt = '═══════════════════════════════════════════════════════════════\n';
        prompt += '  🚀 COMPREHENSIVE PROJECT PROMPT\n';
        prompt += '═══════════════════════════════════════════════════════════════\n\n';
        
        // Database
        if (dashboardStateDE.database.selected) {
            prompt += '📦 **DATABASE**\n';
            prompt += `Database: ${dashboardStateDE.database.selected}\n`;
            prompt += `Type: ${dashboardStateDE.database.remoteCredentials ? 'Remote' : 'Localhost'}\n\n`;
        }
        
        // Backend
        if (dashboardStateDE.backend.length > 0) {
            prompt += '🖥️ **BACKEND**\n';
            dashboardStateDE.backend.forEach((item, i) => {
                prompt += `${i + 1}. ${item.name || 'Unnamed'}\n`;
                if (item.prompt) prompt += `   ${item.prompt}\n`;
            });
            prompt += '\n';
        }
        
        // Pages
        if (dashboardStateDE.page.length > 0) {
            prompt += '📄 **PAGES**\n';
            dashboardStateDE.page.forEach((item, i) => {
                prompt += `${i + 1}. ${item.name || 'Unnamed'}\n`;
                if (item.prompt) prompt += `   ${item.prompt}\n`;
            });
            prompt += '\n';
        }
        
        // Frontend
        if (dashboardStateDE.frontend.length > 0) {
            prompt += '🎨 **FRONTEND**\n';
            dashboardStateDE.frontend.forEach((item, i) => {
                prompt += `${i + 1}. ${item.name || 'Unnamed'}\n`;
                if (item.prompt) prompt += `   ${item.prompt}\n`;
            });
            prompt += '\n';
        }
        
        prompt += '═══════════════════════════════════════════════════════════════\n';
        prompt += `Generated: ${new Date().toLocaleString()}\n`;
        prompt += '═══════════════════════════════════════════════════════════════\n';
        
        const editor = document.getElementById('promptEditorDE');
        if (editor) {
            editor.value = prompt;
            showNotificationDE('Comprehensive prompt generated!', 'success');
        }
    };
    
    // ══════════════════════════════════════════════════════════════════
    // PROJECT MANAGEMENT
    // ══════════════════════════════════════════════════════════════════
    
    window.openNewProjectPopupDE = function() {
        document.getElementById('newProjectPopupDE').classList.add('active');
        const input = document.getElementById('newProjectNameDE');
        if (input) {
            input.value = '';
            setTimeout(() => input.focus(), 100);
        }
    };
    
    window.createProjectDE = async function() {
        const input = document.getElementById('newProjectNameDE');
        const name = input ? input.value.trim() : '';
        
        if (!name) {
            showNotificationDE('Please enter a project name!', 'warning');
            return;
        }
        
        showNotificationDE('Creating project...', 'info');
        
        const result = await saveProjectToDB({ name: name });
        
        if (result.success) {
            dashboardStateDE.currentProject = result.id;
            saveDashboardStateDE();
            await loadProjectsListDE();
            
            document.getElementById('newProjectPopupDE').classList.remove('active');
            input.value = '';
            showNotificationDE(`Project "${name}" created!`, 'success');
        } else {
            showNotificationDE('Error creating project: ' + result.message, 'error');
        }
    };
    
    window.saveCurrentProjectDE = async function() {
        if (!dashboardStateDE.currentProject) {
            showNotificationDE('No project selected! Create a new project first.', 'warning');
            return;
        }
        
        showNotificationDE('Saving project...', 'info');
        
        const currentProject = projectsCacheDE.find(p => p.id == dashboardStateDE.currentProject);
        
        const result = await saveProjectToDB({
            id: dashboardStateDE.currentProject,
            name: currentProject?.name || 'Project'
        });
        
        if (result.success) {
            showNotificationDE('Project saved!', 'success');
            await loadProjectsListDE();
        } else {
            showNotificationDE('Error saving: ' + result.message, 'error');
        }
    };
    
    window.openLoadProjectPopupDE = async function() {
        await loadProjectsListDE();
        
        const listContainer = document.getElementById('projectListDE');
        
        if (projectsCacheDE.length === 0) {
            listContainer.innerHTML = `
                <div class="project-list-empty-de">
                    <i class="fas fa-folder-open"></i>
                    <p>No projects saved yet</p>
                </div>
            `;
        } else {
            listContainer.innerHTML = projectsCacheDE.map(p => `
                <div class="project-list-item-de" data-id="${p.id}" onclick="selectProjectItemDE(this, '${p.id}')">
                    <div class="project-list-info-de">
                        <div class="project-list-name-de">${p.name}</div>
                        <div class="project-list-date-de">${new Date(p.created_at || p.updated_at).toLocaleDateString()}</div>
                    </div>
                    <i class="fas fa-chevron-right" style="color: var(--text-muted); font-size: 0.7rem;"></i>
                </div>
            `).join('');
        }
        
        document.getElementById('loadProjectPopupDE').classList.add('active');
    };
    
    window.selectedProjectIdDE = null;
    
    window.selectProjectItemDE = function(element, id) {
        document.querySelectorAll('.project-list-item-de').forEach(item => {
            item.classList.remove('selected');
        });
        element.classList.add('selected');
        window.selectedProjectIdDE = id;
    };
    
    window.loadSelectedProjectDE = async function() {
        if (!window.selectedProjectIdDE) {
            showNotificationDE('Please select a project first!', 'warning');
            return;
        }
        
        showNotificationDE('Loading project...', 'info');
        
        const project = await getProjectFromDB(window.selectedProjectIdDE);
        
        if (project) {
            dashboardStateDE = {
                database: {
                    selected: project.database_name || '',
                    remoteCredentials: project.include_remote == 1,
                    localhostCredentials: project.include_localhost == 1
                },
                backend: project.backends || [],
                page: project.pages || [],
                frontend: project.frontends || [],
                currentProject: project.id
            };
            
            const editor = document.getElementById('promptEditorDE');
            if (editor && project.prompt_content) {
                editor.value = project.prompt_content;
            }
            
            saveDashboardStateDE();
            renderAllItemsDE();
            await loadProjectsListDE();
            
            document.getElementById('loadProjectPopupDE').classList.remove('active');
            window.selectedProjectIdDE = null;
            showNotificationDE(`Project "${project.name}" loaded!`, 'success');
        } else {
            showNotificationDE('Error loading project', 'error');
        }
    };

    window.onProjectSelectDE = async function() {
        const selector = document.getElementById('projectSelectorDE');
        const projectId = selector?.value;
        
        if (!projectId) {
            dashboardStateDE.currentProject = null;
            saveDashboardStateDE();
            return;
        }
        
        showNotificationDE('Loading...', 'info');
        
        const project = await getProjectFromDB(projectId);
        
        if (project) {
            dashboardStateDE = {
                database: {
                    selected: project.database_name || '',
                    remoteCredentials: project.include_remote == 1,
                    localhostCredentials: project.include_localhost == 1
                },
                backend: project.backends || [],
                page: project.pages || [],
                frontend: project.frontends || [],
                currentProject: project.id
            };
            
            const editor = document.getElementById('promptEditorDE');
            if (editor && project.prompt_content) {
                editor.value = project.prompt_content;
            }
            
            saveDashboardStateDE();
            renderAllItemsDE();
            showNotificationDE(`Project "${project.name}" loaded!`, 'success');
        }
    };
    
    window.deleteCurrentProjectDE = async function() {
        if (!dashboardStateDE.currentProject) {
            showNotificationDE('No project selected!', 'warning');
            return;
        }
        
        const currentProject = projectsCacheDE.find(p => p.id == dashboardStateDE.currentProject);
        
        if (confirm(`Delete "${currentProject?.name}"?`)) {
            showNotificationDE('Deleting...', 'info');
            
            const result = await deleteProjectFromDB(dashboardStateDE.currentProject);
            
            if (result.success) {
                dashboardStateDE.currentProject = null;
                saveDashboardStateDE();
                await loadProjectsListDE();
                showNotificationDE('Project deleted!', 'success');
            } else {
                showNotificationDE('Error: ' + result.message, 'error');
            }
        }
    };
    
    window.resetDashboardProjectDE = function() {
        if (confirm('Reset dashboard? This will clear all items.')) {
            dashboardStateDE = {
                database: { selected: '', remoteCredentials: false, localhostCredentials: false },
                backend: [],
                page: [],
                frontend: [],
                currentProject: null
            };
            saveDashboardStateDE();
            renderAllItemsDE();
            loadProjectsListDE();
            showNotificationDE('Dashboard reset!', 'success');
        }
    };
    
    window.resetDashboardDE = function() {
        resetDashboardProjectDE();
    };
    
    // ══════════════════════════════════════════════════════════════════
    // EDITOR FUNCTIONS
    // ══════════════════════════════════════════════════════════════════
    
    window.clearEditorDE = function() {
        const editor = document.getElementById('promptEditorDE');
        if (editor) {
            editor.value = '';
            showNotificationDE('Editor cleared!', 'success');
        }
    };
    
    window.pasteToEditorDE = async function() {
        try {
            const text = await navigator.clipboard.readText();
            const editor = document.getElementById('promptEditorDE');
            if (editor) {
                editor.value += text;
                showNotificationDE('Content pasted!', 'success');
            }
        } catch (err) {
            showNotificationDE('Failed to paste. Check clipboard permissions.', 'error');
        }
    };
    
    window.copyPromptDE = async function() {
        const editor = document.getElementById('promptEditorDE');
        if (editor && editor.value) {
            try {
                await navigator.clipboard.writeText(editor.value);
                showNotificationDE('Copied to clipboard!', 'success');
            } catch (err) {
                // Fallback
                editor.select();
                document.execCommand('copy');
                showNotificationDE('Copied to clipboard!', 'success');
            }
        } else {
            showNotificationDE('Nothing to copy!', 'warning');
        }
    };
    
    function appendToEditorDE(text) {
        const editor = document.getElementById('promptEditorDE');
        if (editor) {
            if (editor.value) editor.value += '\n\n';
            editor.value += text;
            editor.scrollTop = editor.scrollHeight;
        }
    }
    
    // ══════════════════════════════════════════════════════════════════
    // NOTIFICATION HELPER
    // ══════════════════════════════════════════════════════════════════
    
    function showNotificationDE(message, type = 'info') {
        // Remove any existing notifications
        const existingToasts = document.querySelectorAll('.toast-notification-de');
        existingToasts.forEach(t => t.remove());
        
        // Icon mapping
        const icons = {
            success: 'fa-check-circle',
            error: 'fa-exclamation-circle',
            warning: 'fa-exclamation-triangle',
            info: 'fa-info-circle'
        };
        
        // Create toast element
        const toast = document.createElement('div');
        toast.className = `toast-notification-de ${type}`;
        toast.innerHTML = `
            <i class="fas ${icons[type] || icons.info}"></i>
            <span>${message}</span>
            <i class="fas fa-times toast-close" onclick="this.parentElement.remove()"></i>
        `;
        
        document.body.appendChild(toast);
        
        // Auto remove after 4 seconds
        setTimeout(() => {
            if (toast.parentElement) {
                toast.classList.add('hiding');
                setTimeout(() => toast.remove(), 300);
            }
        }, 4000);
        
        console.log(`[${type.toUpperCase()}] ${message}`);
    }
    
    // ══════════════════════════════════════════════════════════════════
    // OPEN/SWITCH TO PROMPT MANAGER TAB
    // ══════════════════════════════════════════════════════════════════
    
    // Using named window - browser remembers window by name
    const PROMPT_MANAGER_WINDOW_NAME = 'PromptManagerWindow';
    const PROMPT_MANAGER_URL = 'Prompt-Manager.php';
    
    window.openOrSwitchToPromptManager = function() {
        // Try to open/switch to the named window
        // If window with this name exists, it will focus on it
        // If not, it will open a new window with this name
        const win = window.open(PROMPT_MANAGER_URL, PROMPT_MANAGER_WINDOW_NAME);
        
        if (win) {
            win.focus();
            showNotificationDE('🔄 Prompt Manager tab opened/switched', 'success');
        } else {
            // Popup blocker might have prevented opening
            showNotificationDE('⚠️ Please allow popups to open Prompt Manager', 'warning');
        }
    };
    
    // ══════════════════════════════════════════════════════════════════
    // PROPAGATE FUNCTIONALITY (Manual sync between pages)
    // ══════════════════════════════════════════════════════════════════
    
    let propagateChannelDE = null;
    
    try {
        propagateChannelDE = new BroadcastChannel('prompt_manager_propagate');
        
        // Listen for propagate messages from other page
        propagateChannelDE.onmessage = function(event) {
            const data = event.data;
            
            if (data.type === 'propagate' && data.source !== 'index1') {
                console.log('📡 Received propagate from Prompt Manager:', data);
                
                // Apply the received state
                applyPropagatedDataDE(data);
                
                showNotificationDE('✅ Data received from Prompt Manager!', 'success');
            }
        };
        
        console.log('📡 Propagate channel connected');
    } catch (e) {
        console.log('BroadcastChannel not supported');
    }
    
    // Propagate all data to the other page
    window.propagateToOtherPageDE = function() {
        if (!propagateChannelDE) {
            showNotificationDE('❌ Sync not available. Make sure Prompt Manager is open.', 'error');
            return;
        }
        
        // Collect all current data
        const propagateData = {
            type: 'propagate',
            source: 'index1',
            timestamp: Date.now(),
            
            // Project selection
            currentProject: dashboardStateDE.currentProject,
            
            // Dashboard items
            backend: dashboardStateDE.backend || [],
            page: dashboardStateDE.page || [],
            frontend: dashboardStateDE.frontend || [],
            
            // Database selection
            database: dashboardStateDE.database || {},
            
            // Prompt editor content
            promptContent: document.getElementById('promptEditorDE')?.value || ''
        };
        
        // Send to other page
        propagateChannelDE.postMessage(propagateData);
        
        showNotificationDE('📤 Data sent to Prompt Manager!', 'success');
        console.log('📤 Propagated data:', propagateData);
    };
    
    // Apply received propagate data
    function applyPropagatedDataDE(data) {
        // Apply project selection
        if (data.currentProject) {
            const selector = document.getElementById('projectSelectorDE');
            if (selector) {
                selector.value = data.currentProject;
                dashboardStateDE.currentProject = data.currentProject;
            }
        }
        
        // Apply dashboard items
        if (data.backend) dashboardStateDE.backend = data.backend;
        if (data.page) dashboardStateDE.page = data.page;
        if (data.frontend) dashboardStateDE.frontend = data.frontend;
        if (data.database) dashboardStateDE.database = data.database;
        
        // Apply prompt editor content
        if (data.promptContent !== undefined) {
            const editor = document.getElementById('promptEditorDE');
            if (editor) {
                editor.value = data.promptContent;
            }
        }
        
        // Render the items
        renderAllItemsDE();
        saveDashboardStateDE();
        
        // Reload projects list to ensure dropdown is up to date
        loadProjectsListDE();
    }
    
    // ══════════════════════════════════════════════════════════════════
    // SEND TO PROMPT.TXT FUNCTIONALITY (uses Prompt-Manager.php config)
    // ══════════════════════════════════════════════════════════════════
    
    // IndexedDB configuration (same as Prompt-Manager.php)
    const DB_NAME_DE = 'PromptManagerDB';
    const DB_VERSION_DE = 1;
    const STORE_NAME_DE = 'fileHandles';
    
    let promptFolderHandleDE = null;
    let promptFileHandleDE = null;
    
    function openDBDE() {
        return new Promise((resolve, reject) => {
            const request = indexedDB.open(DB_NAME_DE, DB_VERSION_DE);
            request.onerror = () => reject(request.error);
            request.onsuccess = () => resolve(request.result);
            request.onupgradeneeded = (event) => {
                const db = event.target.result;
                if (!db.objectStoreNames.contains(STORE_NAME_DE)) {
                    db.createObjectStore(STORE_NAME_DE, { keyPath: 'id' });
                }
            };
        });
    }
    
    async function getHandleFromDBDE(id) {
        try {
            const db = await openDBDE();
            const tx = db.transaction(STORE_NAME_DE, 'readonly');
            const request = tx.objectStore(STORE_NAME_DE).get(id);
            return new Promise((resolve) => {
                request.onsuccess = () => { db.close(); resolve(request.result?.handle || null); };
                request.onerror = () => { db.close(); resolve(null); };
            });
        } catch (err) {
            return null;
        }
    }
    
    // Initialize Send connection on page load
    async function initSendConnectionDE() {
        const savedFolderName = localStorage.getItem('promptFolderName');
        const btnSend = document.getElementById('btnSendDE');
        
        if (!savedFolderName) {
            if (btnSend) {
                btnSend.disabled = true;
                btnSend.classList.remove('connected');
                btnSend.title = 'No folder configured. Configure in Prompt Manager first.';
            }
            return;
        }
        
        // Try to get the folder handle from IndexedDB
        try {
            const savedHandle = await getHandleFromDBDE('promptFolder');
            if (savedHandle) {
                // Request permission
                const perm = await savedHandle.requestPermission({ mode: 'readwrite' });
                if (perm === 'granted') {
                    promptFolderHandleDE = savedHandle;
                    try {
                        promptFileHandleDE = await promptFolderHandleDE.getFileHandle('prompt.txt', { create: false });
                    } catch (e) {
                        promptFileHandleDE = await promptFolderHandleDE.getFileHandle('prompt.txt', { create: true });
                    }
                    
                    // Enable send button
                    if (btnSend) {
                        btnSend.disabled = false;
                        btnSend.classList.add('connected');
                        btnSend.title = `Send to ${savedFolderName}/prompt.txt`;
                    }
                    
                    showNotificationDE(`✅ Connected to ${savedFolderName}/prompt.txt`, 'success');
                    console.log('📁 Send connected to:', savedFolderName);
                } else {
                    // Permission denied - show reconnect option
                    if (btnSend) {
                        btnSend.disabled = false;
                        btnSend.classList.remove('connected');
                        btnSend.title = `Click to reconnect to ${savedFolderName}/prompt.txt`;
                    }
                }
            }
        } catch (err) {
            console.log('Send auto-connect failed:', err.message);
            if (btnSend) {
                btnSend.disabled = false;
                btnSend.classList.remove('connected');
                btnSend.title = 'Click to try reconnecting to prompt.txt';
            }
        }
    }
    
    // Send editor content to prompt.txt
    window.sendToPromptFileDE = async function() {
        const btnSend = document.getElementById('btnSendDE');
        const savedFolderName = localStorage.getItem('promptFolderName');
        
        // If not connected, try to connect first
        if (!promptFileHandleDE) {
            if (!savedFolderName) {
                showNotificationDE('❌ No folder configured. Please configure in Prompt Manager first.', 'error');
                return;
            }
            
            // Try to reconnect
            try {
                const savedHandle = await getHandleFromDBDE('promptFolder');
                if (savedHandle) {
                    const perm = await savedHandle.requestPermission({ mode: 'readwrite' });
                    if (perm === 'granted') {
                        promptFolderHandleDE = savedHandle;
                        try {
                            promptFileHandleDE = await promptFolderHandleDE.getFileHandle('prompt.txt', { create: false });
                        } catch (e) {
                            promptFileHandleDE = await promptFolderHandleDE.getFileHandle('prompt.txt', { create: true });
                        }
                        
                        if (btnSend) {
                            btnSend.classList.add('connected');
                            btnSend.title = `Send to ${savedFolderName}/prompt.txt`;
                        }
                        
                        showNotificationDE(`✅ Reconnected to ${savedFolderName}/prompt.txt`, 'success');
                    } else {
                        showNotificationDE('❌ Permission denied. Please allow folder access.', 'error');
                        return;
                    }
                } else {
                    showNotificationDE('❌ No folder handle found. Configure folder in Prompt Manager first.', 'error');
                    return;
                }
            } catch (err) {
                showNotificationDE('❌ Failed to connect: ' + err.message, 'error');
                return;
            }
        }
        
        // Get editor content
        const editor = document.getElementById('promptEditorDE');
        const content = editor ? editor.value : '';
        
        try {
            // Create a writable stream
            const writable = await promptFileHandleDE.createWritable();
            
            // Write the content
            await writable.write(content);
            
            // Close the stream
            await writable.close();
            
            const folderName = localStorage.getItem('promptFolderName') || 'folder';
            if (content.trim()) {
                showNotificationDE(`✅ Sent to ${folderName}/prompt.txt`, 'success');
            } else {
                showNotificationDE(`🔄 Cleared ${folderName}/prompt.txt`, 'info');
            }
            console.log('📤 Content sent to prompt.txt, length:', content.length);
            
        } catch (err) {
            console.error('Error writing to prompt.txt:', err);
            
            if (err.name === 'NotAllowedError') {
                showNotificationDE('❌ Permission denied. Please click Send again to reconnect.', 'error');
                // Reset connection
                promptFolderHandleDE = null;
                promptFileHandleDE = null;
                if (btnSend) {
                    btnSend.classList.remove('connected');
                }
            } else {
                showNotificationDE('❌ Error writing: ' + err.message, 'error');
            }
        }
    };
    
    // ══════════════════════════════════════════════════════════════════
    // INITIALIZE ON DOM READY
    // ══════════════════════════════════════════════════════════════════
    
    async function initAllDE() {
        loadDashboardStateDE();
        await loadProjectsListDE();
        updateAllCountsDE();
        initSendConnectionDE();
        console.log('✅ Development Dashboard DE initialized');
    }
    
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', initAllDE);
    } else {
        initAllDE();
    }
    
    console.log('✅ Development Dashboard & Prompt Editor DE - Loaded');
})();
</script>

<!-- New Project Popup -->
<div class="project-popup-overlay-de" id="newProjectPopupDE">
    <div class="project-popup-de">
        <div class="project-popup-header-de">
            <div class="project-popup-title-de">
                <i class="fas fa-plus-circle"></i>
                New Project
            </div>
            <button class="project-popup-close-de" onclick="document.getElementById('newProjectPopupDE').classList.remove('active')">
                <i class="fas fa-times"></i>
            </button>
        </div>
        <div class="project-popup-body-de">
            <div class="project-form-group-de">
                <label class="project-form-label-de">Project Name</label>
                <input type="text" class="project-form-input-de" id="newProjectNameDE" placeholder="Enter project name...">
            </div>
        </div>
        <div class="project-popup-footer-de">
            <button class="project-popup-btn-de cancel" onclick="document.getElementById('newProjectPopupDE').classList.remove('active')">Cancel</button>
            <button class="project-popup-btn-de primary" onclick="createProjectDE()">Create Project</button>
        </div>
    </div>
</div>

<!-- Load Project Popup -->
<div class="project-popup-overlay-de" id="loadProjectPopupDE">
    <div class="project-popup-de">
        <div class="project-popup-header-de">
            <div class="project-popup-title-de">
                <i class="fas fa-folder-open"></i>
                Load Project
            </div>
            <button class="project-popup-close-de" onclick="document.getElementById('loadProjectPopupDE').classList.remove('active')">
                <i class="fas fa-times"></i>
            </button>
        </div>
        <div class="project-popup-body-de">
            <div class="project-list-de" id="projectListDE">
                <div class="project-list-empty-de">
                    <i class="fas fa-folder-open"></i>
                    <p>No projects saved yet</p>
                </div>
            </div>
        </div>
        <div class="project-popup-footer-de">
            <button class="project-popup-btn-de cancel" onclick="document.getElementById('loadProjectPopupDE').classList.remove('active')">Cancel</button>
            <button class="project-popup-btn-de primary" onclick="loadSelectedProjectDE()">Load Project</button>
        </div>
    </div>
</div>

</body>

</html>
</html>